INSERT INTO Next_Capability VALUES(290,4,20,'Applications Staffing (Skill Modeling/Inventory)','Approaches to map, develop, and manage workforce competencies for applications and technology.',NULL,NULL,1);
INSERT INTO Next_Capability VALUES(291,9,45,'AI Model Lifecycle Management','Ability to design, train, deploy, monitor, and retrain AI/ML models with consistent governance and automation.','Technical','Head of AI',1);
INSERT INTO Next_Capability VALUES(292,9,46,'Responsible AI Governance','Processes ensuring ethical, transparent, and compliant AI practices across the organization.','Governance','Chief Risk Officer',1);
INSERT INTO Next_Capability VALUES(293,9,47,'Decision Intelligence Enablement','Embedding AI-driven insights into strategic and operational decisions through data-driven workflows.','Business','CIO',1);
INSERT INTO Next_Capability VALUES(294,9,48,'AI Service Integration','Capability to expose and consume AI models and cognitive services through APIs and event frameworks.','Technical','Head of Platform Engineering',1);
INSERT INTO Next_Capability VALUES(295,10,49,'Enterprise Automation Platform','Unified automation ecosystem supporting RPA, workflow orchestration, and intelligent task management.','Technical','CIO',1);
INSERT INTO Next_Capability VALUES(296,10,50,'Autonomous Operations (AIOps)','Capability to enable predictive analytics, anomaly detection, and self-healing infrastructure.','Technical','Head of IT Operations',1);
INSERT INTO Next_Capability VALUES(297,10,51,'Automation Governance','Framework to manage automation lifecycle, security, and compliance.','Governance','COO',1);
INSERT INTO Next_Capability VALUES(298,11,52,'GreenOps & Carbon Efficiency','Capability to monitor, manage, and optimize energy and carbon footprint across hybrid environments.','Technical','Head of Operations',1);
INSERT INTO Next_Capability VALUES(299,11,53,'Sustainability Analytics','Ability to capture, analyze, and report sustainability performance using integrated data pipelines.','Analytical','Chief Sustainability Officer',1);
INSERT INTO Next_Capability VALUES(300,11,54,'Circular IT Asset Management','Process for procurement, reuse, and recycling of IT assets to minimize environmental impact.','Process','Head of Procurement',1);
INSERT INTO Next_Capability VALUES(301,12,55,'Experience Design & Journey Mapping','Capability to visualize and optimize customer and employee journeys using design thinking.','Business','Chief Experience Officer',1);
INSERT INTO Next_Capability VALUES(302,12,56,'Experience Analytics & Sentiment Intelligence','Use of data and AI to understand and predict experience satisfaction and engagement.','Analytical','Head of Digital Experience',1);
INSERT INTO Next_Capability VALUES(303,12,57,'Ecosystem Platform Enablement','Capability to integrate external partners, APIs, and marketplaces into business processes.','Technical','Chief Digital Officer',1);
INSERT INTO Next_Capability VALUES(304,1,1,'FinOps & Cloud Economics','Establishes the practices, tooling, and cultural disciplines required to bring financial accountability to cloud spend. Covers real-time visibility, unit economics, tagging governance, rightsizing, commitment management, anomaly detection, and showback/chargeback to align cloud investment with business value.','Core','FinOps Lead / Cloud Financial Manager',1);
INSERT INTO Next_Capability VALUES(305,2,8,'Supply Chain Security','Manages the security risk introduced by third-party software components, open-source dependencies, and vendor-supplied code throughout the software supply chain. Covers Software Bill of Materials (SBOM) generation and governance, dependency vulnerability scanning, third-party component vetting policies, build pipeline integrity controls, and supplier security attestation. Aligns to NIST SP 800-161, CISA SBOM guidance, NIS2 Article 21, and Australia SOCI supply chain obligations.','Core','CISO / Supply Chain Security Lead',1);
INSERT INTO Next_Capability VALUES(306,2,10,'Zero Trust Network Access (ZTNA) Architecture','Establishes and governs a Zero Trust posture at the network and access layer through continuous verification, micro-segmentation, least-privilege enforcement, and identity-aware access control for all users, devices, and workloads regardless of location. Covers ZTNA policy engine design, software-defined perimeter (SDP) implementation, east-west traffic controls, device trust scoring, and integration with IAM and SIEM. Distinct from general Network Security (id=60) which covers perimeter controls.','Core','Network Security Architect / Zero Trust Lead',1);
INSERT INTO Next_Capability VALUES(307,2,8,'AI Security & Model Integrity','Governs the security risks specific to AI and ML systems including adversarial input attacks, model poisoning, data exfiltration via LLMs, prompt injection, model inversion, and membership inference. Covers AI threat modelling, model integrity verification, AI red-teaming practices, LLM guardrail governance, and secure AI deployment standards. Operates as the security control layer for capabilities governed in the AI & Cognitive Systems domain (Responsible AI Governance id=292, AI Model Lifecycle Management id=291).','Core','AI Security Lead / CISO',1);
INSERT INTO Next_Capability VALUES(308,4,24,'Technical Debt Management','Provides a structured discipline for identifying, quantifying, prioritising, and remediating technical debt across the application portfolio. Covers technical debt taxonomy (code debt, architectural debt, test debt, infrastructure debt, documentation debt), debt scoring and visualisation, remediation backlog governance, debt accumulation rate tracking, and integration with investment and portfolio decisions. Distinct from App Rationalization (id=144) which governs portfolio-level decisions; Technical Debt Management governs the ongoing health of retained assets.','Core','Chief Architect / Engineering Lead',1);
INSERT INTO Next_Capability VALUES(309,9,45,'Generative AI & LLM Operations','Manages the operational lifecycle of Generative AI and Large Language Model deployments including prompt engineering governance, RAG pipeline management, LLM fine-tuning and evaluation, hallucination monitoring and mitigation, token cost management, model version control, and responsible output validation. Covers model selection frameworks, context window management, retrieval quality scoring, and integration with enterprise data governance. Extends AI Model Lifecycle Management (id=291) specifically for foundation model and GenAI workloads.','Core','GenAI Platform Lead / MLOps Engineer',1);
INSERT INTO Next_Capability VALUES(310,7,38,'Digital Twin & Simulation','Enables the creation and operational use of digital replicas of physical or logical systems for modelling, simulation, and predictive analysis. Covers infrastructure digital twins (capacity and performance simulation), application dependency twins (change impact modelling), sustainability twins (energy and carbon footprint modelling), and operational twins (failure mode simulation). Provides a forward-looking simulation layer that complements monitoring and observability capabilities.','Core','Digital Twin Architect / Innovation Lead',1);
INSERT INTO Next_Capability VALUES(311,9,45,'Feature Store & Data Preparation','Manages the engineering, versioning, and serving of ML features across training and inference pipelines. Covers feature registry design, point-in-time correct feature retrieval, feature drift detection, and integration with data platform and model training workflows. Prevents training-serving skew and accelerates model development through reusable, governed feature libraries.','Technical','ML Platform Engineer / Head of AI',1);
INSERT INTO Next_Capability VALUES(312,9,45,'Model Evaluation & Benchmarking','Structured capability to evaluate, benchmark, and compare AI/ML models before and after production deployment. Covers evaluation metric frameworks (accuracy, F1, BLEU, ROUGE, RAGAS for RAG), A/B testing of model variants, shadow deployment, regression testing against baseline models, and LLM-specific evaluation including hallucination rates, latency, and cost-per-token benchmarks. Distinct from monitoring post-deployment drift — this is pre-deployment validation.','Technical','Head of AI / MLOps Lead',1);
INSERT INTO Next_Capability VALUES(313,9,46,'AI Bias Detection & Fairness Testing','Systematic processes to detect, measure, and mitigate bias in AI models and training datasets. Covers demographic parity analysis, disparate impact testing, counterfactual fairness evaluation, bias auditing across protected attributes, and remediation techniques including re-weighting, adversarial debiasing, and post-processing corrections. Aligned to ISO/IEC TR 24027, NIST AI RMF MAP-2, and Australian AI Ethics Principles.','Governance','Chief Risk Officer / AI Ethics Lead',1);
INSERT INTO Next_Capability VALUES(314,9,46,'AI Explainability & Interpretability','Capability to generate and communicate meaningful explanations for AI model predictions and recommendations to business stakeholders, auditors, and regulators. Covers SHAP, LIME, and attention-based explanation methods; model-agnostic vs intrinsically interpretable model selection; explanation dashboards; counterfactual explanation generation; and regulatory-grade explainability documentation for high-stakes decisions. Aligned to EU AI Act Article 13 transparency requirements.','Governance','Chief Risk Officer / AI Product Owner',1);
INSERT INTO Next_Capability VALUES(315,9,46,'AI Regulatory Compliance & Risk Management','Manages compliance with AI-specific regulatory frameworks including the EU AI Act, Australia AI Ethics Framework, APRA CPG 234 AI guidance, and sector-specific regulations. Covers AI risk register maintenance, impact assessments, regulatory horizon scanning, audit readiness, and engagement with regulators on AI system registration and disclosure obligations.','Governance','Chief Compliance Officer / CISO',1);
INSERT INTO Next_Capability VALUES(316,9,47,'Predictive Analytics & Forecasting','Enterprise capability to build, deploy, and govern predictive models for business forecasting including demand forecasting, capacity planning, churn prediction, revenue projection, and risk scoring. Covers time-series modelling, ensemble methods, automated retraining pipelines, forecast accuracy tracking, and integration of predictions into operational decision workflows and business dashboards. Distinct from Decision Intelligence Enablement (id=293) which focuses on embedding insights into decision processes.','Business','Head of Analytics / Chief Data Officer',1);
INSERT INTO Next_Capability VALUES(317,9,48,'AI Agent & Orchestration Framework','Capability to design, deploy, and govern multi-agent AI systems and agentic workflows. Covers agent architecture patterns (ReAct, Plan-and-Execute, LangGraph, AutoGen), tool-use and function-calling frameworks, agent memory and state management, agent-to-agent communication protocols, human-in-the-loop checkpointing, and enterprise guardrails for autonomous agent execution. Includes agent observability, cost control, and escalation policies. Distinct from GenAI & LLM Operations (id=309) which governs individual model operations.','Technical','Head of AI / Platform Architect',1);
INSERT INTO Next_Capability VALUES(318,9,48,'Cognitive Search & Knowledge Retrieval','Enterprise search capability combining semantic vector search, knowledge graph traversal, and retrieval-augmented generation to surface contextually relevant information across structured and unstructured data. Covers embedding model selection and management, vector database governance, hybrid search (BM25 + dense retrieval), chunking and indexing strategies, retrieval quality scoring (MRR, NDCG), and knowledge base lifecycle management. Foundational to GenAI & LLM Operations (id=309).','Technical','Head of AI / Enterprise Architect',1);
INSERT INTO Next_Capability VALUES(319,9,59,'AI Compute & Accelerator Management','Provision, scheduling, and optimisation of GPU, TPU, and AI accelerator infrastructure for training, fine-tuning, and inference workloads. Covers GPU fleet management, CUDA/ROCm environment management, workload scheduling (SLURM, Kubernetes GPU operators), model serving infrastructure (Triton Inference Server, vLLM, TorchServe), inference cost optimisation (quantisation, batching, caching), and AI network fabric management (InfiniBand, RoCE). Enables the compute foundation for all AI lifecycle activities.','Technical','Head of Infrastructure / AI Platform Lead',1);
