INSERT INTO Next_CapabilityInvestmentCost VALUES(304,305,2.5,'Supply Chain Security: SBOM tooling, dependency scanning integration, supplier attestation programme, policy and process build. Higher than default — requires toolchain investment and supplier engagement programme.','2026-03-07 09:59:58');
INSERT INTO Next_CapabilityInvestmentCost VALUES(305,306,3.0,'ZTNA Architecture: SDP platform licensing, micro-segmentation implementation, policy engine design and rollout across hybrid estate. Highest of the 6 — significant architectural change programme.','2026-03-07 09:59:58');
INSERT INTO Next_CapabilityInvestmentCost VALUES(306,307,2.0,'AI Security & Model Integrity: AI threat modelling methodology, red-teaming capability, LLM guardrail tooling, model monitoring integration. Moderate — primarily a process and tooling uplift.','2026-03-07 09:59:58');
INSERT INTO Next_CapabilityInvestmentCost VALUES(307,308,1.5,'Technical Debt Management: Debt taxonomy, automated code analysis tooling (e.g. SonarQube tier), debt backlog governance process. Lower — primarily process and lightweight tooling.','2026-03-07 09:59:58');
INSERT INTO Next_CapabilityInvestmentCost VALUES(308,309,2.5,'Generative AI & LLM Operations: Enterprise LLM platform, RAG pipeline build, prompt governance tooling, hallucination monitoring. Higher — platform investment and ongoing token/compute cost.','2026-03-07 09:59:58');
INSERT INTO Next_CapabilityInvestmentCost VALUES(309,310,2.0,'Digital Twin & Simulation: Digital twin platform (e.g. NVIDIA Omniverse, AWS IoT TwinMaker, or equivalent), data integration pipeline, pilot domain build. Moderate — platform licensing and integration effort.','2026-03-07 09:59:58');
INSERT INTO Next_CapabilityInvestmentCost VALUES(310,311,2.0,'Feature Store: platform licensing (Feast OSS or Tecton/Hopsworks commercial), data engineering buildout, integration with data platform. Moderate — primarily platform and engineering effort.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityInvestmentCost VALUES(311,312,1.5,'Model Evaluation: evaluation framework tooling, benchmark dataset curation, CI/CD integration. Lower — primarily process and pipeline engineering.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityInvestmentCost VALUES(312,313,1.5,'Bias Detection: bias testing library (Fairlearn, AIF360), dataset analysis tooling, governance process build. Lower — primarily tooling and process uplift.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityInvestmentCost VALUES(313,314,2.0,'Explainability: SHAP/LIME tooling integration, explanation API development, regulatory documentation process. Moderate — platform and compliance engineering.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityInvestmentCost VALUES(314,315,2.5,'AI Regulatory Compliance: legal and compliance advisory, AI risk register system, conformity assessment process, regulatory engagement. Higher — external expertise and ongoing programme cost.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityInvestmentCost VALUES(315,316,2.5,'Predictive Analytics: ML platform extension, time-series model development, business integration for forecast consumption, retraining automation. Moderate to high — platform and delivery.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityInvestmentCost VALUES(316,317,3.0,'AI Agents: agentic framework build (LangGraph/AutoGen), enterprise guardrails, agent registry, security review, integration with enterprise systems. Highest — complex architecture and risk management investment.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityInvestmentCost VALUES(317,318,2.0,'Cognitive Search: vector database deployment, embedding model licensing, RAG pipeline build, knowledge base governance. Moderate — primarily platform and data engineering.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityInvestmentCost VALUES(318,319,3.0,'AI Compute: GPU cluster procurement or reserved cloud GPU contracts, Kubernetes GPU operators, inference server deployment, network fabric. Highest — significant infrastructure capital or committed cloud spend.','2026-03-07 10:53:30');
INSERT INTO Next_CapabilityLevel VALUES(1,291,1,'Ad Hoc','AI projects are experimental and isolated. Governance and traceability minimal.','Manual data preparation. No reproducibility.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(2,291,2,'Defined','Standardized pipelines emerging with basic model versioning.','Central model registry initiated.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(3,291,3,'Integrated','Unified MLOps platform manages training deployment and monitoring.','Automated testing and rollback enabled.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(4,291,4,'Intelligent','AI lifecycle automated with drift detection and continuous retraining.','Performance alerts and adaptive retraining active.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(5,291,5,'Adaptive','Fully autonomous model management and optimization driven by feedback loops.','Self learning pipelines and governance integrated.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(6,292,1,'Ad Hoc','No formal oversight. AI usage inconsistent and opaque.','Compliance risk high.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(7,292,2,'Defined','Initial ethical principles established. Manual reviews of models.','Occasional governance checkpoints.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(8,292,3,'Integrated','Ethical review boards and explainability frameworks embedded.','Automated audit trails in place.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(9,292,4,'Intelligent','Automated bias and compliance monitoring active.','Real time governance dashboards.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(10,292,5,'Adaptive','Dynamic compliance and bias detection tuned to regulatory changes.','Self updating governance frameworks.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(11,299,1,'Ad Hoc','Manual sustainability reporting with disconnected systems.','ESG data incomplete.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(12,299,2,'Defined','Standardized sustainability metrics emerging.','Partial automation of data collection.',NULL,1);
