INSERT INTO Next_CapabilityLevel VALUES(14,299,4,'Intelligent','AI predicts sustainability outcomes and risks.','Predictive sustainability analytics active.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(15,299,5,'Adaptive','AI driven sustainability optimization and predictive modeling.','Carbon reduction automated.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(16,302,1,'Ad Hoc','Feedback unstructured and analyzed manually.','Basic surveys only.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(17,302,2,'Defined','Basic sentiment analysis tools applied to select channels.','Limited insights available.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(18,302,3,'Integrated','Unified experience data across customer and employee touchpoints.','Cross channel analytics established.',NULL,1);
