INSERT INTO Next_CapabilityLevel VALUES(21,1,1,'Ad Hoc','The organization has defined cloud performance related kpis/metrics and aligned them with the strategic cloud objectives and critical cloud processes.','Legacy kpis & metrics mapping (baselining)\u000aenterprise speed and agility\u000akpi and metric definition and capture processes\u000afoundational esg metrics are baselined',NULL,1);
