INSERT INTO Next_CapabilityLevel VALUES(23,1,3,'Integrated','The organization has assessed cloud transformation maturity and workforce transformation characteristics on a basic level to understand current state and where major gaps exist.','Workforce transformation\u000abusiness transformation\u000acloud transformation maturity assessment {basic}\u000acloud financials\u000a_ esg metrics and kpis are included in the tbo dashboard\u000aannual sustainability report includes sustainable it approach and subsequent impact',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(24,1,4,'Intelligent','Meaningful cloud performance related data has been collected and has reached critical mass, such that meaningful baselines are created, and ad hoc queries can be run against large data sets, and data becomes predictive for future opportunities.','Integrated data for correlation and query\u000a',NULL,1);
