INSERT INTO Next_CapabilityLevel VALUES(29,50,2,'Defined','A standardized taxonomy and methodology exists for risk rating and a single record of truth is used for issue tracking.  employees are encouraged with incentives to self-identify issues and compensating controls/exceptions are used frequently.','Compliance requirements inventory\u000arisk management framework\u000aaccountability and incentives \u000a_defined & documented strategy\u000a_defined & documented standards\u000a_defined & documented guidelines\u000a_defined & documented requirements \u000arisk analysis and evaluation process\u000arisk treatment process documented\u000arisk owners process documented \u000arisk register in place \u000arisk impact analysis process',NULL,1);
