INSERT INTO Next_CapabilityLevel VALUES(32,2,4,'Intelligent','The organization builds solutions to be sustainable and long-term and clearly communicates timelines and deadlines.  there as a heavy reliance on incentives to ensure owners  accept accountability.','Proactive risk mitigation in design\u000abehavior monitoring tools\u000aadvanced analytics tools \u000asocial media monitoring tools \u000aproactive risk treatment process \u000aautomated control assessment and evaluation process.',NULL,1);
