INSERT INTO Next_CapabilityLevel VALUES(35,3,2,'Defined','The transformation business offices fully enabled and governing all cloud activities regardless of consumption model. the tbo is the central point for all multi-cloud standards and estate enablement.','Tbo roadmap communication \u000atbo meeting cadence finalized\u000aworkflow process to enable new functionality \u000abacklog prioritization\u000aautomated centralized dashboard \u000aestablished standards (with esg)\u000adefined tbo exception process\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(36,3,3,'Integrated','The transformation business office is an integral part of the overall organizational transformation with active engagement with devops, containerization, data architectures, and sustainability as they prepare for hybrid/multi-cloud workload enablement and migration.','Tbo enablement process refined \u000acommon set of kpis measuring progress \u000afully automated dashboard with esg metrics \u000anew provider functionality actively reviewed\u000amulti-cloud providers\u000aannual sustainability report includes sustainable it approach and subsequent impact',NULL,1);
