INSERT INTO Next_CapabilityLevel VALUES(415,80,4,'Intelligent','Problem & incident management is optimized self-healing and a proactive approach to site/service reliability engineering. the organization supports multi-cloud incident response with an orchestrated course of action that is tailored to the characteristics of the host environment.','Preparation\u000acommunication & facilities\u000a_encryption software\u000a\u000aanalysis\u000a_hunting\u000a\u000aincident mitigation\u000a_deception techniques\u000a_self-healing\u000a_sre techniques\u000a\u000a~~~\u000a\u000acontainment, eradication, and recovery\u000a_multi-cloud incident response\u000a_orchestrated course of action/response\u000a_extended detection & response (xdr)\u000a\u000apreparation\u000aincident mitigation\u000a_digital innovation & forensics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(416,81,1,'Ad Hoc','The enterprise establishes the foundation of their threat & vulnerability management approach, with an emphasis on:\u000a- strategy\u000a- policy\u000a- process & procedure\u000a- up to data inventory\u000a- source of record','Threat & vulnerability mgmt. strategy\u000a_threat & vulnerability mgmt. policy\u000a_threat & vulnerability mgmt. standards\u000a_threat & vulnerability mgmt. architecture\u000a_threat & vulnerability mgmt. plan\u000a_threat & vulnerability mgmt. guidelines\u000a_threat & vulnerability mgmt. requirements\u000a_manual vulnerability assessments\u000a_risk taxonomy\u000a_vulnerability assessment solution\u000a_ad hoc scans\u000a_vulnerability prioritization\u000a_infrastructure vulnerability mgmt.\u000a_application vulnerability mgmt.\u000a_vulnerability scanning\u000a_vulnerability source of record\u000a_vulnerability tracking & source of record\u000a_source code scanning\u000a_asset inventory',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(417,81,2,'Defined','The organization is effectively performing threat & vulnerability management. a dedicated team leverages documented slas to establish expectations, and root cause analysis is paramount to addressing opportunities for improvement at scale.','Process & procedure\u000a_kpis & metrics\u000a_vulnerability mgmt. team\u000a_mitigation slas (by category/level of importance)\u000a_regulatory framework compliance\u000a_database vulnerability mgmt.\u000a_database compliance testing\u000a_network compliance testing\u000a_infrastructure compliance testing\u000a_external library vulnerability analysis\u000a_scheduled scans\u000a_scan to patch lifecycle\u000a_threat & vulnerability mgmt. reporting\u000a_service discovery\u000a_root cause analysis',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(418,81,3,'Integrated','The organization leverages risk-based prioritization and end-to-end process measurement combined with trend analysis to accelerate time to value and reduce risk.','End-to-end process measurement\u000a_efficiency metrics\u000a_risk-based prioritization\u000a_trend analysis\u000a_security advisory & alerting\u000a_service dependency analysis & mgmt.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(419,81,4,'Intelligent','The organization utilizes external threat intelligence feeds and subscriptions plus threat hunting to augment their proactive countermeasures and stay one step ahead of attackers.','Integration with enterprise risk mgmt.\u000a_threat intelligence feeds/subscriptions\u000a_threat hunting\u000a_threat vector prioritization\u000a_threat-driven metrics & trends',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(420,81,5,'Adaptive','The organization leverages continuous patching to automate time-consuming and difficult manual processes, utilizing ai/ml capabilities to manage the many vulnerabilities that lead to security threats.','Unified business & it processes\u000a_continuous patching\u000a_intelligence & advisory services\u000a_bug bounty program',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(421,82,1,'Ad Hoc','Their employees complete their ordered tasks in the allocated time. their employees have enough skills as long as they can perform their role, no further skill development is required.','Work time policies\u000awellbeing policies',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(422,82,2,'Defined','Their employees work at a relative specific time and location. in some areas of the organization,  first initiatives of diversity and well-being are being implemented on an individual basis. overachievement of individual targets is being recognized.','Target setting process \u000awellbeing offerings\u000adiversity and inclusion leadership training.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(423,82,3,'Integrated','They support their employees in self organizing themselves in e.g. volunteer groups or non-work interest groups. through enabling flexible weekly work schedules and limited part-time offerings they are able to attract a more diverse workforce, which is seen as an advantage and tracked throughout the organization. they take the development and upskilling of their people serious and ensure their compensation is adequate in comparison.','Flexible work options\u000aindividual goal setting processes\u000aextracurricular activities to promote wellbeing and health \u000adiversity and inclusion training for all employees\u000aannual employee satisfaction program\u000adocumented mentorship program\u000amarket compensation program and organizational policy\u000adedicated engagement communication strategy',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(424,82,4,'Intelligent','They ensure their people have the flexibility to encompass their life and work. through flexible worktime, time account and part time offering their employees have the opportunity to create their work life balance. through wellbeing programs they offer a work environment beyond just completing task and following orders. their employees have the opportunity to create and participate though satisfaction reviews, where they can voice their opinions and expect actions to follow','Part time offering and processes\u000awellbeing programs\u000aemployee survey \u000acontinuous employee feedback loop',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(425,82,5,'Adaptive','They enable their employees to develop and execute their own ideas. by creating a diverse environment they embrace their differences. they regularly review their employees satisfaction and derive clear actions from it to build a better environment. the wellbeing of their employees is a priority and they empower everyone to drive their own personal development.','Flexible working options and processes\u000apersonal development offerings\u000ahealth and wellbeing tracking',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(426,83,1,'Ad Hoc','They are aware of the need of modern digital skills, some of them have been defined and few of their employees are becoming more skilled in this area. their employees ask for mentoring and coaching. they define a career as ladder climbing and see the advancement by achieving a higher level.','Specific career paths\u000aemployee interest tracking (manager awareness)\u000alearning journey based on employee initiative',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(427,83,2,'Defined','They define some modern digital roles and these are formalized. in conjunction pockets of learning curriculums start to appear. additionally cross functional work and collaboration is being tested in some departments. mentoring and coaching is not offered through programs but executed on an informal unstructured individual basis.','\u000ajob roles and titles for some roles\u000aemployee interest tracking spans it group\u000alearning journey supported by manager',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(428,83,3,'Integrated','They define the criteria and requirements for all digital modern roles and their career paths. they establish learning journeys for critical roles. cross functional collaboration is demonstrating clear results. talent programs begin to appear and offer opportunities to develop future leaders. career development conversations are part of standard processes and additional offer such as mentoring and coaching programs have been established.','Modern digital role specific career paths\u000amodern digital job roles, titles, and responsibility\u000amodern digital role related learning journey',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(429,83,4,'Intelligent','They empower their employees to develop through modern digital career paths and accompanying learning journeys across all levels. their top talents are developed through talent programs and horizontal careers are being developed. they focus on internal development whenever possible and change is driven by dedicated and strategic advisory roles.','Career paths span organization-wide\u000amodern digital specific job roles, titles, and responsibility',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(430,83,5,'Adaptive','They drive modern digital role career paths. all roles within the organization are documented, defined and underpinned by integrated learning journeys. the fully integrated talent technology ecosystem is supported by fluid arrangements and horizontal career paths to foster cross departmental collaboration and learning opportunities.','Multiple talent acquisition pipelines\u000amodern digital role specific career paths (aligned to learning journeys)\u000amodern digital role learning journey (aligned to career paths)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(431,84,1,'Ad Hoc','They hire people to perform specific tasks and roles on an ad hoc basis. they thereby rely on outsourced forces or agencies to find a suitable candidate. the department hiring the individual knows best what kind of candidate they want and they therefore drive the recruitment process, rather than hr, creating a unstructured hiring process.','Skills business case library\u000arole description library\u000aemployee hiring processes\u000aemployee onboarding processes\u000anew hire contribution tracking mechanisms\u000athird-party source relationships\u000atalent needs identification process\u000amentorship program',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(432,84,2,'Defined','They attract candidates through a variety of channels, through current employees, their attractive employer brand, social media, candidate pipelines and intern programs or by hiring contractor or temps. recruitment is run in house allowing for occasional collaboration between hr and the departments to fill vacant positions.  diversity, for them is starting to become a topic and recruitment is considered a part of the overall strategy to fulfill diversity ambitions. when candidates apply they receive communication from them in a timely manner to inform them about the status of their application, allowing for talent pools and pipelines to emerge. their compensation is up to the market standard','Role requirements\u000aemployee profiles\u000asearching for candidates processes\u000ainterviewing candidates processes\u000ahiring candidates processes\u000aonboarding candidates processes\u000amarketing/brand engagement process\u000areferral bonus program\u000atotal compensation package\u000amarket compensation service subscription',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(433,84,3,'Integrated','They have created and established hiring processes. the candidate journey is similar or the same no matter where within the organization the individual applies. hiring needs are regularly discussed between hr and the departments and hr has developed a recruitment strategy to plan ahead for future demand. to attract talent events are organized, social media is utilized and employees are positioned as band ambassadors. short term employment as opportunities to shape and mold potential future employees and start providing a pipeline for permanent hires. once and individual has been hired a modified employee on-boarding processes is started to reflect requisite learning journeys. to develop their employees they provide sme-level training and learning journeys and communicate advancement paths','Skill gap identification mechanisms\u000ahiring plans (to meet demand)\u000apartnership management mechanisms\u000astart-to-finish recruiting processes\u000aexternal recruiting pipeline\u000acustomer journey mapping process \u000adocumented onboarding process\u000alearning journeys \u000acareer paths\u000aemployee surveys',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(434,84,4,'Intelligent','They  see their employees as a long term asset. long term development plans for employees are in place, by offering e.g. job-rotations. succession planning processes for experts and leaders are established, ensuring some roles are (back-)filled before they even become vacant. to attract talent strategic partnerships with universities have been set up and local talent pools are leveraged. their recruitment processes are optimized through boolean searches. employees testimonials are utilized to promote the employer. diversity is tracked through kpis and is part of the overall strategy of the organization. human capital management is integrated into human experience management.','Recruiting pipeline including external, job boards, campus recruiting, etc.\u000agrowth planning instead of gap-filling planning\u000ahiring-for-growth planning and processes\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(435,84,5,'Adaptive','They see talent acquisition as an competitive advantage as they attract talent from competitors and other industries. they hire candidates on their potential they see in them rather than the current skills set they have to offer. by leveraging global talent pools and matching unsuccessful candidates with open vacancies they take a proactive approach towards recruitment. their culture, diversity and the work environment they create are differentiator which attract candidates. hiring on a cultural fit and potential is more important than aligning the candidate to a job description.','Reputation tracking and metrics\u000aexecutive / leadership hiring tracking\u000arecruitment kpis',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(436,85,1,'Ad Hoc','They have high-level information about the change vision, strategy and planning with initial engagement of the communications team.','High-level information on change vision, strategy and planning\u000acommunications team awareness\u000acommunications team commitment',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(437,85,2,'Defined','They have a communication plan on change vision, strategy and planning, and are in alignment with the communications team. there''s a need for regular communication about the change vision and strategy so that most employees are aware.  there are basic mechanisms in place to track employee awareness and acceptance of communications around change vision and strategy.','Communications team alignment\u000acommunications stakeholder map\u000acommunication plan on change vision, strategy and planning\u000acommunication channels & mediums\u000aemployee awareness of change vision, strategy and planning',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(438,85,3,'Integrated','They have a comprehensive organization-wide communication plan on change vision, strategy and planning, with active engagement of the communications team. there is frequent and robust, organization-wide communication, providing information on change vision, strategy and planning, that is consistent across all management layers. they have active involvement of c-level in communicating and explaining the change vision, strategy and planning and defined kpis are defined to track employee awareness.','Communications team engagement\u000arobust communication plan about change vision, strategy and planning\u000amaterial for c-level to communicate about change vision, strategy and planning\u000akpis to track employee awareness',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(439,85,4,'Intelligent','They have c-level executives to drive the communicating about the change vision, strategy and planning. they have a well established process for two-way communication about the change vision, strategy and planning with a formal feedback process  to improve communication. they have a process to educate multipliers (e.g. line managers) and a central dashboard of kpis to track employee awareness and acceptance of communications. they have most employees informed about and aware of the change vision, strategy and planning, as demonstrated by the kpis.','Established process for two-way communication\u000aformal feedback process on communication\u000acoaching available for c-level to drive communication about vison and strategy\u000acentral kpi dashboard',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(440,85,5,'Adaptive','They have a constant flow of in-depth change vison, strategy and planning information targeted at various personas and via a variety of communication means. they have feedback on this communication immediately addressed and acted upon. they have a central, constantly updated dashboard of kpis to track employee awareness and engagement and all employees to are aware of and engaged in the change vision, strategy and planning, as demonstrated by the kpis.','Constant flow of in-depth change communication\u000awell-established and utilized formal feedback process on communication\u000acentral, constantly updated dashboard of kpi\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(441,86,1,'Ad Hoc','They have initial people and organization related communication, leading to a enterprise-level communications plan. this requires an executive sponsor and initial engagement of the communications team and hr.','High-level information on people and organizations\u000acommunications plan (on enterprise level)\u000aexecutive sponsor\u000acommunications team awareness\u000ahr awareness',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(442,86,2,'Defined','They have regular communication about people and organization related topics, with alignment of the communications team and hr, to ensure most employees are aware of the communication about people and organization related topics.','Regular communication about people and organization related topics\u000acommunications team alignment\u000ahr alignment\u000acommunications stakeholder map\u000acommunication channels & mediums\u000aemployee awareness of communication',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(443,86,3,'Integrated','They have a comprehensive organization-wide communication plan regarding people and organizations with frequent, robust communication and a communications feedback loop. the communications team and hr are actively engaged in communication and team leaders  communicate and explain what is changing, why it''s happening and what''s needed from the employees. kpis are defined to track employee awareness of communications regarding people and organizations.','Communications team engagement\u000ahr engagement\u000acomprehensive organization-wide communication plan regarding people and organizations\u000acommunications feedback loop\u000amaterial for team leaders to communicate about people and organization related topics\u000akpis to track employee awareness',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(444,86,4,'Intelligent','They have team leaders to actively drive the communication about people and organization related topics and to lead as example. a formal feedback process is implemented to improve communication and  a variety of communication tools are available to drive push and pull communication. a central dashboard of kpis tracks employee awareness and acceptance of communications, and according to the kpis, most employees are informed and aware of people and organization related topics.','Comprehensive information on people and organizations\u000arobust communication plan about people and organizational related topics\u000aformal feedback process on communication\u000acommunications content curation\u000acoaching available for team leaders and c-level to drive communication about people and organizations\u000acentral kpi dashboard',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(445,86,5,'Adaptive','They have a constant flow of in-depth information about people and organization related topics, targeted at various personas and via a variety of communication means. they access to portals that auto-populate with the most relevant and up-to-date information and resources for various stakeholders and constantly monitor kpis to measure change awareness.  well-established programs are in place to adapt communication plans  as needed. an outbound marketing communications plan is developed.','Well-established and utilized formal feedback process on communication\u000atargeting and personalizing communications\u000aoutbound marketing communications\u000acentral constantly updated kpi dashboard',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(446,87,1,'Ad Hoc','They have at least a few individuals in the organization aware of what training and tooling resources are available to them.','Access to training products/services',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(447,87,2,'Defined','They have all employees aware of what training and tooling resources are available to them.','Employee awareness of upskilling resources',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(448,87,3,'Integrated','They have frequent robust, organization-wide communication, providing information on updates to learnings, capabilities, and tools. team leaders communicate about the skill and competency development possibilities and basic mechanisms in place to track employee awareness and acceptance of communications about skill and competence development.','Guidelines on information about upskilling\u000acommunication plan about upskilling\u000amaterial available for team leaders to communicate about development possibilities',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(449,87,4,'Intelligent','They have team leaders to drive the communication about skill and competence development. a formal feedback process is implemented to improve communication about the training and tooling resources that are available, with a central dashboard of kpis to track employee awareness and acceptance.','Robust organization-wide communication plan about upskilling\u000aformal feedback process\u000acoaching available to team leaders to drive the communication about development possibilities\u000akpi dashboard to track employee awareness',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(450,87,5,'Adaptive','They have easy to access portals that auto-populate with the most relevant and up-to-date learning and upskilling capabilities are available for each individual. a central, constantly updated set of kpis are used to track employee awareness, acceptance and engagement of communications regarding upskilling and according to the kpis, all employees are fully informed of, aware of, and engaged in learning/capabilities/tools that are available to them.','Constant flow of communication on upskilling options and employee development opportunities\u000awell-established and utilized formal feedback process on communication\u000acentral, constantly updated kpi dashboard to track employee awareness and engagement',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(451,90,1,'Ad Hoc','As part of the comprehensive esg strategy, it leadership is actively participating with the development of the diversity & inclusion program.  a common vision is defined & a communication plan is developed.','Diversity & inclusion vision\u000ait diverity & inclusion strategy\u000astakeholder map\u000acurrent state metrics baselined and understood',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(452,91,1,'Ad Hoc','As part of the comprehensive esg strategy, it leadership is actively participating with the development of the diversity & inclusion program.  a common vision is defined & a communication plan is developed.','Diversity & inclusion vision\u000ait diverity & inclusion strategy\u000astakeholder map\u000acurrent state metrics baselined and understood',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(453,90,2,'Defined','Diversity, equity & inclusion steering committee is being defined and policies and standards are established.  diversity and inclusion expectations are communicated broadly.','Diversity, equity & inclusion steering committee \u000adiversity, equity & inclusion roadmap (time bound)\u000adiversity, equity & inclusion employee awareness program \u000apublic diversity, equity & inclusion disclosure\u000adiversity, equity & inclusion vendor management\u000akpis and metrics\u000adiversity, equity & inclusion policy\u000aboard reporting \u000acommunication plan \u000adiversity & inclusion initiatives are underway',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(454,91,2,'Defined','Diversity, equity & inclusion steering committee is being defined and policies and standards are established.  diversity and inclusion expectations are communicated broadly.','Diversity, equity & inclusion steering committee \u000adiversity, equity & inclusion roadmap (time bound)\u000adiversity, equity & inclusion employee awareness program \u000apublic diversity, equity & inclusion disclosure\u000adiversity, equity & inclusion vendor management\u000akpis and metrics\u000adiversity, equity & inclusion policy\u000aboard reporting \u000acommunication plan \u000adiversity & inclusion initiatives are underway',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(455,92,3,'Integrated','Diversity, equity & inclusion governance, kpis and monitoring is in place.','Diversity and inclusion training\u000adocumented it diversity, equity & inclusion goals\u000arecruitment process designed to attract and retain a diverse workforce\u000aemployee resource groups \u000adiversity & inclusion kpis reported and monitored',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(456,93,3,'Integrated','Diversity, equity & inclusion governance, kpis and monitoring is in place.','Diversity and inclusion training\u000adocumented it diversity, equity & inclusion goals\u000arecruitment process designed to attract and retain a diverse workforce\u000aemployee resource groups \u000adiversity & inclusion kpis reported and monitored',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(457,92,4,'Intelligent','Dedicated it sustainable team created','Diversity, equity & inclusion team\u000a3rd party diversity, equity & inclusion verification \u000avendor compliance \u000a \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(458,93,4,'Intelligent','Dedicated it sustainable team created','Diversity, equity & inclusion team\u000a3rd party diversity, equity & inclusion verification \u000avendor compliance \u000a \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(459,92,5,'Adaptive','Chief diversity officer is defined with board oversight','Chief diversity officer\u000abiannual board diversity, equity & inclusion updates\u000adiversity and inclusion leadership program \u000adiversity, equity & inclusion in executive compensation plans',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(460,93,5,'Adaptive','Chief diversity officer is defined with board oversight','Chief diversity officer\u000abiannual board diversity, equity & inclusion updates\u000adiversity and inclusion leadership program \u000adiversity, equity & inclusion in executive compensation plans',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(461,94,1,'Ad Hoc','They need each team member to understand what tasks they have to complete and how to do this. managers will check the results regularly and provide instructions if the results need improvement. managers communicate with their teams when needed to ensure a seamless workflow and good results. managers decide who needs upskilling and select the right training. they also review how leadership is implemented and consider applying changes.','Work instructions\u000afirst definition of a leadership culture \u000adocumented accountability model',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(462,95,1,'Ad Hoc','They need each team member to understand what tasks they have to complete and how to do this. managers will check the results regularly and provide instructions if the results need improvement. managers communicate with their teams when needed to ensure a seamless workflow and good results. managers decide who needs upskilling and select the right training. they also review how leadership is implemented and consider applying changes.','Work instructions\u000afirst definition of a leadership culture \u000adocumented accountability model',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(463,94,2,'Defined','They need each team member to understand what responsibilities they have. they need to know the roles they play within the team and how they contribute to team success. the team members are free how to perform tasks assigned by their manager within their given responsibilities. leadership styles are based on team needs and the situation given. most teams have regular team meetings in place to discuss progress, issues and successes. leaders occasionally ask for team feedback. team members begin to feel ownership for their own progress and development.','Documentation of roles and responsibilities within teams\u000aschedule for team meetings\u000aexpectations towards team members documented\u000aleadership training: communication with team, asking for feedback\u000ateam training: taking responsibility for their work and career',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(464,95,2,'Defined','They need each team member to understand what responsibilities they have. they need to know the roles they play within the team and how they contribute to team success. the team members are free how to perform tasks assigned by their manager within their given responsibilities. leadership styles are based on team needs and the situation given. most teams have regular team meetings in place to discuss progress, issues and successes. leaders occasionally ask for team feedback. team members begin to feel ownership for their own progress and development.','Documentation of roles and responsibilities within teams\u000aschedule for team meetings\u000aexpectations towards team members documented\u000aleadership training: communication with team, asking for feedback\u000ateam training: taking responsibility for their work and career',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(465,94,3,'Integrated','They need their teams and their leaders to discuss ways of working, goals, and issues in a open way. upcoming decisions are discussed within the team and everybody is encouraged to voice their views and propose potential solutions to their leader who will take those into account when making decisions. all of this is done in a way that values different opinions and appreciates diversity. there is a 2-way communication between team and leaders in place and leaders welcome and actively ask for feedback. each team member feels a strong sense of ownership with regards to their own and the team success. leaders act as change agents actively leading their team through change.','Company vision documented and cascaded down through organization\u000acommunication plan and material describing the leadership approach\u000aleadership training: leading through change, diversity & inclusion\u000ateam collaboration training/workshops\u000adocumented feedback process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(466,95,3,'Integrated','They need their teams and their leaders to discuss ways of working, goals, and issues in a open way. upcoming decisions are discussed within the team and everybody is encouraged to voice their views and propose potential solutions to their leader who will take those into account when making decisions. all of this is done in a way that values different opinions and appreciates diversity. there is a 2-way communication between team and leaders in place and leaders welcome and actively ask for feedback. each team member feels a strong sense of ownership with regards to their own and the team success. leaders act as change agents actively leading their team through change.','Company vision documented and cascaded down through organization\u000acommunication plan and material describing the leadership approach\u000aleadership training: leading through change, diversity & inclusion\u000ateam collaboration training/workshops\u000adocumented feedback process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(467,94,4,'Intelligent','They need leaders to act as coaches, providing guidance rather than instructions. they need to support and coach their team members especially in decision making processes. leaders provide direction and vision and set guardrails for the team in which context they operate. they need all leaders to frequently and actively seek for input from the team, especially when making decisions. this also means encouraging team members to find their own solutions for problems and they are empowered to make their own decisions which also means accepting a certain level of risk. leaders only intervene in critical situations. to be able to do so leaders provide their teams with all the resources and information they need. two-way feedback is an established routine and leaders understand that they need team feedback to grow. the leadership style supports the enterprise ethos, ambitions, and goals. diversity and inclusion are main focus areas in  leadership development','Company vision discussed and adopted in each organization\u000atraining for leaders: coaching skills, empowerment, self-management\u000ateam training: business acumen, decision making, taking risks\u000atraining for all: diversity & inclusion\u000akpi on diversity & inclusion\u000awide access to business information',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(468,95,4,'Intelligent','They need leaders to act as coaches, providing guidance rather than instructions. they need to support and coach their team members especially in decision making processes. leaders provide direction and vision and set guardrails for the team in which context they operate. they need all leaders to frequently and actively seek for input from the team, especially when making decisions. this also means encouraging team members to find their own solutions for problems and they are empowered to make their own decisions which also means accepting a certain level of risk. leaders only intervene in critical situations. to be able to do so leaders provide their teams with all the resources and information they need. two-way feedback is an established routine and leaders understand that they need team feedback to grow. the leadership style supports the enterprise ethos, ambitions, and goals. diversity and inclusion are main focus areas in  leadership development','Company vision discussed and adopted in each organization\u000atraining for leaders: coaching skills, empowerment, self-management\u000ateam training: business acumen, decision making, taking risks\u000atraining for all: diversity & inclusion\u000akpi on diversity & inclusion\u000awide access to business information',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(469,94,5,'Adaptive','They need leaders to provide a long-term vision and a strong sense of purpose. while traditional reporting lines become less important and are primarily need for hr processes, team members define their own goals and ways of working. this means that leaders and team members are aligned and provide feedback mutually. rigid team structures disappear more and more, and people work in varying roles and responsibilities in flexible and dynamic teams. to support this there is an organization wide framework of rules in place that describes how run it. as long as people adhere to these core rules, everything is possible. diversity and inclusion are internalized as core principles in all leadership actions and in the organizational setup.','Strong company wide vision and purpose statements, adoption workshops in each organization and team\u000aorganization-wide framework of basic rules how to collaborate and achieve outcomes together\u000awell-defined process how to set team goals\u000aleadership training: diversity & inclusion, "new" leadership\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(470,95,5,'Adaptive','They need leaders to provide a long-term vision and a strong sense of purpose. while traditional reporting lines become less important and are primarily need for hr processes, team members define their own goals and ways of working. this means that leaders and team members are aligned and provide feedback mutually. rigid team structures disappear more and more, and people work in varying roles and responsibilities in flexible and dynamic teams. to support this there is an organization wide framework of rules in place that describes how run it. as long as people adhere to these core rules, everything is possible. diversity and inclusion are internalized as core principles in all leadership actions and in the organizational setup.','Strong company wide vision and purpose statements, adoption workshops in each organization and team\u000aorganization-wide framework of basic rules how to collaborate and achieve outcomes together\u000awell-defined process how to set team goals\u000aleadership training: diversity & inclusion, "new" leadership\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(471,96,1,'Ad Hoc','They need performance management in place with some basic standardization of the process. performance management procedures are defined on a basic level. they need each line manager to own the process how they handle performance management, but they are given freedom how much effort the put into it. performance measures are rather set by each manager within their teams. performance feedback is starting to become a routine. recognition for good performance is left to the individual line manager and takes place occasionally. underperformers are managed as needed on a team level with the line manager making the required decisions and driving the process.','Documentation of basic performance process\u000afirst establishment of objectives\u000amerit adjustments',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(472,97,1,'Ad Hoc','They need performance management in place with some basic standardization of the process. performance management procedures are defined on a basic level. they need each line manager to own the process how they handle performance management, but they are given freedom how much effort the put into it. performance measures are rather set by each manager within their teams. performance feedback is starting to become a routine. recognition for good performance is left to the individual line manager and takes place occasionally. underperformers are managed as needed on a team level with the line manager making the required decisions and driving the process.','Documentation of basic performance process\u000afirst establishment of objectives\u000amerit adjustments',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(473,96,2,'Defined','They need to have a consistent process for performance reviews in place. tools need available to support this process. performance goals are cascaded down from higher management levels and used as a basis for individual goals. individual performance objectives are clearly communicated to team members on at least an annual basis. individual performance reviews take place at least once per year. a general feedback culture is  starting to show.  overachieving goals is recognized by the line manager and communicated within the team. overachievement leads to individual benefits. there are guidelines available how to deal with underperformers, the process is owned by the line manager.','Documentation of consistent performance process\u000atools & platforms to manage the process\u000acommunication of goals of higher management\u000aguidelines how to deal with underperformers\u000acompensation planning\u000amerit & bonus rewards\u000aperformance improvement plan (pip) or equivalent\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(474,97,2,'Defined','They need to have a consistent process for performance reviews in place. tools need available to support this process. performance goals are cascaded down from higher management levels and used as a basis for individual goals. individual performance objectives are clearly communicated to team members on at least an annual basis. individual performance reviews take place at least once per year. a general feedback culture is  starting to show.  overachieving goals is recognized by the line manager and communicated within the team. overachievement leads to individual benefits. there are guidelines available how to deal with underperformers, the process is owned by the line manager.','Documentation of consistent performance process\u000atools & platforms to manage the process\u000acommunication of goals of higher management\u000aguidelines how to deal with underperformers\u000acompensation planning\u000amerit & bonus rewards\u000aperformance improvement plan (pip) or equivalent\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(475,96,3,'Integrated','They need performance goal setting a collaborative effort between manager and individuals. they implement a  formal performance review process throughout the entire organization. this process itself is continuously reviewed and improved. every employee experiences several performance checkpoints per year. they have regular conversations about skill and career development with their line manager. they have plans in place how to manage different levels of underperformers. they also have plans and programs in place to recognize top individual performance on a departmental level. all leaders have a "tool kit" that allows them to provide instant recognition and rewards based on exceptional performance.','Documentation of ongoing performance evaluation process\u000acalibration process to align performance evaluation between different teams\u000aall leaders trained on performance management and giving feedback\u000adetailed plans and support tools how deal with underperformers\u000abroad reward system for top-performers \u000aoff-cycle bonuses & rewards\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(476,97,3,'Integrated','They need performance goal setting a collaborative effort between manager and individuals. they implement a  formal performance review process throughout the entire organization. this process itself is continuously reviewed and improved. every employee experiences several performance checkpoints per year. they have regular conversations about skill and career development with their line manager. they have plans in place how to manage different levels of underperformers. they also have plans and programs in place to recognize top individual performance on a departmental level. all leaders have a "tool kit" that allows them to provide instant recognition and rewards based on exceptional performance.','Documentation of ongoing performance evaluation process\u000acalibration process to align performance evaluation between different teams\u000aall leaders trained on performance management and giving feedback\u000adetailed plans and support tools how deal with underperformers\u000abroad reward system for top-performers \u000aoff-cycle bonuses & rewards\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(477,96,4,'Intelligent','They need leaders to regularly communicate the performance review process and results to apply consistency across teams. performance goal setting is a collaborative effort between manager, team and individuals. they have implemented informal reviews and feedback formats, that also allow for peer feedback. feedback is considered an ongoing process and is given by  leaders and peers. individual and team success are recognized on an organization level. they use a consistent and well-structured process for talents evaluation, including 360° feedback. special celebration programs are in place for overachievers.\u000athey use a variety of programs to manage underperformers that allow for highly individualized interventions.','Plan for ongoing communication on performance management\u000aprocess description for goal setting as a joint effort\u000afeedback tools\u000atraining: providing feedback\u000awell-defined talent evaluation process\u000aperformance management feedback loop (for continuous improvement)\u000aintegration with talent management and succession planning',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(478,97,4,'Intelligent','They need leaders to regularly communicate the performance review process and results to apply consistency across teams. performance goal setting is a collaborative effort between manager, team and individuals. they have implemented informal reviews and feedback formats, that also allow for peer feedback. feedback is considered an ongoing process and is given by  leaders and peers. individual and team success are recognized on an organization level. they use a consistent and well-structured process for talents evaluation, including 360° feedback. special celebration programs are in place for overachievers.\u000athey use a variety of programs to manage underperformers that allow for highly individualized interventions.','Plan for ongoing communication on performance management\u000aprocess description for goal setting as a joint effort\u000afeedback tools\u000atraining: providing feedback\u000awell-defined talent evaluation process\u000aperformance management feedback loop (for continuous improvement)\u000aintegration with talent management and succession planning',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(479,96,5,'Adaptive','They need performance goals primarily planned in a bottom-up approach to support agile ways of working. for this they set a frame (e.g., organization vision and goals, basic rules) in which the goal setting has to take place. performance is usually managed by the teams themselves, including managing high and low performing individuals. for this there are processes and meeting structures in place to discuss individual and team performance (retrospectives). this is supported by a strong feedback culture within each team. the focus lies on team and organizational performance while still appreciating the contribution of individuals. there are organization-wide programs in place to recognize and celebrate overachieving teams.','Documentation on team driven performance management process\u000aestablished cadence of retrospectives and feedback sessions\u000ateam coaching on feedback culture',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(480,97,5,'Adaptive','They need performance goals primarily planned in a bottom-up approach to support agile ways of working. for this they set a frame (e.g., organization vision and goals, basic rules) in which the goal setting has to take place. performance is usually managed by the teams themselves, including managing high and low performing individuals. for this there are processes and meeting structures in place to discuss individual and team performance (retrospectives). this is supported by a strong feedback culture within each team. the focus lies on team and organizational performance while still appreciating the contribution of individuals. there are organization-wide programs in place to recognize and celebrate overachieving teams.','Documentation on team driven performance management process\u000aestablished cadence of retrospectives and feedback sessions\u000ateam coaching on feedback culture',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(481,98,1,'Ad Hoc','They need each team member to focus on tasks specific to their role which are clearly laid out to them. they consider it a supporting function that  takes care of it processes running smoothly which allows the business units to achieve their results. they give clear work instructions that team members follow. they''re focus lies on stability and they are very caution in taking any risks and consider any change very carefully. this means that they rather focus on improving existing routines than driving major innovation initiatives. they want to keep disruption to a minimum. they consider a job  well-done if the tasks assigned are completed in time and the work complies with rules given. change is considered rather a challenge than an opportunity.  team members prefer to stick to routines and "business as usual".','Long-standing team routines and behavioral standards (rather unspoken than documented)\u000adefinition of "job well done"\u000aminimal, legally required compliance training',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(482,99,1,'Ad Hoc','They need each team member to focus on tasks specific to their role which are clearly laid out to them. they consider it a supporting function that  takes care of it processes running smoothly which allows the business units to achieve their results. they give clear work instructions that team members follow. they''re focus lies on stability and they are very caution in taking any risks and consider any change very carefully. this means that they rather focus on improving existing routines than driving major innovation initiatives. they want to keep disruption to a minimum. they consider a job  well-done if the tasks assigned are completed in time and the work complies with rules given. change is considered rather a challenge than an opportunity.  team members prefer to stick to routines and "business as usual".','Long-standing team routines and behavioral standards (rather unspoken than documented)\u000adefinition of "job well done"\u000aminimal, legally required compliance training',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(483,98,2,'Defined','They focus on delivering high-quality work. it is considered a supporting function that allows business units to deliver quality output. their goal is to increase efficiency and effectiveness in everything they do. they value continuous improvement and have partly standardized processes for that. they implement changes when needed but they evaluate the opportunity and risks carefully first to minimize disruption and keep daily operations running smoothly.  to further improve, employee feedback becomes more and more important to them.  they collect and analyze feedback on a regular basis and turn into action. this also means that they encourage key team members developing and sharing new ideas.','Basic process description for continuous improvement\u000adescription of basic feedback process\u000aleadership training: encourage collaboration and sharing\u000arole-specific compliance training',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(484,99,2,'Defined','They focus on delivering high-quality work. it is considered a supporting function that allows business units to deliver quality output. their goal is to increase efficiency and effectiveness in everything they do. they value continuous improvement and have partly standardized processes for that. they implement changes when needed but they evaluate the opportunity and risks carefully first to minimize disruption and keep daily operations running smoothly.  to further improve, employee feedback becomes more and more important to them.  they collect and analyze feedback on a regular basis and turn into action. this also means that they encourage key team members developing and sharing new ideas.','Basic process description for continuous improvement\u000adescription of basic feedback process\u000aleadership training: encourage collaboration and sharing\u000arole-specific compliance training',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(485,98,3,'Integrated','They need everybody to put the customer in the center of their actions and develop a strong "service mindset". meeting the external or internal customer''s needs becomes the driver of all actions. to ensure this, they measure internal and external customer satisfaction regularly and use the results to improve their processes. the focus of it is on delivering high-quality services to all business functions and delivery excellence is top-of mind and key metrics for all team members. change is a common theme to most and usually appreciated and considered an opportunity to make things better. the entire organization values continuous improvement, and it is a priority.  processes for it are standardized and monitored. they encourage everybody to come up with new ideas and part of the innovation initiatives. people start experimenting and consider errors as learning opportunities. they start to develop a "growth mindset" that puts personal and organizaitoal development in the center.','Team and leader training: develop a customer focused mindset, develop a growth mindset\u000acustomer satisfaction metrics\u000adetailed process and kpi description for continuous improvement\u000areward initiative for continuous improvement and innovation\u000ainitiatives to raise team cohesion and spirit\u000arole-specific compliance training plus reinforcement activities',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(486,99,3,'Integrated','They need everybody to put the customer in the center of their actions and develop a strong "service mindset". meeting the external or internal customer''s needs becomes the driver of all actions. to ensure this, they measure internal and external customer satisfaction regularly and use the results to improve their processes. the focus of it is on delivering high-quality services to all business functions and delivery excellence is top-of mind and key metrics for all team members. change is a common theme to most and usually appreciated and considered an opportunity to make things better. the entire organization values continuous improvement, and it is a priority.  processes for it are standardized and monitored. they encourage everybody to come up with new ideas and part of the innovation initiatives. people start experimenting and consider errors as learning opportunities. they start to develop a "growth mindset" that puts personal and organizaitoal development in the center.','Team and leader training: develop a customer focused mindset, develop a growth mindset\u000acustomer satisfaction metrics\u000adetailed process and kpi description for continuous improvement\u000areward initiative for continuous improvement and innovation\u000ainitiatives to raise team cohesion and spirit\u000arole-specific compliance training plus reinforcement activities',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(487,98,4,'Intelligent','They consider it a main contributor to business success and see them working at eye-level with the business units. everybody takes accountability for their outcomes and feel responsible for the outcomes of the entire team. all team members react on changing requirements in a swift and agile manner. everybody is encouraged to try out new things, take risk and think out-of-the-box. they reward new ideas and bold moves. people embrace change and consider it an opportunity to develop themselves and the organization. people broadly demontrate a growth mindset. continuous improvement and disruptive innovation are strategic priorities and integral part of every job and everybody''s responsibility.  diversity of thought and background is embraced by the team and considered a foundation of growth. people feel proud of working for the organization and contributing to the overall business success.','Training: develop a business mindset, dealing with failure, driving change, agile ways of working\u000akpi outcome based for all organizations\u000areward process for taking ownership and leadership\u000ateam coaching\u000ainitiatives to raise pride and identification with organization\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(488,99,4,'Intelligent','They consider it a main contributor to business success and see them working at eye-level with the business units. everybody takes accountability for their outcomes and feel responsible for the outcomes of the entire team. all team members react on changing requirements in a swift and agile manner. everybody is encouraged to try out new things, take risk and think out-of-the-box. they reward new ideas and bold moves. people embrace change and consider it an opportunity to develop themselves and the organization. people broadly demontrate a growth mindset. continuous improvement and disruptive innovation are strategic priorities and integral part of every job and everybody''s responsibility.  diversity of thought and background is embraced by the team and considered a foundation of growth. people feel proud of working for the organization and contributing to the overall business success.','Training: develop a business mindset, dealing with failure, driving change, agile ways of working\u000akpi outcome based for all organizations\u000areward process for taking ownership and leadership\u000ateam coaching\u000ainitiatives to raise pride and identification with organization\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(489,98,5,'Adaptive','They consider it a major innovation engine that explores and drives new business areas. all team members understand their role in the value chain and how they contribute to the overall success. innovation is a continuous process and leads to constant increase of value. change is considered necessary and without it, the organization is stalled. multiple change projects are underway all the time and are frequently driven bottom-up. people pro-actively start new initiatives to explore new areas for potential future business. that means that taking risk and experimenting is a habit and failure considered as learning opportunity.  people openly share their learnings and are keen to learn from others. work is performed in an agile way, speed and customer satisfaction are key measures. continuous improvement is a strategic priority across all departments and adoption is high and formalized across all teams.','Training: developing new business ideas, creativity, change mindset\u000akpi for sharing and cross-team innovation',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(490,99,5,'Adaptive','They consider it a major innovation engine that explores and drives new business areas. all team members understand their role in the value chain and how they contribute to the overall success. innovation is a continuous process and leads to constant increase of value. change is considered necessary and without it, the organization is stalled. multiple change projects are underway all the time and are frequently driven bottom-up. people pro-actively start new initiatives to explore new areas for potential future business. that means that taking risk and experimenting is a habit and failure considered as learning opportunity.  people openly share their learnings and are keen to learn from others. work is performed in an agile way, speed and customer satisfaction are key measures. continuous improvement is a strategic priority across all departments and adoption is high and formalized across all teams.','Training: developing new business ideas, creativity, change mindset\u000akpi for sharing and cross-team innovation',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(491,100,1,'Ad Hoc','They run change impact assessments when needed on an ad hoc basis and apply an approach that works for the situation given. the assessment is at a basic level and focuses rather on roles and required skill changes. line managers are responsible for the follow -up.','Basic tools for change impact assessment\u000abasic steps of an impact assessment process defined\u000abasic training on how to run an change impact assessment\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(492,100,2,'Defined','They understand the scenarios when a change impact assessment is needed. they are able to deliver the assessment on a team and departmental level. it usually covers technology and process aspects on top of individual skills, attitudes and behaviors. there exists some consistency with regards to the approach they apply. the assessment outcomes lead to a change strategy and plan on a team or departmental level.','Impact assessment program is implement, process defined and described \u000aset of basic tools\u000abasic success metrics\u000amanual data collection tools\u000atrained experts to run assessment\u000atraining program on how to run a change impact assessment\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(493,100,3,'Integrated','They need to have a structured and scalable approach for change impact assessment in place. it covers all aspects of change (technology, processes, behavior, skills, ...) and can be run up to an organizational level. the focus usually lies on assessing changes to individuals and leaders. \u000athe goal is to fully understand the change impact on each target group so that targeted follow-up actions are enabled. the outcomes lead to a detailed change strategy and plan on an organizational level. the follow-up of the change impact assessment is measured against defined kpi.','Scalable process and tools for impact assessment covering a variety of focus areas\u000adigital data collection tools for large, distributed and complex environments\u000akpi to measure progress\u000ametrics partially automated',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(494,100,4,'Intelligent','They need change impact assessments an ongoing process. changes and people''s reaction on them are monitored all the time (e.g. pulse surveys). they use additional data sources to measure adoption in an automated fashion (e.g. usage data of applications). they constantly gain new insights by the data collected which allows them to anticipate change early and manage it rather pro-actively than reactively. change impact assessments cover all levels: individuals, leaders, teams and the entire organization.','Tools to track change impact on an ongoing basis\u000aautomated data collection tools\u000aintelligent tools to discover dependencies and risks\u000ametrics automated',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(495,100,5,'Adaptive','They need to monitor change impacts on an ongoing basis. they apply a number of sophisticated and automated tools to collect data. they observe a wide adoption of automation and ai to support the analysis of the data and grow the understanding of change impact. they use the insights they gain to anticipate change early to pro-actively manage current and upcoming changes.','Automated processes to deliver information on change impact\u000amethods to detect and monitor dependencies between parallel change activities\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(496,101,1,'Ad Hoc','Key stakeholders understand current changes, and plan activities supporting the change when required. they focus on the most important aspects considering only the people directly being involved. they assign change tasks on an ad-hoc basis and they are  taken on by people on top of their day jobs.\u000a\u000a','Basic ocm training and knowledge\u000abasic tools and templates to plan the change\u000acore ocm objectives defined \u000ahigh level risks and gaps identified\u000achange strategy formulated',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(497,101,2,'Defined','They need to build an understanding of the nature and extent of the change. they establish a sense of urgency and actively identify potential resistance and risks. they create basic ocm strategy and put a plan in place which also results in ocm communications to relevant audiences.  they identify core change roles are and select dedicated people to take care of change activities. they implement change agents who are recognized within silos.','Role-specific ocm training and knowledge\u000aset of tools and templates to prepare change \u000aappointed change agents on departmental level\u000arisks and gaps identified \u000aaction plan to drive change\u000ahigh-level business case \u000acore kpis to drive initial definition of the strategy \u000acommunication strategy and plan\u000atraining strategy and plan to build new skills during change\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(498,101,3,'Integrated','They fully understand current changes. they extensively assess the impact of the change on the organization. based on the outcomes of the assessment they build a comprehensive strategy for ocm and put a detailed action plan in place. they establish a communications and change management program specifically addressing all target audiences. they ensure that there is alignment between key stakeholders and executive leadership regarding the scope and scale of the transformation. they identify and implement key roles driving and supporting the change. change role owners are fully committed to work on the change activities. change agents are recognized across the entire organization.','Role-specific ocm training, regular updates and refresh training\u000aorganization wide methodology and set of tools and templates to plan and deliver a change program\u000abusiness case for ocm\u000aformal change program\u000ametrics to measure success and progress of ocm program\u000achange agents in place on organizational level\u000aknowledge sharing platform and process for change agents\u000afeedback loop in place to improve ocm approach and processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(499,101,4,'Intelligent','They need to fully understand current changes and are pro-actively anticipating future changes. they manage multiple changes in a variety of stages in parallel. their leadership is fully aware of dependencies and potential interferences between different change initiatives. they have a well-established strategy and plan in place for ocm that is regularly reviewed and updated. they deploy comprehensive communication and change management programs and implement a constant feedback loop in place with all employees.','Tools and templates for managing and coordinating multiple changes\u000ausage of ocm tools optimized \u000amulti-change program management\u000atools and methods to measure progress and success of multiple parallel change initiatives\u000adigital dashboards to track progress and raise alerts with documented response\u000adedicated ocm team\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(500,101,5,'Adaptive','They consider change as an ongoing phenomenon with directions taking different turns all the time. they have multiple change programs are in place that are fully anticipated by leadership and the change program owners. they frequently review all change programs and check their alignment. if needed, they adjust them in a swift and agile manner. every employee in the entire organization is always fully aware of the role they play in the transformation and they pro-actively support and drive the changes.','Agile methods to manage multiple change projects in parallel, allowing for flexibility in scale and scope',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(501,102,1,'Ad Hoc','They need to identify the most relevant key stakeholders for the digital transformation. they have a transformation sponsor in place who is responsible for at least the most relevant target groups. they also appoint first change agents / ambassadors.','Initial description of the core stakeholder roles (sponsor, change agent)\u000agroups of stakeholders identified (e.g. xyz management, abc engineers, etc.) \u000alist of key individual stakeholders',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(502,102,2,'Defined','They identify all stakeholders relevant for the change. they perform a stakeholder analysis which allows them to understand the role each stakeholder plays in the change, how they are personally impacted and how they have to contribute to the change activities. they put an initial stakeholder management plan in place and keep it up-to-date. they identify a transformation sponsor who is responsible for all target groups and who is committed to drive the change. the change agents / ambassadors are centrally coordinated and educated.','Basic template for stakeholder matrix\u000awell-defined stakeholder role descriptions\u000adetailed list of stakeholders\u000atrained experts to run stakeholder analysis \u000adefined and documented stakeholder engagement model\u000ametrics to measure stakeholder engagement',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(503,102,3,'Integrated','They need to apply a detailed and standardized method for stakeholder analysis in place. they have a full stakeholder engagement plan in place covering all stakeholders which is regularly reviewed and updated. they set up a governance board to coordinate all stakeholder engagement activities on a departmental level. they track progress regularly and implement changes to the stakeholder plan when needed. the transformation sponsor is actively involved in driving the changes and this has top priority for him/her. they implement a network of change agents / ambassadors who drive the change into the organizations.','Comprehensive templates for stakeholder matrix and map\u000astandardized process description for stakeholder analysis and definition of actions \u000awell-defined actions for all stakeholders\u000akpi for stakeholders incl. sponsor to drive support of changes\u000a\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(504,102,4,'Intelligent','They need able to run detailed stakeholder analyses that allow them to gain new insights on an ongoing basis. they regularly review findings and adjust their stakeholder strategy accordingly. they have a detailed stakeholder engagement plan in place that is dynamically adjusted when required.\u000atheir stakeholder engagement plan is fully scalable across the entire organization. they track progress on an ongoing basis. they have an organization-wide network of change communities in place which allows them to align activities, share learnings and leverage experiences.','Scalable (digital) tools and process for stakeholder analysis and management\u000aprocess and tools for ongoing tracking of stakeholder engagement (dashboards)\u000acontinuous improvement of stakeholder engagement\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(505,102,5,'Adaptive','They need to build a strong organization-wide stakeholder network where people closely cooperate in a self-organized way to drive the change collaboratively. they apply new tools and methods that are invented by the stakeholders themselves while managing the change. the organizational change expertise is externally acknowledged and the organization is considered as role model for driving and managing change.','Organization-wide stakeholder network\u000anew tools and methods developed by stakeholders while managing change\u000aexternal recognition of change expertise',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(506,103,1,'Ad Hoc','They are documenting the organizational design.','Organizational charts\u000amonetary rewards on departmental level\u000alinear career paths on departmental level\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(507,103,2,'Defined','They have the organizational design aligned with departmental goals and processes. they have the start of cross-functional team capabilities by introducing project work or matrix reporting structures. they have job families, at least at departmental level and ad-hoc review of the organizational structure in some critical areas, especially when kpi are not met.','Update process for organizational charts\u000afirst job families documented with roles & responsibilities described \u000aad-hoc governance forum to review and adjust organizational setup\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(508,103,3,'Integrated','They have the adoption of a centralized, standardized organizational structure definition, aligned with the organization''s strategy, goals and processes. they have job families that can serve as a basic structure for all departments and for talent development, compensation and promotion across all departments. they have a regular (annual) review of organization design across all departments and their alignment with the company goals.','Standardized description of the organizational structure\u000aregular review process\u000aleadership training: leading distributed teams\u000aguidelines how to mange a matrix organization\u000astandardized templates for job families \u000aorganizational vision and objectives shared and followed across the entire organization\u000adecision making processes based on the same criteria and standardized throughout the organization\u000aalignment of organizational design with performance management and talent enablement\u000a\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(509,103,4,'Intelligent','They have organization-wide adoption of centrally defined organizational structures, fully aligned with company goals and strategies. they have a flexible mix of organizational models. they have "distributed" cross functional teams that take on more of the traditional it roles as they deliver in a product focus manner. they have a first trend to implement self-organized, agile teams in some business or functional areas and a gradual move from job descriptions to fluent job roles. they have all leaders involved in reviewing and adjusting of organizational structures when required.','Process to ensure organization is aligned with organizational goals\u000ageneric role descriptions that can be applied cross-departmental\u000acontinuous review and improvement of organizational design\u000atraining for leaders and experts: modern organizational models\u000aguidelines on agile ways of working\u000ateam and leader training: agile ways of working\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(510,103,5,'Adaptive','They have an organization-wide organizational framework in place, defining rather rules than structures. the organizational set-up needs to fully reflects "from project to product" notions and ownership of the teams for achieving business results. they have self-organized, agile teams wherever this leads to better results. it requires "federated" it  teams with complete site engineering capabilities that allow for solutions deployed to meet customer needs. these federated teams need fully organized from a product perspective. they have most people working in roles rather than in fixed jobs, with the responsibility of all employees to identify the best way of working and organizing themselves.','Organization-wide framework of rules for agile working\u000aprocess defined how to create and implement product focused teams\u000ateam training and coaching: agile ways of working\u000aleadership training and coaching: new style of leadership',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(511,104,1,'Ad Hoc','They have to perform ad hoc gap assessments and develop enablement plans where critically needed. this requires documenting goals for people strategy and planning.','Ad-hoc gap assessments and enablement plans\u000afederated (each manager doing their own) gap assessment\u000afederated enablement plan\u000ainitial vision development\u000adocumented goals',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(512,104,2,'Defined','They have initial alignment between company goals and skill and staffing needs, with standardized enablement plans. this requires a cross functional skill and staffing strategy for transformation and a standardized gap assessment that is not specialized to any one technology or area. within silos, various teams and departments  start developing long term vision, goals, enablement plans, and kpi tracking for staffing and skills to help ensure future needs are met','Standard skills gap assessment\u000across functional skill and staffing strategy for transformation\u000astandardized enablement plan',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(513,104,3,'Integrated','They have a single, cohesive strategy for staffing and skills including visions, enablement plans, goals, and kpis, aligned with the company goals. this also requires leadership to align on enablement plans, visions, and goals to business needs. they have the organization to have specialized gap assessments to ensure emerging technology needs are searched for and found across the entire organization, with active tracking kpis in near-real time.','Single, cohesive strategy for staffing and skills\u000akpis for staffing and skills strategy\u000aspecialized gap assessments for emerging technologies\u000aleadership alignment on people enablement',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(514,104,4,'Intelligent','They have leadership continuously review staffing capacity management and strategy, staffing plans, enablement plans, skill needs, and business needs. this requires dashboards to keep employees, managers, and leadership up to date on current status and communication staffing capacity management plans and roadmaps. it also requires comprehensive long term people planning.','People enablement plan review process\u000apeople enablement plan improvement process\u000astaffing capacity dashboard\u000along-term people planning',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(515,104,5,'Adaptive','They have leadership fully aligned with skill and staffing needs that are in line with company goals and business objectives. this requires leveraging robust staffing capacity management processes including roadmaps and resource tracking to ensure peak performance of employee staffing and skills. also, emerging technology needs predicted and skills trained/available to fill coming needs.','People enablement plan benchmarking process\u000apredictive analysis of emerging technologies needs\u000aproactive training and staffing to fill coming needs',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(516,105,1,'Ad Hoc','They have initial risk & succession plans and skill capacity needs  identified, and initial plan focusing on critical modern digital skillset redundancy is under development.','Risk succession plans\u000arole scoring model & process (to determine criticality of roles)\u000aprocess for identifying critical roles, positions, and use cases\u000aprocess for identifying people & potential successors per role\u000ahuman resources system of record\u000askills coverage & redundancy requirements\u000abusiness continuity requirements\u000aoperational continuity requirements',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(517,105,2,'Defined','They have the implementation of risk & succession plans and skill capacity plans underway and at least 50% of modern digital skillsets are redundant.','Skill capacity plans\u000a>50% of critical skillsets are redundant\u000ajob shadowing\u000askills & competencies attestation process\u000aprocess for forecasting role-based demand (demand mgmt.)\u000aresource availability, utilization, and redundancy tracking & reporting \u000aresource capacity plan for plan\u000aresource capacity feedback loop\u000aresource capacity pilot',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(518,105,3,'Integrated','They have all  modern digital skillsets redundant within the organization and succession plans are quickly and effectively followed as roles become open as a result of a transformation program. there has been at least one instance of experimentation with rotational teams.','>90% of critical skillsets are redundant\u000asuccession plans\u000ahr and business alignment on people planning\u000ajob rotation\u000askills & competencies tracking\u000aresource capacity plan\u000aresource capacity kpis & metrics\u000arisk & succession plan & process\u000ajob shadowing plan & process\u000ajob shadowing pilot',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(519,105,4,'Intelligent','They have matrixed organizational structure and rotational teams commonplace within different silos and departments and considerable cross-pollination of critical skillsets throughout the it organization exists.','Cross-pollination tracking mechanisms\u000across-pollination metrics\u000a50% of critical skill sets have cross-pollination\u000ajob shadowing program\u000ajob rotation plan & process\u000ajob rotation pilot',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(520,105,5,'Adaptive','They have matrixed organizational structure and rotational teams commonplace within the organization and considerable cross-pollination of all technical skillsets, critical or not, throughout the it organization exists.','>90% of technical skill sets have cross-pollination\u000acost reductions through capacity planning\u000aregular job rotation',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(521,106,1,'Ad Hoc','Third-party staffing partnerships are being investigated and developed to potentially fulfill business requirements and are managed directly by the business unit.','Documented selection criteria \u000athird-party staffing contacts documented',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(522,106,2,'Defined','Initial partnerships are in place with priority third-party staffing providers and centralized contract management provides formal expectations and are communicated to providers.','Third-party staffing provider partnerships in place\u000acentralized common selection criteria \u000acentralized contract management\u000adocumented contractor expectations\u000alimits of liability, intellectual property rights, and dispute resolution contract language expectations are pre-defined',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(523,106,3,'Integrated','They have end-to-end management of third-party staffing providers including governance, risk models, and monitoring to ensure vendors and client organization are collaboratively working towards shared objectives.','Third-party staffing partnerships governance and monitoring\u000acentralized third-party staffing program formation \u000aprovider tiers documented\u000aprovider management program documented\u000aformal rfp process defined\u000adocumented escalation process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(524,106,4,'Intelligent','They have continued evaluation of third-party staffing capabilities by developing and tracking kpis and as needed, adjust, improve, and acquire new partnerships.','Third-party staffing providers capabilities kpis\u000acentralized provider management program formation\u000aprovider viability process defined\u000aprovider onboarding and off boarding process \u000aongoing provider evaluation process\u000aprovider scorecards\u000aindependent diversity and inclusion assessments',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(525,106,5,'Adaptive','They have to have fully integrated third-party staffing providers into organizational programs and have established kpis to continuously monitor risk, compliance, and performance. the organization has developed preferential status with some vendors and leverages this for benefits such as discounts. underutilized vendors and capabilities are continuously re-evaluated and pruned.','Tracking of third-party staffing providers governance, risk models, compliance and performance\u000apreferential status tracking with providers\u000aprovider partner advisory council seat\u000are-occurring provider viability assessments\u000adiversity and inclusion policy compliance without exception',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(526,107,1,'Ad Hoc','They have continuous learning to happen across the organization at the individual contributor level and continuous learning has only begun part of the cultural mindset. their thought leadership is occasionally expressed internally through thought leader publications','Continuous learning mindset\u000alearning agenda\u000aoccasional thought leadership publications internally',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(527,107,2,'Defined','They reward continuous learning on a formalized basis and have a growth framework based on objectives/key results (okrs) started in key areas of the organization focused on aspirational goals and measurable outcomes. members of the organization publish their thought leadership through articles,  webinars and podcasts. lunch & learn are leveraged to talk about successful projects internally','Incentives for continuous learning\u000acontinuous learning year-end review process\u000agrowth framework (based on okrs and objectives)\u000aaspirational goals\u000athought leadership article tracking (key modern digital team, internal/external, modern digital-related)\u000aarticle content tracking\u000alunch and learn awareness tracking (most people aware)\u000alunch and learn attendance tracking (most people attend regularly)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(528,107,3,'Integrated','They encourage risk taking and experimentation, ensure blameless retrospectives occur regularly, encourage teams to attend hackathons, and begin to form/embed guilds and interest groups into the culture.  additionally, partnerships with learning and development are more collaborative and continuous feedback loops are being established. social media such as linkedin is regularly used by senior member to promote thought leadership. published articles generate engagement with the brand and its product and services','Employee risk taking/experimentation and risk-taking measurement and tracking (i.e. how much risk are employees taking and how does the organization back them up)\u000aorganization hackathons, skill guilds or interest groups\u000atracking system for hackathon/skill guild/interest group attendance and participation\u000athought leadership article tracking (senior members, external)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(529,107,4,'Intelligent','They have a culture to drive continuous learning, smes and team members hold lunch and learns, dojos held on regular basis, teams innovating on their learnings and sharing knowledge/collaborating with learning and development.  continuous improvement feedback loops are the norm. the company''s thought leaders participate at event and conferences showcasing their expertise in a certain space.','Use of lunch and learns\u000ause of dojos\u000amentorship program\u000abuddy programs\u000athought leadership article tracking (smes, internal/external, modern digital-related)\u000athought leadership time-spent tracking\u000asome smes are dedicated 100% to thought leadership publication',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(530,107,5,'Adaptive','They ensure that positive change is rewarded and there is rapid adoptions of transformation and new culture.  the organization holds hackathons and works to attract top industry talent, continuous learning culture is established across the organization, and continuous innovation of new capabilities, services, and products are wide spread. thought leaders are perceived as  icons within their field.','Public praise tracking for embracing cultural change\u000aincentives program for embracing cultural change\u000acontinuous innovation programs\u000aemployee industry recognition tracking\u000avip modern digital talent\u000acloud smes/leaders are icons in industry',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(531,108,1,'Ad Hoc','They have a modern digital career  assessments of current teams and they understand and identify critical skills and gaps. risk & succession planning is conducted via skill capacity planning.','Skills assessment\u000askills gap assessment\u000askill gap tracking mechanisms\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(532,108,2,'Defined','They  have defined modern digital career program kpis and track against the kpis.  additionally, they have reporting capabilities to continue maturing with progress made towards a centralized dashboard representation of the data.','Kpis\u000akpi tracking\u000areporting tools/mechanisms\u000ainitial kpi reporting dashboard\u000asystem of record as a feature',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(533,108,3,'Integrated','They have risk assessments in place for critically short  modern digital careers  and have kpi tracking and reporting centralized with the ability to see skills/certs/gaps across the organization.','Risk assessments process\u000amechanism for risk assessment tracking\u000amechanism for kpi tracking\u000akpi reporting\u000akpi reporting dashboard (certifications, skills, gaps)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(534,108,4,'Intelligent','They have kpi tracking and reporting a critical function of the business and data from kpi dashboards drive program decisions.','Talent enablement-related kpis tracking\u000atalent enablement-related kpis reporting\u000adata-driven and kpi-driven program decisions\u000akpi reporting dashboard & observability',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(535,108,5,'Adaptive','They have data analysts/scientists to make efforts to leverage kpis and program data in novel ways, augmenting the value of the reporting, and gleaning new insights into program and kpi performance.','Formalized use of data analytics\u000adata-driven and kpi-driven business decisions',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(536,109,1,'Ad Hoc','They identify initial it champions based on skills/training/interest and provide opportunities to folks that want to get involved with the modern digital initiative.','Digital champion tracking\u000adigital champion identification\u000ait-related open opportunities tracking (employee involvement)\u000amentoring model & process\u000amentoring & coaching plan for plan\u000amentor & coach recruitment process\u000amentor/coach match process with mentee',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(537,109,2,'Defined','They have an initial mentorship program at each level of seniority in the organization and formal mentorship programs/skill guilds are in the early stages of planning and implementation.','Mentorship program\u000aplanning/implementation of skill guilds\u000amentoring & coaching plan\u000amentoring & coaching kpis & metrics\u000amentoring & coaching pilot\u000amentoring & coaching feedback loop\u000amentor & coach training\u000asystem of record\u000amentoring tracking & reporting',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(538,109,3,'Integrated','They have skill guilds, led by smes, to develop and enable increasing internal support. formalized avenues for participation and learning within the transformation  program are available to all who are interested. fully formalized and structured mentorship programs exist','Skill guilds\u000aparticipation and engagement programs (for skill guilds and mentorship programs)\u000amentoring & coaching program',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(539,109,4,'Intelligent','They have a mentorship program well-known throughout the company and have well-developed skill guilds act as pockets of thought leadership and talent enablement for the broader organization.','Mentorship program reputation tracking\u000awell-developed skill guilds',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(540,109,5,'Adaptive','They are an industry leader in mentoring and coaching best practices, identify emergent themes in coaching and mentoring techniques, and maximize return on investment from coaching and mentoring programs.','Industry-leading mentorship program\u000aindustry-leading coaching program',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(541,110,1,'Ad Hoc','They have at least a few individuals in the organization to have modern digital learning plans that they have discussed with their managers with ad hoc resources and licensing available to employees to learn and develop.','Employee learning plans\u000atraining resources\u000atraining tools (learning and development system)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(542,110,2,'Defined','They have skill development plans a formal part of year-end reviews and goal-setting for core cloud/hybrid team members. each employees has specific organizational goals that match the organizations needs (specific to skills and competencies). formal learning and development strategy considered and investment made into a formal learning and development management system.','Learning and development system\u000askill development as part of year-end review process\u000aemployee skill development plans',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(543,110,3,'Integrated','They have all members of the core modern digital team to have formal learning plans which include technical certifications and these plans are formally discussed in year-end reviews and goal-setting. the learning and development management system is robust in the number of learning journeys and support is consistently updated with new content based on industry developments and employee interest. employee development is part of their managers goals','Certification tracking process and tools (1 certification per it employee)\u000a1 learning journey per role in learning and development system\u000ayear-end review process including learning plan\u000alearning and development system review and update cycle',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(544,110,4,'Intelligent','They have all modern digital stakeholders, including those in broader it, hr, and finance, to have formal learning plans which include certifications, event attendance, and stretch goals during performance reviews and goal-setting. these plans are formally discussed in year-end reviews and goal-setting. learning and development management system is used widely within the organization, and is effective in helping employees to grow and develop. managers are evaluated on the development of their direct reports.','Employee modern digital-related learning plans for all it stakeholders\u000aemployee goal tracking (smart-style goals)\u000aemployee event attendance tracking\u000aenterprise-wide learning and development system\u000aemployee skill development plans for all it stakeholders\u000aevaluation of managers based on the development of their people',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(545,110,5,'Adaptive','They have all employees in the organization with access to modern digital training. a learning and development management system is a strategic asset of the organization, and the learning journeys associated with it are a unique competitive advantage of the organization within its industry. they continuously track the personal development of their employees and they are regularly updated','Enterprise-wide employee development plans\u000aenterprise-wide employee goal tracking\u000aenterprise-wide training resources\u000aenterprise-wide certification tracking process and tools',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(546,111,1,'Ad Hoc','The enterprise may understand the design patterns concept, but does not have a program for definition and adoption','There are developers that understand and use design patterns but the practice isn’t standardized or widespread within the organization',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(547,111,2,'Defined','The enterprise makes use of design patterns in many of its application designs','The enterprise understands design patterns and is building its design pattern practices\u000athere exists a list of approved design patterns but it is incomplete and not often updated\u000areviewing the design pattern list or library is a defined part of the application development process, but actual implementation is spotty\u000adesign patterns are generally an individual’s responsibility – knowledge is acquired through developer investigation and passed along via incidental mentoring\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(548,111,3,'Integrated','Identification and incorporation of design patterns is part of any new application design enterprise wide.','The enterprise has a defined design pattern practice that lists approved patterns and is used to educate developers\u000aa defined step in the sdlc of all applications is a review to identify any useful design patterns.\u000adesign patterns are periodically reviewed, outdated or insecure patterns are removed and new patterns are considered and, after passing evaluation, added.\u000athe cost implications of different design patterns are considered as a part of the process for designing, approving, and reviewing design patterns',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(549,111,4,'Intelligent','Part of enterprise sdlc is periodic review and rationalization of application portfolio, including re-evaluation of existing and potential design patterns.','The enterprise sdlc involves periodically reviewing applications to identify and outdated design patterns that need to updated to more modern versions, or identify where new patterns might be appropriate (often linked to an update in the tech version with new functionality)\u000athe enterprise supports developers attending training, conferences and hackathons to keep them abreast of any new innovations\u000athe enterprise has metrics and kpis for design patterns',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(550,111,5,'Adaptive','The enterprise innovates in the design pattern space, becoming a thought leader and creating new patterns that are then adopted in the community at large.','Developers in the enterprise are noted thought leaders in their tech space, contributing and supporting developments and innovations\u000athe enterprise has an innovation space that allows cutting edge, experimental design patterns to be implemented and evaluated\u000athe enterprise has an innovation culture that rewards new discovery and they are often represented at tech conferences presenting new concepts or patterns',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(551,112,1,'Ad Hoc','The enterprise has some service architecture, but discovery, segmentation and configuration are all manual and ad-hoc','The enterprise has implemented some micro-services\u000athese services are hard coded to be able to communicate\u000athe services environment is monolithic and not segmented\u000aconfiguration is a manual process, generally for each individual service',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(552,112,2,'Defined','The enterprise uses service architecture and has defined but manual processes for registration (discovery), configuration and segmentation.','The enterprise has a defined, documented service architecture\u000aregistration for discovery is a manual process – new services must be added and retired services removed by developers\u000aconfiguration of services has defined states with associated functional limitations, but implementing the configuration is a manual operation\u000asegmentation of services is simple (e.g. public/private, web/middleware/data, etc.)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(553,112,3,'Integrated','The enterprise has extensive service architecture and uses centralized automated framework/tool (e.g. consul) for d,s &c.','The enterprise has an extensive and mature service architecture implementation and practice\u000athe enterprise automates the registry process, generally via a tool or framework (e.g. hashicorp consul)\u000asegmentation is abstracted to allow no-trust connection based communication mesh',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(554,112,4,'Intelligent','The enterprise service mesh in integrated into the ci/cd framework for application development and deployment.','The service discovery, configuration and segmentation actions are all instrumented via ci/cd pipelines',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(555,112,5,'Adaptive','The enterprise innovates in the service mesh space, developing creative, industry leading solutions for d,s & c.','Developers partner with outside service mesh providers to implement new functionality\u000athe enterprise acts as a thought leader in the service mesh space, developing functionality and opinions that are adopted throughout the industry\u000adevelopers represent the enterprise at tech conferences and industry publications and outlets',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(556,113,1,'Ad Hoc','Any guidelines and/or approved technology lists are informal and not documented','Guidelines are generally word of mouth and change from bu to bu or development team to development team.\u000atechnology lists are also institutional knowledge and not documented (e.g. “we’re a java shop”)\u000aapplication portfolio contains a plethora of technologies and code quality varies widely',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(557,113,2,'Defined','Documented guidelines exist, but are out of date and not followed.  same for technology lists','The enterprise has published guidelines and approved technology lists, but they are out of date and rarely reviewed or updated\u000athe actual application portfolio tech does not match the approved list\u000anew developers are not instructed on enterprise guidelines, or are informally told that they don’t really matter (no enforcement).\u000athe existence of documented guidelines without any enforcement causes tension and confusion during code reviews and design discussions.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(558,113,3,'Integrated','The enterprise has guidelines and approved technology lists, and these are periodically reviewed, updated and followed.','The enterprise has clear guidelines, both general and for specific tech where needed, as well as clear approved technology lists\u000adevelopers follow these guidelines and peer review enforces compliance\u000anew application design begins with assumption that technology will be from approved list\u000aold, non-compliant applications exist, but are tracked for replacement when time/resources allow',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(559,113,4,'Intelligent','The enterprise has automated enforcement of guidelines and technology lists - via configurable static code analysis tools, curated library and compiler selections, etc.','Guidelines are enforced via code review, but also through automated static code analysis during the ci process\u000anon-approved tech is unavailable, by excluding it from the enterprise curated libraries and source code repos or some other institutional method\u000aguidelines align with best practices and highest level of industry code standards\u000athe enterprise uses outside validation for checking internal standards (e.g. veracode)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(560,113,5,'Adaptive','The enterprise has a flexible configuration of guidelines and approved technologies that allows for an efficient standardization for the application portfolio while giving freedom to innovation teams to experiment with new technologies and coding practices.','Developers are god-like in their ability to write error free code, and guidelines are not needed',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(561,114,1,'Ad Hoc','Organization has defined low-code, no-code, robotic process automation needs (also known as low code application platforms (lcap)).','Lcaps high level goals\u000alcaps in service \u000alaps pocs \u000alcap it smes \u000asponsors for lcap',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(562,114,2,'Defined','Organization has standardized on low code application platforms.','Lcap business case\u000alcap utilization plan for bus\u000aenablement plan for change, problem and incident management \u000alcap stakeholder map\u000alcap enablement plan\u000aprocess re-engineering practice \u000ametrics and kpis documented',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(563,114,3,'Integrated','Organization has fully implemented low code application platforms and has completed training for business units.','Standards documented \u000across functional roles defined \u000arbac\u000alcaps dr and bcp plans and testing\u000alcap lifecycle management \u000astandardized training \u000aan lcap cross-functional leadership \u000alcap communities \u000alcap evaluation process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(564,114,4,'Intelligent','Organization has multiple production enabled low-code application platform systems. it has established roles, guilds, centers of excellence. standardized measurements are reported. leveraging ai and intelligent process automation.','Collaborative user groups \u000acenters of excellence are defined \u000ahr roles defined \u000aslas, slos, rtos, rpo defined \u000acognitive intelligence implemented',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(565,114,5,'Adaptive','Organization has establish continuous improvement practices for low code application platforms. automating all manual processes possible. cognitive process automation is being leveraged.','Constant improvement program \u000avendor steering committee participants \u000aproduct owner integration \u000a-hyper automation practices \u000acognitive process automation w \u000aai produced recommendation process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(566,115,1,'Ad Hoc','The enterprise may understand the reference architecture concept, but has not defined any for use','Each application is developed greenfield, without any continuity or reuse of previous application architectures\u000athe enterprise understands that this is inefficient, insecure and causes multiple maintenance issues, they have not yet implemented reference architecture standards and practices',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(567,115,2,'Defined','The enterprise has several low quality reference architectures.  most applications do not use them.','The enterprise has one or more draft reference architectures\u000aesg engineering principles documented',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(568,115,3,'Integrated','The enterprise has developed secure, sustainable, and deployable reference architectures and almost all workloads are implemented using them.','The enterprise has developed secure, sustainable, and deployable reference architectures.\u000athe enterprise has developed architectures that align with, and enable the achievement of the stated cost objectives',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(569,115,4,'Intelligent','The enterprise has a comprehensive library of high quality reference architectures and associated iac templates.','The enterprise has a comprehensive library of high quality reference architectures.\u000athe enterprise has infrastructure as code for the reference architectures.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(570,115,5,'Adaptive','The enterprise has a flexible list of iac reference architectures, deployable via ci/cd supporting quick innovation.  the enterprise is a source of new architectural designs and patterns.','Reference architectures are normalized to most basic patterns allowing complex application architectures to build from multiple granular basic building blocks\u000athis process is implemented via iac templates that allow dynamic, multi-part architectural configurations to be defined, modified and automatically deployed\u000athe enterprise actively explores the reference architecture space, innovating and creating new patterns that are adopted by the software community',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(571,116,1,'Ad Hoc','The enterprise has limited or no containerization','Early stage containerization strategy (plan for a plan)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(572,116,2,'Defined','The enterprise has some containerized workloads','Some workloads are containerized\u000athere is no centralized container image repository \u000acontainers configuration and deployment is manual\u000acontainers are treated as virtual machines and multi-tier applications are simply stuffed into containers\u000acontainer orchestration emerging',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(573,116,3,'Integrated','Containerization practice is maturing (emerging ci/cd, automated testing, central registry, etc. )','\u000acontainerization strategy emerging\u000acontainerization is used extensively in some parts of the organization and used where appropriate\u000amultiple container image repositories\u000acontainers are integrated into per-team ci/cd process – allowing some automated testing and deployment\u000asome teams are aggregating container logs and evaluating with other application logs (in their stack) for troubleshooting, event monitoring and analytics\u000asome workloads are properly normalized (e.g. multi-tier applications are hosted via multiple containers)\u000acontainer orchestration is the norm (single cluster)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(574,116,4,'Intelligent','Containerization practice is mature ( ci/cd, automated testing, central registry, etc. )','\u000acontainerization strategy developed \u000acontainerization is common throughout the organization and used where appropriate\u000acontainer image repository \u000acontainers are integrated into common ci/cd process – allowing automated testing and deployment\u000acontainer logs are aggregated and evaluated with other application logs for troubleshooting, event monitoring and analytics\u000aworkloads are properly normalized (e.g. multi-tier applications are hosted via multiple containers)\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(575,116,5,'Adaptive','Container deployment and management is automated and abstracted through an orchestration framework (e.g. kubernetes, aks, eks, etc.)','Metrics driven container elasticity process \u000acontainers are redundant with failover capability\u000aautomated image updated process \u000acontainer orchestration standards',NULL,1);
