INSERT INTO Next_CapabilityLevel VALUES(577,117,2,'Defined','The enterprise has some virtualized workloads','Virtualization standards being developed\u000a virtualization strategy started',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(578,117,3,'Integrated','Virtualization practice is maturing (emerging standardization)','Some workloads are virtualized\u000acentralized image repository started\u000aemerging standards for virtualized workloads \u000avirtualization strategy documented \u000aautomation and orchestration\u000a \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(579,117,4,'Intelligent','Virtualization practice is mature (standardized)','Most workloads are virtualized\u000acentralized image repository \u000awell defined standards for virtualized workloads\u000avirtualization strategy adopted across organization \u000a \u000a',NULL,1);
