INSERT INTO Next_CapabilityLevel VALUES(646,127,1,'Ad Hoc','The organization has a defined paper policy with procedures on how policies should be implemented.  policy is well known and understood across application teams. an initial ownership model is established and violation countermeasures are defined with understanding that continued learning is required to establish final approach.','Policy and procedure defined\u000aapplication teams aware\u000aviolation countermeasures defined',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(647,127,2,'Defined','The organization implements paper policy with service provider(s) structure and format.  application teams review compliance and implement some automated counter measures. violation counter measures are defined with a mix of scripted/automated + manual response, the exception process is enriched, and all violations are logged.','Policy implemented\u000aapplication teams review compliance\u000aapplication teams involved with countermeasure automation',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(648,127,3,'Integrated','The organization has defined a set of kpis and metrics that are operationalized and has implemented monitoring, measuring, and reporting mechanisms.  risk assessments are performed based upon visibility into the ecosystem and threat landscape.  application teams focus on kpis and implement monitoring within their work.','Monitoring, measurement, and reporting\u000aapplication teams focus on kpis as applicable and implement local monitoring\u000aassist with root cause analysis',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(649,127,4,'Intelligent','The organization performs root cause analysis for all compliance issues and are remediated with short and long term approached.  the application development program is fully integrated with broader enterprise compliance program and the response to measured information is regularly performed.','Management at scale\u000aapplication teams tightly involved with response and root cause remediation\u000atightly integrated with enterprise compliance program',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(650,127,5,'Adaptive','The organization has established a compliance training program and promotes knowledge sharing via both informal and formal channels.  volunteers work to bridge the gaps and act as liaisons between business -to-it and it-to-it groups.','Organizational learning and education\u000aapplication teams involved with improving process and app compliance\u000aactive training and communication',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(651,128,1,'Ad Hoc','Data is retained on an ad hoc basis.  policy is neither consistent nor widely used.','Ad hoc retention\u000asemi consistent application of policy',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(652,128,2,'Defined','The organization implements a written standard for retention.  data is retained based on the schedule and procedures in the policy.','Standard and implementation \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(653,128,3,'Integrated','Validation of the data retention is performed on a periodic basis.','Data validity scenarios tested\u000apractices improved\u000adata retention standards align with storage tiering standards to reduce cost',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(654,128,4,'Intelligent','Root cause analysis is performed after any issue or remediation.  results are folded into the procedures mandated by the policy and design patterns improved as applicable le.','Root cause analysis\u000aremediations applied',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(655,128,5,'Adaptive','The application teams includes data retention within their training program and promotes knowledge sharing via both informal and formal channels.','Team learning and education\u000ametrics monitored',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(656,129,1,'Ad Hoc','Sla/slo not defined clearly within initial system requirements. developers have only limited ownership of production problems.','Requirements not specified\u000a developers not vested\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(657,129,2,'Defined','Application teams have standard delivery sla/slos for all projects to track and provide insight to employees regarding their performance based on certain quality standards across projects. this is not an organizational priority and as a result no standards are in place nor tracked company-wide.\u000a some teams support an ownership culture, however it is not a priority. the level of engagement and resource investment in the activity is low as well.','Some teams support ownership culture but not promoted organizationally.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(658,129,3,'Integrated','Creating a culture of ownership amongst the development team is an organizational priority.  application team knows how the application factors into the specification.  patterns are documented to support sla/slo.','Culture of ownership emerging\u000adesign patterns to improve overall sla/slo',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(659,129,4,'Intelligent','The processes and procedures for a culture of ownership are formalized across all teams and supported by the organization. results are tracked to evaluate success. a standardized, formal set of sla/slos are in place and tracked companywide. individuals and teams are evaluated based upon these set benchmarks to ensure consistent quality across projects.','Strong culture of ownership\u000acompanywide sla/slos for quality / improvements.\u000asuccessful patterns repeated in projects',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(660,129,5,'Adaptive','The org structure amplifies the culture of ownership. processes and procedures are formalized across all application teams and supported by the organization. results are tracked to evaluate success on an ongoing basis. leadership is actively involved in supporting and adjusting policies to allow for continued success. employee feedback is tracked and used for improvements.','Very strong culture of ownership\u000aformal benchmarks tracking ownership across teams.\u000aemployee feedback for continuous improvement.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(661,130,1,'Ad Hoc','Few teams integrate automation into their processes/procedures however tooling and tooling usage is not standardized.  there is no standard approach organization wide to automation.','Manual processes\u000along delivery time of needed resources\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(662,130,2,'Defined','Most teams leverage some level of automation and standard usage and tooling boundaries exist within teams. the company values what automation can add, but has not made automation an organizational priority.','Automation roadmap\u000atooling identified\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(663,130,3,'Integrated','Established processes/procedures guide automation adoption in line with the automation framework. standards developed to govern automation approach and develop tooling boundaries.','Standards and guideline in place\u000aautomated compliance reporting',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(664,130,4,'Intelligent','Automation standards have been implemented by application and infrastructure teams across the organization. exceptions to automation standards are tracked and approved by a standards committee. teams routinely evaluate their portfolio to assess the ability to further enhance efficiencies of automation.','Automation standards implemented across the enterprise\u000aperiodic reviews to improve efficiencies',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(665,130,5,'Adaptive','Automation standards committee proactively reviews automation approach and adjusts standards to align with industry best practices. automation standards have been implemented by application and infrastructure teams across the organization. exceptions to automation standards are tracked and approved by a standards committee. teams routinely evaluate their portfolio to assess the ability to further enhance efficiencies of automation.','Alignment with industry standards',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(666,131,1,'Ad Hoc','Applications are built with little consideration of how they will operate in a production system.  there is very little integration of service availability tooling in application design which causes frequent availability interruptions.','Little to no integration of availability tooling in application design\u000afrequent service interruptions',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(667,131,2,'Defined','Operational integrations are added on to monitor availability and performance.  tooling is home grown or immature and inconsistent.  monitoring is superficial and does not delivery the quality of service needed for the business.','Immature availability monitoring tooling\u000ascripts that ping services\u000aoffshore leveraged to deal with support overhead',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(668,131,3,'Integrated','Application performance monitoring toolset identified and in use.  gaps still exist in detailed reporting and are added to the roadmap.  apm provides health statistics but redundancy and failover needs to be addressed.','Apm tooling\u000aapplication uptime reporting\u000aredundancy and failover needs identified but not in place\u000aavailability testing',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(669,131,4,'Intelligent','Monitoring is at the transaction level and in use throughout the organization.  proactive issue identification is enabled by following transactions throughout all of the various systems and services.  issues are rapidly remediated.  focus is on zero downtime rather than service interruption resolution.','Transaction tracking\u000anear zero performance issues seen by users',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(670,131,5,'Adaptive','Machine learning and other innovative solutions are used in conjunction with transactional tooling to forecast action that will needed based on subtle indicators.  costs are no longer linear with growth of application portfolio.','Ai/ml\u000acost optimization',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(671,132,1,'Ad Hoc','Incident response and management processes and procedures are created and published. tickets from "cloud" incidents are manually created in the service desk tool. incident prioritization and classifications are being established.','Centralized incident management exists\u000aincident severity and prioritization categories \u000athere is documented procedures based on incident category \u000ateams are documented and defined in the incident management system\u000aformal logging of incidents \u000acommunication plans and "call trees" have been developed for technical and management team\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(672,132,2,'Defined','Cloud incidents are integrated into itsm tools and managed through partial automation with some manual intervention required. incident assignment and category assignment are completed by the service desk team. service desk acts as the hub for monitoring and communicating incident status.','Cloud incidents are integrated into itsm \u000ateam and routing assignment primarily completed by the service desk\u000a"self-help" developed within the knowledge management system (see kms)\u000ametrics are leveraged for active management \u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(673,132,3,'Integrated','Cloud incidents are detected using monitoring tools and alerts are automatically sent and entered into incident management tool. basic communication is automated for team routing and management awareness. escalation is automated based on category priority and documented resolution times.  there is a formal "swarming" protocol established for high severity priorities when expected resolution times are not met.','Cloud incidents are automatically detected and included in itsm tool \u000adocumented resolution expectation times by category\u000ascripts are leveraged for fast diagnosis and remediation\u000aautomated escalation for technical and management support \u000aautomated incident notification\u000aa direct link exists between incident management, crisis management, and business continuity\u000alevel 1 resolution has established a benchmark \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(674,132,4,'Intelligent','Cloud incidents are automatically created in incident management tool with appropriate severity and automatic routing. incidents are primarily resolved via level 1 service desk, automation or "self-help".  incident status awareness is continuous and current.','Cloud incidents have full automated inclusion \u000a"self-help" dashboards are available \u000a"self-healing" is being automated for pre-defined incidents\u000aautomated team assignment and routing\u000aautomated status communication with expectation mgmt.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(675,132,5,'Adaptive','Cloud service impacts, compliance drift, and cost impacts are rare due to self-healing and auto-scaling.  in cases, where auto correction is not possible automation is built to speed correction.','Logged incidents are used in planning \u000atrending and predictive analytics are in use to prevent incidents\u000aautomated "self-healing" for appropriate incidents\u000amonitoring utilized machine learning and artificial intelligence to detect incidents prior to impact',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(676,133,1,'Ad Hoc','The it department provides core services but standard and processes are not established.  support is largely reactive and handled on a case by case basis rather than established best practices.','Inconsistent quality of deliverables\u000adisjointed delivery process\u000alack of quality and clarity in service requests',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(677,133,2,'Defined','Processes are standardized and repeatable.  the focus is on high customer service.  informal training is provided to users to guide them through the support process.  inefficiencies and human error is reduce but there is still room for improvement.','Informal training\u000ahuman error in manual processes\u000amedium/high risk when introducing change',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(678,133,3,'Integrated','Processes are documented and a knowledge base exists which helps shape itsm capabilities.  regular training is available to ensure efficient process execution and a proactive approach for itsm activities is in place where appropriate.','Decreased risk\u000aimproved quality\u000aproactive service\u000aknowledge base\u000aregular training',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(679,133,4,'Intelligent','Processes are managed with a quantitative approach.  monitoring is in place to enable continuous improvement.  automation is leveraged as much as possible and service failures are minimal.','Automation\u000adetailed monitoring\u000aservice targets and analytics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(680,133,5,'Adaptive','Strong governance controls ensure processes are optimized.  all itsm processes are integrated with business objectives.','Strong governance \u000aoptimized service enabled by automation and monitoring\u000atight feedback loops',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(681,134,1,'Ad Hoc','Traditional team alignments and reporting structures are in place as the organization begins its cloud operating model journey. traditional budgeting and project focus delivery as the cloud strategy and governance are gaining momentum.','Critical to the cloud operating model is the vision defining new business outcomes.... why hybrid/cloud ... what will be different? ( see governance and architecture) \u000ahybrid architecture implementation priorities are documented: saas 1st, paas 2nd, iaas 3rd, etc.. (whatever is appropriate for the firm) \u000ateams are organized traditionally by function (infrastructure teams and development teams)\u000afederated prioritization occurs for budget expenditure and are project based\u000a"service requests" are leveraged to engage cross functional needs\u000amost new features, services, and capabilities are built as needed on a project basis or at request of leadership \u000aprocesses and shared services are standardized \u000aiac and automation only are adopted as a key principle\u000acloud program is limited to shared services, select applications and workloads\u000athe initial cloud program may be built by central services without applications input\u000athe initial cloud program may be built by business unit development teams without central services \u000ait governance exists for architecture and project deployments \u000adesign documents for cloud builds will be gathered and published\u000aperformance, functionality, and characteristic requirements will be documented for cloud services \u000acloud roles are defined and racis completed (see people pillar) \u000athere is a centralized approach for cloud endpoint monitoring with particular focus on compliance and drift alerting. (see centralized logging, monitoring and alerting) \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(682,281,1,'Ad Hoc','Traditional team alignments and reporting structures are in place as the organization begins its cloud operating model journey. traditional budgeting and project focus delivery as the cloud strategy and governance are gaining momentum.','Critical to the cloud operating model is the vision defining new business outcomes.... why hybrid/cloud ... what will be different? ( see governance and architecture) \u000ahybrid architecture implementation priorities are documented: saas 1st, paas 2nd, iaas 3rd, etc.. (whatever is appropriate for the firm) \u000ateams are organized traditionally by function (infrastructure teams and development teams)\u000afederated prioritization occurs for budget expenditure and are project based\u000a"service requests" are leveraged to engage cross functional needs\u000amost new features, services, and capabilities are built as needed on a project basis or at request of leadership \u000aprocesses and shared services are standardized \u000aiac and automation only are adopted as a key principle\u000acloud program is limited to shared services, select applications and workloads\u000athe initial cloud program may be built by central services without applications input\u000athe initial cloud program may be built by business unit development teams without central services \u000ait governance exists for architecture and project deployments \u000adesign documents for cloud builds will be gathered and published\u000aperformance, functionality, and characteristic requirements will be documented for cloud services \u000acloud roles are defined and racis completed (see people pillar) \u000athere is a centralized approach for cloud endpoint monitoring with particular focus on compliance and drift alerting. (see centralized logging, monitoring and alerting) \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(683,134,2,'Defined','While reporting lines are organized traditionally, hub-and-spoke implementations provide cross-functional team capabilities.    annual planning cycles are in place with enterprise prioritization determining funding for the firm.   the tbo is executing (see governance and architecture), and the cloud operating model is built.','Hub-and-spoke model creates virtual cross-functional teams\u000aperiodic planning cycle (likely consistent with fiscal year)\u000aproject prioritization process based on characteristics such as risk, roi, and customer \u000acenters of excellence are starting to form beyond the tbo (devops, rpa, data, finops)\u000astrategies are developed and shared broadly with the team and organization \u000acloud service management processes are developed to respond to automation\u000adaily service management and reporting continue to develop to ensure quality operations\u000aautomated deployments include streamlined end-to-end services initiation for target applications\u000aautomation process maps outline interactions and dependencies between service lines\u000adocumented automated controls objectives by application and data classification \u000aiac, devops, and containerization all anticipate multi-cloud hybrid deployments (see devops, governance and architecture) \u000acloud notification, reporting, and response updated to enable automation\u000alist of manual activities to be applied for controls to enable automation\u000aa mix of automated and manual processes support semi-automated provisioning and operations\u000agrc framework updated for cloud services and control requirements based on application/data classifications',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(684,281,2,'Defined','While reporting lines are organized traditionally, hub-and-spoke implementations provide cross-functional team capabilities.    annual planning cycles are in place with enterprise prioritization determining funding for the firm.   the tbo is executing (see governance and architecture), and the cloud operating model is built.','Hub-and-spoke model creates virtual cross-functional teams\u000aperiodic planning cycle (likely consistent with fiscal year)\u000aproject prioritization process based on characteristics such as risk, roi, and customer \u000acenters of excellence are starting to form beyond the tbo (devops, rpa, data, finops)\u000astrategies are developed and shared broadly with the team and organization \u000acloud service management processes are developed to respond to automation\u000adaily service management and reporting continue to develop to ensure quality operations\u000aautomated deployments include streamlined end-to-end services initiation for target applications\u000aautomation process maps outline interactions and dependencies between service lines\u000adocumented automated controls objectives by application and data classification \u000aiac, devops, and containerization all anticipate multi-cloud hybrid deployments (see devops, governance and architecture) \u000acloud notification, reporting, and response updated to enable automation\u000alist of manual activities to be applied for controls to enable automation\u000aa mix of automated and manual processes support semi-automated provisioning and operations\u000agrc framework updated for cloud services and control requirements based on application/data classifications',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(685,134,3,'Integrated','"distributed" cross functional teams are becoming the more common operating model. these distributed teams continue to take on more of the traditional infrastructure roles as they deliver in a product focus manner. the tbo plays an integral role in defining standards and patterns that enables teams to be structured in a distributed manner. \u000a\u000a\u000a','Some teams are organized cross-functionally \u000across functional representation will likely be through coe assignment or temporary assignment and dotted line" \u000acustomer centric principles and capabilities we be emerging and driving newer features, services, and capabilities \u000anew features, services, and capabilities enter the workflow via the respective team product owners\u000athere is limited "silo" divisions \u000aexternal partnership relationships are being leveraged to accelerate and scale\u000acloud strategy to expand throughout the enterprise is created and deployed \u000adaily testing and validation of cloud services demonstrate controls remain in place\u000acontinuous process improvement is focused on end-to-end velocity ( see people pillar)\u000acontainerization architecture is synchronized and common between cloud providers',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(686,281,3,'Integrated','"distributed" cross functional teams are becoming the more common operating model. these distributed teams continue to take on more of the traditional infrastructure roles as they deliver in a product focus manner. the tbo plays an integral role in defining standards and patterns that enables teams to be structured in a distributed manner. \u000a\u000a\u000a','Some teams are organized cross-functionally \u000across functional representation will likely be through coe assignment or temporary assignment and dotted line" \u000acustomer centric principles and capabilities we be emerging and driving newer features, services, and capabilities \u000anew features, services, and capabilities enter the workflow via the respective team product owners\u000athere is limited "silo" divisions \u000aexternal partnership relationships are being leveraged to accelerate and scale\u000acloud strategy to expand throughout the enterprise is created and deployed \u000adaily testing and validation of cloud services demonstrate controls remain in place\u000acontinuous process improvement is focused on end-to-end velocity ( see people pillar)\u000acontainerization architecture is synchronized and common between cloud providers',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(687,134,4,'Intelligent','"distributed" cross functional teams are the operating model. these distributed teams continue to take on more of the traditional infrastructure roles as they deliver in a product focus manner. these distributed teams are primarily organized in a product centric approach.  the tbo plays an integral role in defining standards and patterns that enables teams to be structured in a distributed manner.','Teams are organized autonomously and are cross-functionally \u000across functional representation can be direct reports, ccoe assignment, or temporary assignment and dotted line" \u000aclarity of strategy and value propositions are visible in executive leadership with consistency of message and continuous feedback loops \u000a"silo" divisions have been eliminated and holistic collaboration on value delivery is primary \u000adeep partnership relationships are leveraged to accelerate and scale\u000amigration of applications and workloads at scale to various hybrid cloud end-points\u000aauto recovery for ha applications based on cloud architecture\u000arehydration procedures in place for underperformance and dr\u000aprocesses ensure audit compliance for both infrastructure and application automation \u000anon-compliant services are auto remediated or isolated \u000aprocesses are mature and focus on control throughout the full service lifecycle\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(688,281,4,'Intelligent','"distributed" cross functional teams are the operating model. these distributed teams continue to take on more of the traditional infrastructure roles as they deliver in a product focus manner. these distributed teams are primarily organized in a product centric approach.  the tbo plays an integral role in defining standards and patterns that enables teams to be structured in a distributed manner.','Teams are organized autonomously and are cross-functionally \u000across functional representation can be direct reports, ccoe assignment, or temporary assignment and dotted line" \u000aclarity of strategy and value propositions are visible in executive leadership with consistency of message and continuous feedback loops \u000a"silo" divisions have been eliminated and holistic collaboration on value delivery is primary \u000adeep partnership relationships are leveraged to accelerate and scale\u000amigration of applications and workloads at scale to various hybrid cloud end-points\u000aauto recovery for ha applications based on cloud architecture\u000arehydration procedures in place for underperformance and dr\u000aprocesses ensure audit compliance for both infrastructure and application automation \u000anon-compliant services are auto remediated or isolated \u000aprocesses are mature and focus on control throughout the full service lifecycle\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(689,134,5,'Adaptive','"federated” teams with complete site engineering capabilities allow for solutions to be deployed to meet customer needs. these federated teams are fully organized from a product perspective.  shared services still exist in the organization to provide common capabilities at scale but "federated" teams are empowered to leverage the services and complete full service functions.   continuous optimization, compliance and cost management are the norm.','Teams are organized autonomously and are cross-functionally represented\u000asite engineering encompassed into cross-functional team\u000anew features, services, and capabilities are driven by customer centric and product centric principles (via value streams if safe) \u000aemerging cloud technologies are evaluated and seamlessly implemented into the appropriate cloud end-points\u000aservices auto register with security/compliance framework for all provisioned systems \u000aai correlation and assessment of all operational data and service events \u000adaily service reporting to infrastructure and application operations for configuration remediation\u000aall services are operated within it security operations framework and disciplines \u000aautomatic collection of security, compliance, regulatory, and financial artifacts at time of remediation \u000ainfrastructure services under continuous review to ensure capabilities meet application needs \u000aincrease end-to-end velocity of service provisioning',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(690,281,5,'Adaptive','"federated” teams with complete site engineering capabilities allow for solutions to be deployed to meet customer needs. these federated teams are fully organized from a product perspective.  shared services still exist in the organization to provide common capabilities at scale but "federated" teams are empowered to leverage the services and complete full service functions.   continuous optimization, compliance and cost management are the norm.','Teams are organized autonomously and are cross-functionally represented\u000asite engineering encompassed into cross-functional team\u000anew features, services, and capabilities are driven by customer centric and product centric principles (via value streams if safe) \u000aemerging cloud technologies are evaluated and seamlessly implemented into the appropriate cloud end-points\u000aservices auto register with security/compliance framework for all provisioned systems \u000aai correlation and assessment of all operational data and service events \u000adaily service reporting to infrastructure and application operations for configuration remediation\u000aall services are operated within it security operations framework and disciplines \u000aautomatic collection of security, compliance, regulatory, and financial artifacts at time of remediation \u000ainfrastructure services under continuous review to ensure capabilities meet application needs \u000aincrease end-to-end velocity of service provisioning',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(691,135,1,'Ad Hoc','Traditional waterfall is predominate but within a few pockets of the organization agile is being leveraged.','Objectives documented \u000askills defined and available\u000afunding and tools \u000aroles and responsibilities defined \u000aproduct planning and prioritization\u000asoftware design\u000anew code production\u000adefect handling\u000arequirements documentation \u000adesign specifications \u000aproject schedules / timelines',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(692,135,2,'Defined','Agile /safe being expanded to multiple teams with pi planning including shared services and is leveraging the concept of innovation at ip iterations. those leveraging traditional waterfall are also reviewing code and refactoring as are the agile teams.','Technical debt mitigation\u000acode review (informal peer review)\u000acode refactoring\u000aresearch and development\u000arelease plans \u000asoftware development life cycle (sdlc) documentation \u000aissue tracking system \u000aversion control',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(693,135,3,'Integrated','For the agile teams the enterprise roles are defined as are release trains. teams are focused on optimizing their delivery.  communication is a key element for both the agile teams and traditional waterfall teams.','\u000atechnology awareness program\u000acommunication process across teams\u000astaff utilization metrics \u000aknowledge transfer process \u000aregular meetings and improvement activities\u000asoftware operation and maintenance automation\u000amanaging development environments\u000asoftware portfolio management reports \u000asoftware quality assurance (sqa) reports \u000asoftware development process improvement plans \u000aproject management process improvement plans\u000acode review (team review) \u000acode review documented',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(694,135,4,'Intelligent','At this level the organization is utilizing agile and/or the scaled agile framework the management and delivery of software development. automated code scanning for security.  metrics and measures tracking to improve code quality.  support for a wide choice of programming languages.  modular, service oriented design approach supporting modern practices. \u000a','Pmo governance and oversight\u000aresource allocation processes\u000areporting and communication processes\u000astrategic alignment\u000acontinuous improvement process\u000a-scaled agile framework\u000aaccelerated release cycle\u000ascaled ci/cd\u000aservice oriented design\u000arisk management plans \u000acapacity and availability plans \u000acontinuous integration plans\u000asoftware architecture documents\u000aautomated code review',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(695,135,5,'Adaptive','At this level, the organization has implemented the scaled agile framework complete with enterprise value streams defined, portfolio backlogs with lean budgets and enterprise strategic themes.','Enterprise value stream definitions\u000aportfolio backlogs\u000alean budgets defined (portfolio backlog specific)\u000ainnovation sprint outcome reporting\u000avalue streams definitions\u000aportfolio definition\u000asafe certified tracking\u000asafe certifications\u000alessons learned training for innovation sprints\u000aenterprise roles definitions\u000aagile release trains\u000aoutcomes of innovation sprints\u000acentralized storage and sharing systems for lessons learned\u000asoftware maintenance plans \u000asoftware development process automation tools\u000acontinuous integration (ci) reviews',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(696,136,1,'Ad Hoc','A lack of standardized tooling presents difficulty identifying location, identity, quantity and status of assets and their dependencies.  usage monitoring is difficult which leads to service interruptions and unintended downtime.','Manual inventory tracking\u000aincomplete inventory\u000ano tracking of ephemeral assets',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(697,136,2,'Defined','Tooling is standardized and auto discover assets is in place.  asset deployment and usage monitoring is automated.  reconciliation and remediation of support issues is enabled by asset inventory.','Auto discovery\u000aautomated deployment and usage monitoring\u000aintegration with support desk\u000ainventory registration integration with provisioning lifecycle',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(698,136,3,'Integrated','Assets and dependencies are tracked from deployment to upgrade to retirement.  analytics in place and used for forecasting.','Reporting on support costs and services\u000acomprehensive inventory tracking\u000adelivery of financial insights',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(699,136,4,'Intelligent','Strong change and configuration management practices support maintaining standards throughout asset lifecycle.','Visibility into assets for a given service or bu\u000aintegration with configuration management practice\u000acontinuous compliance\u000ainternal asset ownership',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(700,136,5,'Adaptive','The organization is continually optimizing  the change and configuration management practices.','Fully automated discovery processes with automated configuration management\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(701,137,1,'Ad Hoc','Limited ci/cd - infrequent releases. limited toolchain and rudimentary processes.','Use of source control\u000atight integrations with release process\u000ause of orchestration engine\u000ause of peer review process\u000ause of binary repo\u000acode quality checks\u000aautomated testing candidates are identified\u000aci/cd workflow standardization\u000aworkflow processes documented and shared\u000aci/cd standards documented and shared\u000aintegration with other management tools\u000aci/cd penetration/coverage across app portfolio\u000abranching strategy documented and shared',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(702,137,2,'Defined','Source control and artifact repositories are used consistently throughout the organization.  branching and merging strategy is in place and widely adopted.  build and deploy processes are scripted but not automated.  rollback/dr plans in place.  logging is in place but is not centralized.','Use of source control\u000atight integrations with release process\u000ause of orchestration engine\u000ause of peer review process\u000ause of binary repo\u000acode quality checks\u000aautomated testing hooks\u000aci/cd workflow standardization\u000aworkflow processes documented and shared\u000aci/cd standards documented and shared\u000aintegration with other management tools\u000aci/cd penetration/coverage across app portfolio\u000abranching strategy documented and shared\u000adocumentation exists\u000adevops culture is understood and implementation plan is formulated\u000aautomated testing candidates are identified\u000alogging and monitoring in place with manual remediation and meets compliance standards\u000asource and artifact repositories are in use\u000abranching and merging strategy is in use\u000arollback/dr is not integrated into delivery process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(703,137,3,'Integrated','The organization has a shared repository of ci/cd tools used by all relevant teams. most teams use automated builds and some form of scripting for testing and deployment. ci/cd tools and practices are consistent between teams.','Use of source control\u000atight integrations with release process\u000ause of orchestration engine\u000ause of peer review process\u000ause of binary repo\u000acode quality checks\u000aautomated testing hooks\u000aci/cd workflow standardization\u000aworkflow processes documented and shared\u000aci/cd standards documented and shared\u000aintegration with other management tools\u000aci/cd penetration/coverage across app portfolio\u000abranching strategy documented and shared',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(704,137,4,'Intelligent','The organization has a comprehensive repository of ci/cd toolchains shared by all relevant teams. build, test, deployment, and monitoring are mostly automated for all relevant teams. there are frequent (weekly or bi-weekly) automated releases. pipeline is fully automated.  deployments are optimized to meet or exceed availability requirements.','Code quality checks\u000aci/cd workflow standardization\u000aworkflow processes documented and shared\u000aci/cd standards documented and shared\u000aintegration with other management tools\u000aci/cd penetration/coverage across app portfolio\u000adevops culture is adopted\u000afull automation is in place\u000acentralized logging and monitoring in place with manual remediation and meets compliance standards\u000asource and artifact repositories are in use\u000abranching and merging strategy is in use\u000arollback/dr is integrated into delivery process\u000aalerting with manual remediation is in place\u000azero downtime deployments',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(705,137,5,'Adaptive','Mature, sophisticated and efficient agile organization. highly automated ci/cd process with advanced automation tools, health checks, integration with ticketing and automated provisioning systems (e.g. servicenow), one touch build/deploy.','Use of source control\u000atight integrations with release process\u000ause of orchestration engine\u000ause of peer review process\u000ause of binary repo\u000acode quality checks\u000aautomated testing hooks\u000aci/cd workflow standardization\u000aworkflow processes documented and shared\u000aci/cd standards documented and shared\u000aintegration with other management tools\u000aci/cd penetration/coverage across app portfolio\u000abranching strategy documented and shared',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(706,138,1,'Ad Hoc','Primary project criteria is roi/tco.  cloud service offerings are ad-hoc or largely customized by application.  management of cloud services is ad hoc.  there is limited visibility of the application roadmap.','Roi/tco driven strategy\u000acustomized cloud service offering per application with ad-hoc management\u000alimited visibility of roadmap',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(707,138,2,'Defined','Application roadmap is forming.  application demand management program is forming and a roadmap for cloud service offerings exists.  billing showback for cloud customers is accurate.','Accurate but not comprehensive billing data\u000ashowback available\u000ainitial iac templating\u000acloud service offering roadmap focused on key areas\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(708,138,3,'Integrated','The visibility for the application roadmap is maturing.  continuous testing of cloud services in in place.  application ingestion processes is in line with cloud service offerings.  timely and accurate direct/indirect billing is in place.','Cost predictability\u000acompliance reporting\u000aautomated testing',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(709,138,4,'Intelligent','The application roadmap enables accurate service forecasting.  service dashboards are in place with accurate billing data as well as qos metrics.  application and cloud service performance objectives are present.','Quality of service metrics\u000abilling dashboards\u000aservice catalog\u000akpis for services established',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(710,138,5,'Adaptive','The application roadmap is in complete alignment with the sdlc.  there is continuous optimization of the cloud service offerings which are largely self-service.  comprehensive tco is included in customer billing.','Self-service cloud service provisioning\u000adetailed reporting\u000acontinuous compliance and cost optimization\u000adetailed application roadmap',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(711,139,1,'Ad Hoc','Object oriented software development practiced by a few teams who are more advanced and well versed in oo techniques.  non separation of application, web, and db tiers observed in a few application coding practices.  hard to refactor code.  manual testing.  sporadic agile practices','Agile introduced\u000aobject oriented practices\u000abegin to decouple tightly coupled monolithic applications architectures and the following: \u000aapplication architectural standards \u000aapplication reference architecture \u000adesign patterns documented \u000aservice architecture documented \u000acontainerization strategy',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(712,139,2,'Defined','Efforts towards standardization on objected oriented software development.  beginning of agile practices in sdlc.  test first strategy adopted.  unit testing performed for mission critical apps. energy consumption by application being documented.','#name?',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(713,139,3,'Integrated','Automated unit testing, test first strategy adopted enterprise wide.  oo software development is defacto for all new software development efforts in the organization.  coding standards defined and published.  agile based software development is a norm.  cyclical, controlled release cycles.  code scanning for vulnerability. frequent code reviews','Automated unit testing\u000a-agile production\u000astable release cycle\u000aci/cd pipeline',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(714,139,4,'Intelligent','Ci/cd, frequent release cycles.  automated code scanning for security.  metrics and measures tracking to improve code quality.  support for a wide choice of programming languages.  modular, service oriented design approach supporting modern practices','#name?',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(715,139,5,'Adaptive','On top of ci/cd, frequent release cycles.  automated code scanning for security.  metrics and measures tracking to improve code quality.  support for a wide choice of programming languages.  modular, service oriented design approach supporting modern practices. \u000aalso making use off emerging ai technologies to improve and test and possibly even execute the code development','#name?',NULL,1);
