INSERT INTO Next_CapabilityLevel VALUES(717,140,1,'Ad Hoc','Production issues are frequent and interrupt delivery of new features.  a siloed operating model results in a lot of tickets without a lot of correlation or established raci.  failure rate when introducing changes is high.','Siloed operating model\u000afrequent failures which interrupt delivery of new features\u000avendor-managed production support with little institutional knowledge of key systems/services\u000asparse reporting of production issue process',NULL,1);
