INSERT INTO Next_CapabilityLevel VALUES(956,184,3,'Integrated','The organization has data search capabilities for structured, simi structured and nonstructured data. the e-discovery processes are mature and automated.','Structured, simi-structured and non-structured data search support processes\u000adata access monitoring\u000ae-discovery segregated repository\u000ae-discovery external sharing process \u000ae-discovery tools',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(957,184,4,'Intelligent','The organization has began to use automated search and is able to utilized federated search tools.','Visual data search tools\u000afederated search tools\u000aautomated search capabilities\u000a',NULL,1);
