INSERT INTO Next_CapabilityLevel VALUES(997,191,4,'Intelligent','All teams use organizationally defined event correlation process/algorithms and are completely effective at reducing signal noise/ratio. systems/tools frameworks are shared amongst the organization and regularly iterated upon to improve their effectiveness.','Guidelines / standards / techniques for event correlation are established.\u000acommon / shared tooling is used.\u000aeffective reduction in signal/noise ratio (e.g. use of alerting for threshold breaches)\u000apro-active processes (e.g. regular reviews) are in place to improve effectiveness.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(998,191,5,'Adaptive','All teams use organizationally defined event correlation process/algorithms and are completely effective at reducing signal noise/ratio. systems/tools frameworks are shared amongst the organization and regularly iterated upon to improve their effectiveness. dedicated resources exist to support these efforts and adoption is high and formalized across all teams. leadership supports and evaluates the event correlation process/algorithms regularly and makes changes as needed to process/policy to support business needs.','Guidelines / standards / techniques for event correlation are established.\u000acommon / shared tooling is used.\u000aeffective reduction in signal/noise ratio (e.g. use of alerting for threshold breaches)\u000apro-active processes (e.g. regular reviews) are in place to improve effectiveness.\u000ademonstrated executive support is observed.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(999,192,1,'Ad Hoc','Each team uses their own baseline image. few baseline images are regularly patched for security updates and the process of patching is manual.','Nonstandard, inconsistent baseline image use.',NULL,1);
