INSERT INTO Next_CapabilityLevel VALUES(1002,192,4,'Intelligent','Most teams are using images from gold standard image templates.','Automated, secure image baking process using industry standard sources (e.g. cis)\u000asupport for at least one os.\u000asupport multiple os and variants.\u000aautomated image refresh process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1003,192,5,'Adaptive','All teams are using images from the gold standard image templates. automated scanning, remediation and refresh process . automated flagging and removal of outdated, expired images.','Automated, secure image baking process using industry standard sources (e.g. cis)\u000asupport multiple os and variants.\u000aautomated image refresh process\u000aautomated image retention and expiration policies',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1004,193,1,'Ad Hoc','Limited to no log automation, most teams use basic, ad-hoc, manual log aggregation internally. limited to none sharing of systems, tools, frameworks and standards intra-team. bespoke and one off logging designs/implementations.','Custom logging solutions are seen implemented.\u000ano centralized logging infrastructure or tooling exists.\u000ano common log automation standards.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1005,193,2,'Defined','Organizationally defined log automation standards developed. inconsistent use of implementation and tooling for logging.','Log automation standards are developed\u000alog aggregation is implemented at a team / app / bu level.\u000amultiple or disparate logging tools are used.\u000amanual logging configuration is the norm',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1006,193,3,'Integrated','All teams use organizationally defined logging automation standards and policies. logging automation is implemented using a standard methodology and framework. universal sharing of logging automation templates for across the organization.','Centralized log aggregation infrastructure /tooling is implemented. (e.g. splunk, elk, sumo)\u000a100% of infrastructure logging captured in centralized logs.\u000alog aggregation capabilities support finops dashboarding requirements',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1007,193,4,'Intelligent','All teams use organizationally defined logging automation standards and policies. logging is 100% automated using standardized methodology and framework. some use of logging analytics and event correlation.','Centralized log aggregation infrastructure /tooling is implemented. (e.g. splunk, elk, sumo) by all app teams.\u000aaverage adoption of logging infrastructure & tooling\u000ause of custom log analytic dashboards by infra/app teams.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1008,193,5,'Adaptive','Organizationally defined log automation standards leverage a culture of continuous improvement. universal sharing of all automation for systems/tools/frameworks across the organization. logging leverages tight integration and correlation between security, compliance, infrastructure and applications logs.','Centralized log aggregation infrastructure and tooling is implemented. (e.g. splunk, elk, sumo) and widely adopted.\u000alogging standards (codes, formats) are well defined and documented and shared enterprise-wide.\u000alogging analytic dashboards, thresholds & alerts are scripted and configured or templatized for use by infra/app teams.\u000alogs are searchable and easily accessible (e.g. via a portal) to anyone that needs them.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1009,194,1,'Ad Hoc','Adhoc, bespoke approach to application, operational and security monitoring designs/implementations. limited to no monitoring standards / tools','Manual monitoring configuration\u000alimited re-use of monitoring configurations\u000ae.g. no/competing monitoring design patterns\u000alimited/no standards defined',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1010,194,2,'Defined','Most teams use basic tools internally, some sharing of tools across the business. some capturing of failure events.','Well defined standards for operational and security monitoring\u000amanual configuration of security and operational monitoring\u000aapplication monitoring is ad hoc/inconsistent.\u000aadoption of basic budget/consumption monitoring \u000amultiple tools/implementations in use.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1011,194,3,'Integrated','All teams use organizationally defined tools and universal sharing of tools across the business. basic data capturing of all failure events.','Standardized monitoring tooling and implementation organization-wide.\u000afully automated configuration / deployment of security and operational monitoring.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1012,194,4,'Intelligent','All teams use organizationally defined tools internally, universal sharing of tools across the business. comprehensive data capturing of all failure events. dedicated resources exist to support it.   adoption is high and formalized across all teams.','Standardized monitoring tooling and implementation organization-wide and widely adopted.\u000afully automated deployment of security and operational monitoring.\u000awell defined processes are in place to define common and infra / application-specific monitoring alerts and metrics as part of app onboarding.\u000abudget monitoring capabilities used to improve forecasting capabilities',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1013,194,5,'Adaptive','All teams use organizationally defined tools internally, universal sharing of tools across the business. comprehensive data capturing of all failure events. dedicated resources exist to support it.   adoption is high and formalized across all teams. leadership supports and evaluates the tools regularly and makes changes as needed to process/policy to support business needs. monitoring includes ai/ml capabilities to identify new metrics and perform auto-remediation / self-healing.','Standardized monitoring standards, tooling and implementation organization-wide and widely adopted.\u000afully automated deployment of security and operational monitoring.\u000awell defined processes are in place to define common and infra / application-specific monitoring alerts and metrics as part of app onboarding.\u000aevents/metrics/thresholds defined and implemented at multiple levels across the entire stack.\u000apro-active processes (e.g. regular reviews) are in place to improve metrics collection and reporting.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1014,195,1,'Ad Hoc','Little to no automation of role based access or policies. organizational policies and procedures inadequate to standardize automated rbac implementation.','Manual deployment of rbac assignments and policies\u000aad hoc assignment of roles',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1015,195,2,'Defined','Limited role based access development and deployment. organizational policies developed/adapted to govern automation adoption, use and implementation of roles based access. standard templates have been developed core roles. ad/ldap integration is in place.','Manual deployment of rbac assignments and policies\u000aad hoc assignment of roles\u000alimited documentation of policies and procedures\u000ainformal processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1016,195,3,'Integrated','Standardized roles and policies defined and managed through automation for core infrastructure. standard templates are built for all it roles. single-sign-on integration is implemented.','Well documented process and policies for role assignment\u000arbac lifecycle automated for core infrastructure.\u000acentral repository of rbac roles and policies\u000aapproved baselines defined.\u000asso capabilities are available for use.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1017,195,4,'Intelligent','Standardized automation covers application, service account, and 3rd party integrations. roles and policies are reviewed continuously to ensure least privilege is maintained.  single-sign-on is implemented for all infrastructure and application teams enterprise-wide.','Rbac lifecycle automated for application, service account, and 3rd party integrations\u000arbac role and policy review process in-place.\u000acentral repository of rbac roles and policies\u000aapproved baselines defined.\u000apolicy dashboards created\u000asso adopted enterprise wide',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1018,195,5,'Adaptive','All roles and policies are automated and managed though a central repository. continuous review of the policies and roles for suitability and applicability. policies dashboards and reporting in place to identify and prevent drift from approved baselines.','Continuous review policy in-place\u000abaseline deviant reports generated and reviewed\u000awell defined remediation processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1019,196,1,'Ad Hoc','The organization has recognized a need to have a common release and deployment process, and has named an owner to lead the practice. currently few teams using release management programs which support automated or manual releases on an ad hoc basis per project. few teams use the same release management system. most release management deployments are manual.  however, there is a d','Manual ad hoc releases.\u000arelease and deployment owner\u000arelease and deployment plan\u000achange management process\u000arelease management review process\u000astakeholders defined \u000arelease notes\u000achange logs \u000abackout plan',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1020,142,2,'Defined','A release management process is used to coordinate and plan the activities of it, the business and suppliers for the test and releases of hardware, software, systems and services into the production environment. most teams use release management programs which support automated releases on an ad hoc basis per project. most teams using the same release management system. many release deployments are automated, but many are manual.','Few teams using automated release management.\u000arelease and deployment team\u000arelease and deployment policy\u000arelease and deployment categories\u000arelease and deployment service definitions \u000arelease and deployment roles defined\u000arelease and deployment schedules\u000arelease and deployment audits\u000askillset enablement \u000aarchitecture tools\u000abusiness analysis and modelling tools\u000aproduct/service modelling tools\u000aprocess modelling tools\u000abusiness analysis tools\u000aprocess modelling tools\u000arelease and deployment management tools\u000apipeline management tools\u000asoftware delivery and integration tools\u000aknowledge base tools\u000a-release plan\u000aconfiguration item record\u000arelease calendar\u000arelease checklist\u000adefinitive media library\u000arelease validation and testing process \u000arelease automation process \u000arelease version control process \u000arelease management metrics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1021,197,2,'Defined','A release management process is used to coordinate and plan the activities of it, the business and suppliers for the test and releases of hardware, software, systems and services into the production environment. most teams use release management programs which support automated releases on an ad hoc basis per project. most teams using the same release management system. many release deployments are automated, but many are manual.','Few teams using automated release management.\u000arelease and deployment team\u000arelease and deployment policy\u000arelease and deployment categories\u000arelease and deployment service definitions \u000arelease and deployment roles defined\u000arelease and deployment schedules\u000arelease and deployment audits\u000askillset enablement \u000aarchitecture tools\u000abusiness analysis and modelling tools\u000aproduct/service modelling tools\u000aprocess modelling tools\u000abusiness analysis tools\u000aprocess modelling tools\u000arelease and deployment management tools\u000apipeline management tools\u000asoftware delivery and integration tools\u000aknowledge base tools\u000a-release plan\u000aconfiguration item record\u000arelease calendar\u000arelease checklist\u000adefinitive media library\u000arelease validation and testing process \u000arelease automation process \u000arelease version control process \u000arelease management metrics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1022,142,3,'Integrated','All relevant teams use release management programs which support automated releases for every project and use the same release management system across delivery teams. the majority of releases are automated.','Automated release management.\u000astreamlined approval process\u000arelease and deployment units\u000arelease and deployment backout plans\u000averification of the service components\u000averification of the release procedures\u000arelease execution\u000arelease verification\u000arelease review\u000a-release readiness checklist \u000a-test plan \u000a-risk assessment\u000a-release management dashboard\u000arelease automation tool\u000arelease improvement plan\u000arelease audit log\u000acontinuous improvement process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1023,197,3,'Integrated','All relevant teams use release management programs which support automated releases for every project and use the same release management system across delivery teams. the majority of releases are automated.','Automated release management.\u000astreamlined approval process\u000arelease and deployment units\u000arelease and deployment backout plans\u000averification of the service components\u000averification of the release procedures\u000arelease execution\u000arelease verification\u000arelease review\u000a-release readiness checklist \u000a-test plan \u000a-risk assessment\u000a-release management dashboard\u000arelease automation tool\u000arelease improvement plan\u000arelease audit log\u000acontinuous improvement process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1024,142,4,'Intelligent','All relevant teams use release management programs which support automated releases for every project and use the same release management system across delivery teams. dedicated resources exist to support it. adoption is high and formalized across all teams.','Automated release management.\u000aexception based release review process.\u000ahigh release frequency\u000atight integration with change management and configuration management',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1025,197,4,'Intelligent','All relevant teams use release management programs which support automated releases for every project and use the same release management system across delivery teams. dedicated resources exist to support it. adoption is high and formalized across all teams.','Automated release management.\u000aexception based release review process.\u000ahigh release frequency\u000atight integration with change management and configuration management',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1026,142,5,'Adaptive','All teams use release management programs which support automated releases for every project and use the same release management system across delivery teams. dedicated resources exist to support it. adoption is high and formalized across all teams. leadership re-examines the overall state of continuous improvement on an on-going basis.','Fully automated/zero touch release management.\u000aexception based release review process.\u000azero downtime releases.\u000avery high release frequency',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1027,197,5,'Adaptive','All teams use release management programs which support automated releases for every project and use the same release management system across delivery teams. dedicated resources exist to support it. adoption is high and formalized across all teams. leadership re-examines the overall state of continuous improvement on an on-going basis.','Fully automated/zero touch release management.\u000aexception based release review process.\u000azero downtime releases.\u000avery high release frequency',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1028,198,1,'Ad Hoc','Few apps and infrastructure deployments  have either been designed with self-service in mind. impetus for the change is driven by individual teams and not companywide.','No self-service capabilities observed.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1029,198,2,'Defined','The company values self-service solutions and some app/software teams designing new or are re-designing current products with self-service in mind. minimal resource investment by the company still limits widespread adoption of this mindset.','Isolated pockets of self-service culture\u000amultiple tools/frameworks in use\u000ainformal guidance on self-service goals',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1030,198,3,'Integrated','Self service designing is the standard organization wide and processes/policies are in place to reflect this goal. standardized tooling and strategy has been developed to promote a consistent user experience.','Organizational self-service goals well-defined\u000aorganizational self-service goals documented and published\u000arefactoring to support self-service low priority',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1031,198,4,'Intelligent','All teams have adopted the companywide policy of designing/re-designing their products to leverage a self-service model where appropriate. success of the efforts of self-service solutions is measured and self-service goals are adjusted as needed.','Organizational self-service frameworks and tools well-defined\u000aorganizational self-service frameworks and tool guidance published\u000arefactoring to support self-service increased priority',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1032,198,5,'Adaptive','All teams have adopted the companywide policy of designing/re-designing their products to align with org self-service goals. success of the efforts of self-service efforts is measured and adjusted as needed. leadership evaluates the success of the self-service model and ensures current policies/procedures allow teams to efficiently leverage self-service.','Metrics and best-practices for self-service well-defined\u000ametrics and best-practices for self-service measured and reported\u000arefactoring to support self-service high priority for organization',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1033,199,1,'Ad Hoc','Few teams integrate automated testing methods; some leverage them on an ad hoc basis','Primarily manual testing.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1034,199,2,'Defined','Most teams use some form of automated testing regularly. improved testing capabilities and results are valued, but not a priority for the company','Automated testing\u000aunit testing\u000aintegration testing',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1035,199,3,'Integrated','Standardized automated testing design and implementation for infrastructure deployments. all teams follow a defined process of using some form of test automation and improvement of the capabilities is a business priority and valuable to the organization.','Test automation standards established organization wide.\u000atest coverage limits (e.g. 80% test coverage) established and mandated.\u000aautomated testing is included as part of the ci/cd pipeline.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1036,199,4,'Intelligent','End to end integration testing integrated into ci/cd pipelines for full stack deployments. an organizationally defined set of test automation coverage has been agreed upon by all teams and a process is in place to guide integration of the methodologies into all projects. teams routinely evaluate the effectiveness of current capabilities against future needs.','Test automation standards established organization wide.\u000atest coverage limits (e.g. 80% test coverage) established and mandated.\u000aend to end automated testing is included as part of the ci/cd pipeline.\u000aperformance testing is a habit.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1037,199,5,'Adaptive','Fully automated deployments leveraging end to end testing with a culture of continuous improvement. an organizationally defined set of test automation coverage has been agreed upon by all teams and a process is in place to guide integration of the methodologies into all projects. leadership routinely evaluate the effectiveness of current capabilities for current and future business needs based on successes and the input of teams.','Test automation standards established organization wide.\u000atest coverage limits (e.g. 80% test coverage) established and mandated.\u000aend to end automated testing is included as part of the ci/cd pipeline.\u000aperformance testing is a habit.\u000achaos / resiliency testing\u000aa/b testing',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1038,200,1,'Ad Hoc','Few teams leverage workflows on a limited basis, but no organizational policies guide their use.','Little to none or adhoc workflow automation processes and manual handoffs between teams.\u000alittle to none workflow automation organizational guidance/policies.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1039,200,2,'Defined','Most teams use informal workflows but little to no standardization one off and bespoke solutions exist. workflow automation has been identified as important but not a priority for the organization.','Ad-hoc workflow automation on team by team case\u000amultiple tools/frameworks in use\u000aorganizational goals for workflow automation defined\u000aefforts to automate workflows given low priority by organization',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1040,200,3,'Integrated','Standards for workflow automation are defined, policies/procedures have been established companywide and standardization and implementation is a priority. basic templates exist for workflow implementation.','Itsm/workflow mgmt. standards and policies are defined.\u000aitsm tooling. (e.g. servicenow)\u000alow adoption',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1041,200,4,'Intelligent','Workflow processes/procedures are formalized and are a strategic priority for all teams and adoption is high. standard workflow templates developed to meet most business needs. effectiveness of templates is evaluated by the team and adjusted as needed','Itsm/workflow mgmt. standards and policies are defined.\u000aitsm tooling. (e.g. servicenow)\u000awide adoption\u000aworkflow templates',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1042,200,5,'Adaptive','Workflow review processes/procedures are formalized and are a strategic priority for all teams and adoption is high. effectiveness of workflows are proactively monitored and evaluated by the team. leadership routinely reviews the success of workflows to make changes as needed for changing business needs.','Itsm/workflow mgmt. standards and policies are defined.\u000aitsm tooling. (e.g. servicenow)\u000awide adoption\u000aworkflow templates\u000aworkflow reviews conducted.\u000afeedback and improvements incorporated regularly.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1043,201,1,'Ad Hoc','Ad hoc: development and operations teams will collaborate and engage in continuous improvement when requested.','Adhoc collaboration as needed.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1044,201,2,'Defined','Repeatable: development and operations teams engage in regular collaboration and seek to continuously improve their support across a number of devops initiatives.','Collaboration channels / meetings between dev and ops happen to a certain degree',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1045,201,3,'Integrated','Defined: development and operations teams have a standardized and documented method for cross team collaboration and learning.','Digital collaboration tools (e.g. wikis)\u000atime allocated for collaboration',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1046,201,4,'Intelligent','Measured: development and operations teams have a standardized and documented method for cross team collaboration and learning. continuous learning is part of a larger strategic initiative and there are metrics tracking its success.','Cross functional communication and collaboration.\u000ause of feedback surveys.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1047,201,5,'Adaptive','Optimized: development and operations teams have a standardized and documented method for cross team collaboration and learning. continuous learning is part of a larger strategic initiative and there are metrics tracking its success. leadership is formally looking to continuously restructured to enhance continuous learning and collaboration metrics.','Alignment between teams.\u000across team collaboration (e.g. bof, guilds).\u000aincentives.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1048,202,1,'Ad Hoc','Ad hoc: few teams identify the need for upskilling employees to meet devops needs and efforts to meet business needs are isolated to silos.  education and knowledge sharing is ad hoc, hard to find, and often times outdated.','Business needs\u000adevops skill needs\u000aeducation processes\u000aknowledge sharing processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1049,202,2,'Defined','Repeatable: business units leverage standard processes for identifying and filling devops skill needs via gap assessments.  within business units there is evidence of cross-functional teams being leveraged and leadership works to develop basic education and upskilling programs at the organization-level and host related data within a centralized repository.','Gap assessments\u000across-functional teams\u000aeducation programs\u000aupskilling programs\u000acentralized data repository (devops related)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1050,202,3,'Integrated','Defined: organization defines skill gap analysis process and requires all teams to keep an up-to-date plan for filling identified gaps via talent development plans.  leadership builds processes to remove barriers preventing cross-functional teams, begins to track basic metrics/kpis associated with effectiveness of education and upskilling program, has robust education and upskilling programs that all employees are required to take some level of, and has a robust centralized repository to store devops skill-related education/data.','Gap analysis process\u000agap assessments\u000abarrier identification program\u000abarrier removal program\u000abarrier tracking program\u000ametrics/kpis (effectiveness of education)\u000aeducation programs\u000aupskilling programs\u000acentralized data repository (devops related)\u000atalent development plans\u000aupskilling plans',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1051,202,4,'Intelligent','Measured: organization has real-time insight into status of progress across all teams and removes all barriers preventing cross-functional teams.  evidence indicates that there is widespread, daily use of the centralized repository (metrics/dashboards) and high employee satisfaction with employee upskilling plans and talent development plans.','Progress tracking mechanisms\u000abarrier tracking program\u000across-functional teams\u000acentralized data repository (devops related)\u000arepository use tracking\u000aemployee satisfaction tracking (upskilling plans & talent development plans)\u000atalent development plans\u000aupskilling plans',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1052,202,5,'Adaptive','Optimized: teams across the organization are cross-functional and frequently work across business units to meet needs.  there are dedicated resources that continuously update devops education material in a centralized repository and robust talent development plans are actively used.  leadership tracks progress in real time via robust dashboards and continuously evaluates effectiveness of training materials and processes.','Cross-functional teams\u000adedicated resources (updating devops material)\u000adashboards\u000aeffectiveness tracking (training materials and processes)\u000acontinuous review cycle',NULL,1);
