INSERT INTO Next_CapabilityLevel VALUES(1073,20,1,'Ad Hoc','No personal or team accountability for problems and a "throw it over the wall" philosophy is practiced.  developers have limited ownership of production problems. not driven by organization-wide process or leadership. no promotions or value placed on employees comprehension of service delivery metrics','Highly siloed organization.\u000aorganizational structure creates barriers to collaboration/ownership\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1074,204,1,'Ad Hoc','No personal or team accountability for problems and a "throw it over the wall" philosophy is practiced.  developers have limited ownership of production problems. not driven by organization-wide process or leadership. no promotions or value placed on employees comprehension of service delivery metrics','Highly siloed organization.\u000aorganizational structure creates barriers to collaboration/ownership\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1075,20,2,'Defined','Most teams have standard delivery sla/slos for all projects to track and provide insight to employees regarding their performance based on certain quality standards across projects. this is not an organizational priority and as a result no standards are in place nor tracked company-wide.\u000a some teams support an ownership culture, however it is not a priority. the level of engagement and resource investment in the activity is low as well.','Some teams support ownership culture but not promoted organizationally.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1076,204,2,'Defined','Most teams have standard delivery sla/slos for all projects to track and provide insight to employees regarding their performance based on certain quality standards across projects. this is not an organizational priority and as a result no standards are in place nor tracked company-wide.\u000a some teams support an ownership culture, however it is not a priority. the level of engagement and resource investment in the activity is low as well.','Some teams support ownership culture but not promoted organizationally.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1077,20,3,'Integrated','Creating a culture of ownership amongst the development team is an organizational priority and practiced by all teams with mixed results. basic, standard sla/slos are in place and tracked companywide. these standards are used as the basis for employee evaluations post-project and feedback from delivery employees is gathered.','Culture of ownership',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1078,204,3,'Integrated','Creating a culture of ownership amongst the development team is an organizational priority and practiced by all teams with mixed results. basic, standard sla/slos are in place and tracked companywide. these standards are used as the basis for employee evaluations post-project and feedback from delivery employees is gathered.','Culture of ownership',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1079,20,4,'Intelligent','The processes and procedures for a culture of ownership are formalized across all teams and supported by the organization. results are tracked to evaluate success. a standardized, formal set of sla/slos are in place and tracked companywide. individuals and teams are evaluated based upon these set benchmarks to ensure consistent quality across projects.','Culture of ownership.\u000acompanywide sla/slos for quality / improvements.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1080,204,4,'Intelligent','The processes and procedures for a culture of ownership are formalized across all teams and supported by the organization. results are tracked to evaluate success. a standardized, formal set of sla/slos are in place and tracked companywide. individuals and teams are evaluated based upon these set benchmarks to ensure consistent quality across projects.','Culture of ownership.\u000acompanywide sla/slos for quality / improvements.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1081,20,5,'Adaptive','The org structure amplifies the culture of ownership. processes and procedures are formalized across all teams and supported by the organization. results are tracked to evaluate success on an ongoing basis. leadership is actively involved in supporting and adjusting policies to allow for continued success. employee feedback is tracked and used for improvements.','Very strong culture of ownership\u000aformal benchmarks tracking ownership across teams.\u000aemployee feedback for continuous improvement.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1082,204,5,'Adaptive','The org structure amplifies the culture of ownership. processes and procedures are formalized across all teams and supported by the organization. results are tracked to evaluate success on an ongoing basis. leadership is actively involved in supporting and adjusting policies to allow for continued success. employee feedback is tracked and used for improvements.','Very strong culture of ownership\u000aformal benchmarks tracking ownership across teams.\u000aemployee feedback for continuous improvement.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1083,205,1,'Ad Hoc','Some development and operations groups engage in continuous improvement practices, but it''s not driven by any organization wide process or leadership.
INSERT INTO Next_CapabilityLevel VALUES(1084,205,2,'Defined','The organization values continuous improvement, however it is not a priority.  the level of engagement and resource investment in the activity is low as well.\u000aseveral managers have adjusted goals to incentivize greater collaboration, continuous improvement and delivery in common standards, automation, and cloud usage. this practice is not an official part of the leadership strategy and is not companywide.','Reduced fire-drills / ad hoc solutioning\u000alow frequency of continuous improvement practices.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1085,205,3,'Integrated','The organization values continuous improvement, and it is a priority.  the level of engagement and resource investment in the activity is evident.\u000acompany strategy dictates that all relevant employees have goals and incentivized to collaborate and improve common standards, automation, and shared devops practices. this strategy has just been defined and is currently being proven and potentially rolled out companywide.','Regular cadence established for improvement practices.\u000adocumented devops processes.\u000areduced occurrence of fire drill incidents.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1086,205,4,'Intelligent','Continuous improvement is a strategic priority within all delivery organizations.  process and best practices are documented and promoted. dedicated resources exist to support it.   adoption is high and formalized across all teams.\u000acompany strategy dictates that all relevant employees have goals and are incentivized to collaborate and improve common standards, automation, and shared devops practices. this strategy has been proven and is being rolled out companywide. goals are tracked across the organization as a key metric for product cycle time delivery.','Regular cadence established for improvement practices.\u000aincentives for organizational impact.\u000afire drills rarely occur.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1087,205,5,'Adaptive','Continuous improvement is a strategic priority within all delivery organizations.  process and best practices are documentation and promoted. dedicated resources exist to support it.   adoption is high and formalized across all teams.  leadership re-examines the overall state of continuous improvement on an on-going basis.\u000acompany strategy dictates that all relevant employees have goals and are incentivized to collaborate and improve common standards, automation, and shared devops practices. this strategy has been proven and is being rolled out companywide. goals are tracked across the organization as a key metric for product cycle time delivery.  leadership closely tracks and adjusts metrics to ensure greater alignment.','Strategic importance to devops practices/culture.\u000acultivation and practice for high impact improvement ideas.\u000ahigh frequency of communication of improvement strategies and backlog.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1088,206,1,'Ad Hoc','The development and operations organizations are distinctly separated and accountability/responsibility has specific beginning and end. there is little or no collaboration and communication between the development and operations teams. development focuses specifically on development and passes responsibility off to operations when a product is ready for release. little or no feedback loops exist between operations and development','Early devops adopters identified\u000aexecutive buy-in/sales pitch determined\u000ashort term strategy established',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1089,206,2,'Defined','A concept for integrating development and operations exist and clear accountability and responsibility guidelines are outlined.\u000asome shared accountability/responsibility exists between development and operations (i.e. operations is involved in the development process or development maintains some service responsibility after a release occurs)','Early devops adopters begin sharing responsibility/accountability\u000aexecution on short-term strategy begins\u000adevelopment of long-term vision begins',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1090,206,3,'Integrated','Teams begin to work as one, with early adopters championing change\u000abeginning of a raci to outline responsibility within the team\u000adevelopment and operations still maintain control of their focus areas, but the teams work closely together to produce product and customer driven outcomes','Second layer of adoption among team members occurring\u000ainitial raci for team integration is created\u000amultiple short-term and strategy items are producing visible benefits\u000aconcept is validated and formal investment has been identified (training, tools, etc.)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1091,206,4,'Intelligent','Culture of shared responsibility is prevalent\u000alate adopters are being brought into the momentum of integration between the teams\u000araci is established for cross-functional team','Short-term goals culminating into long-term vision items\u000ainvestment secured\u000aenablement tooling has been implemented\u000alate adopters become involved\u000araci is created',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1092,206,5,'Adaptive','Small cohesive teams are established including both development and operations focused individuals. both development and operations focused team members are involved in the development process and maintaining product stability. developers commonly take on operations/support tasks. feedback loops are established as part of the cohesive team or continuously improve the product.','Long-term vision has been implemented\u000acontinuous feedback is collected and actioned on',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1093,207,1,'Ad Hoc','Few teams integrate automation into their processes/procedures however tooling and tooling usage is not standardized.  there is no standard approach organization wide to automation.','Automation goals\u000atooling boundaries\u000aautomation standards development',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1094,207,2,'Defined','Most teams leverage some level of automation and standard usage and tooling boundaries exist within teams. the company values what automation can add, but has not made automation an organizational priority.','The organization should:\u000adevelop automation standards that cover core it needs, also being the process of developing application automation standards.\u000adefine automation tooling boundaries and determine acceptable usage while preventing overlap between tools.\u000autilize standard approach for development via automation for new infrastructure projects.\u000aestablish automation standards in place for all infrastructure needs and ensure that all infrastructure deployments are in alignment with.\u000acreate an automation standards committee to provide periodic updates to standards and incorporate new technologies.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1095,207,3,'Integrated','Established processes/procedures guide automation adoption in line with the automation framework. standards developed to govern automation approach and develop tooling boundaries.','The organization should:\u000aset automation standards in place for all infrastructure and application development and automated testing needs.\u000aensure all infrastructure and applications deployments meet automation standards.\u000aestablish the automation standards committee to provide proactive reviews of standards and to review proposals for new technologies.\u000agenerally, the committee should push the organization to challenge status quo and is responsible for governing automation.\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1096,207,4,'Intelligent','Automation standards have been implemented by application and infrastructure teams across the organization. exceptions to automation standards are tracked and approved by a standards committee. teams routinely evaluate their portfolio to assess the ability to further enhance efficiencies of automation.','The organization should have:\u000aapplication, infrastructure and automated testing tools are deployed\u000acreate an exception process for any non-automated deployment processes that must be signed off on by the automation committee.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1097,207,5,'Adaptive','Automation standards committee proactively reviews automation approach and adjusts standards to align with industry best practices. automation standards have been implemented by application and infrastructure teams across the organization. exceptions to automation standards are tracked and approved by a standards committee. teams routinely evaluate their portfolio to assess the ability to further enhance efficiencies of automation.','The organization should have:\u000aautomation standards developed and matured with a culture of contiguous improvement',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1098,208,1,'Ad Hoc','Organization lacks of full understanding of risk exposure. very little to none in terms of published guidance on standards around compliance and risk exist.','Very high possibility of risk exposure',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1099,208,2,'Defined','Regulatory compliance is defined and managed in silos. process discipline is unlikely to be rigorous.','Compliance addressed in siloes.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1100,208,3,'Integrated','Compliance framework and processes are is in place. an organization-wide view of compliance and risk is provided to executive leadership in the form of a list of so-called ‘top’ risks. action plans are implemented in response to high priority risks.','Established compliance framework.\u000aculture of risk awareness is established.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1101,208,4,'Intelligent','Compliance management activities coordinated across business areas. common compliance management tools and processes are widely in use. enterprise-wide compliance / risk monitoring, measurement and reporting. alternative responses and scenario planning with an emphasis on managing risk.','Coordinated approach to meeting compliance objectives across business areas.\u000acompliance / risk monitoring, measurement and reporting.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1102,208,5,'Adaptive','Complete understanding of compliance in the context of strategic planning, allocation, business objectives. compliance processes span entire organization / geographies. focus shifts from managing compliance and risk to managing success, achievement of objectives. early warning systems exist to notify when compliance/risk exposure could occur tied with impact to enterprise objectives. industry benchmarking happens regularly.','Complete understanding of compliance in context of performance / objectives.\u000aconsistent compliance processes across organization/geographies.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1103,209,1,'Ad Hoc','Few apps have either been designed for the cloud or are being evaluated/redesigned for a shift to cloud on an ad hoc basis.  impetus for the change is driven by individual teams and not companywide. standards around application design and consumption of paas have not been defined.','Release processes in place\u000ainfrastructure requirements \u000aautomation requirements \u000aformalized design strategy',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1104,209,2,'Defined','The company sees value in cloud-based application design and leveraging paas solutions. most app/software teams designing new or are re-designing current products to live in the cloud. basic standards developed around application design and usage of paas resources. resource investment by the company still limits widespread adoption of this mindset.','The organization should have:\u000astandards defined for paas solution consumption\u000astandards defined for application design\u000apaas usage patterns',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1105,209,3,'Integrated','Standards for application design and consumption of paas resources leveraging cloud best practices are well defined and in use organization wide.  all new application development follows these standards regardless of desired hosting location.','The organization should have:\u000acloud best practices documented\u000aapplication development follows cloud best practices\u000amicroservices\u000amulti-platform\u000asustainability best practices are documented \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1106,209,4,'Intelligent','All teams have adopted the companywide policy of designing/re-designing their products in line with development standards supporting cloud best practices. success of the efforts to put solutions in the cloud is measured and adjusted as needed.','The organization should have:\u000aadd development focuses on cloud best practices and portability\u000acontainers and serverless\u000amulti-platform hosting\u000aautomated testing within the release process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1107,209,5,'Adaptive','All teams have adopted the companywide policy of designing/re-designing their products to leverage cloud best practices. success of the efforts to put solutions in the cloud is measured and adjusted as needed. leadership evaluates the success of development efforts and ensures current policies/procedures allow teams to effectively build solutions in alignment with cloud best practices.','The organization should have:\u000ano touch ci/cd\u000aproactive failure testing\u000aseamless releases',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1108,210,1,'Ad Hoc','Devsecops or security/testing is considered external to the software delivery lifecycle','No practice/notion of devsecops',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1109,210,2,'Defined','Dev/secops goals defined on a per team basis. decentralized thought leadership.','Awareness of importance of security testing, secure sdlc\u000apockets of manual security, vulnerability, penetration testing.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1110,210,3,'Integrated','Devsecops defined as organizational direction. initial guidance and standards published. devsecops tooling is in place.','Devsecops standards are documented.\u000aautomated vulnerability scanning / penetration testing',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1111,210,4,'Intelligent','Devsecops is standard operating model and part of software delivery pipeline. security code reviews and metrics defined.','Security automation and testing pipeline\u000aautomated vulnerability scanning / penetration testing\u000athreat modelling\u000asecurity focused code reviews and security acceptance testing.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1112,210,5,'Adaptive','Security awareness and automation is in the dna of the organization. metrics measured and reported. accountability defined.','Security automation and testing pipeline.\u000aautomated vulnerability scanning / penetration testing\u000athreat modelling\u000asecurity focused code reviews and security acceptance testing.\u000aapplication security testing (static, dynamic, interactive, mobile, runtime, container & infrastructure)\u000ametrics to measure security issues/vulnerabilities found and fixed.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1113,211,1,'Ad Hoc','Oversight of design is informal. most deployments are unique. any design patterns arising organically via re-use of architectures that worked for other similar deployments.','\u000apatching process\u000aserver naming convention\u000aserver configuration process\u000a\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1114,269,1,'Ad Hoc','Oversight of design is informal. most deployments are unique. any design patterns arising organically via re-use of architectures that worked for other similar deployments.','\u000apatching process\u000aserver naming convention\u000aserver configuration process\u000a\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1115,211,2,'Defined','Oversight of design is defined but decentralized. design patterns for items rising organically.','The organization should have:\u000astandard design patterns identified \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1116,269,2,'Defined','Oversight of design is defined but decentralized. design patterns for items rising organically.','The organization should have:\u000astandard design patterns identified \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1117,211,3,'Integrated','Oversight of design is decentralized. most deployments follow standard templates. design patterns are centrally managed and communicated.','The organization should have:\u000aarchitectural standards\u000astandard design artifacts \u000aformal design reviews for infrastructure patterns',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1118,269,3,'Integrated','Oversight of design is decentralized. most deployments follow standard templates. design patterns are centrally managed and communicated.','The organization should have:\u000aarchitectural standards\u000astandard design artifacts \u000aformal design reviews for infrastructure patterns',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1119,211,4,'Intelligent','Design patterns specify required design artifacts, key metrics, benchmarks and best practices.','The organization should have:\u000areusable design artifacts\u000ainfra metrics and kpis\u000aapproved deployment packages \u000acentral repo\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1120,269,4,'Intelligent','Design patterns specify required design artifacts, key metrics, benchmarks and best practices.','The organization should have:\u000areusable design artifacts\u000ainfra metrics and kpis\u000aapproved deployment packages \u000acentral repo\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1121,211,5,'Adaptive','Most design patterns are pre-approved, industry leading and enabled for self-service.','The organization should have:\u000atemplate library\u000apreapproved patterns and processes\u000aself-service immutable infrastructure',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1122,269,5,'Adaptive','Most design patterns are pre-approved, industry leading and enabled for self-service.','The organization should have:\u000atemplate library\u000apreapproved patterns and processes\u000aself-service immutable infrastructure',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1123,212,1,'Ad Hoc','The organization has developed a program and project management (ppm) implantation plan.','There is a documented plan for the implementation and operation of ppm\u000aproject brief / charter / mandate\u000aproject plan\u000arisk register (identification of risk)\u000aresource plan\u000acommunications plan',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1124,212,2,'Defined','The project manager is responsible for the work in the managing projects and managing product delivery process. the project manager also delegates responsibility for the managing product delivery process to the team manager(s).','Documented process \u000aauthorize a project or program process \u000aauthorize the project process \u000aauthorize a stage or exception plan process \u000aauthorize project closure process \u000aapproved project brief, business case, and stage or exception plan template\u000alessons learned template\u000arisk register template\u000aapproved product descriptions templates\u000auser acceptance document template\u000aproject reports template\u000aproject status reports\u000aproject change requests\u000ameeting minutes of project review/progress meetings\u000aaction item log / kanban\u000aproject dashboard\u000aproject risk analysis',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1125,212,3,'Integrated','As the depth of projects grows, the organization realizes the need a  program manager and cross functional oversight bodies for larger project (project boards).','Ppm review process\u000aproject oversight board\u000akpis and metrics\u000aall project roles defined \u000aproject board business case\u000aprogram manager\u000aproject portfolio reports\u000aissue log\u000aproject budget\u000aproject schedule\u000a(pro)active risk management',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1126,212,4,'Intelligent','As an organization with  many projects running at the same time  a program office  is established to offer appropriate support. \u000a','Pmo governance and oversight\u000aresource allocation processes\u000areporting and communication processes\u000astrategic alignment\u000acontinuous improvement process\u000apost-implementation reviews\u000aproject performance metrics\u000aproject quality assessments\u000aproject staff performance reports\u000aproject benefits realization reports',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1127,212,5,'Adaptive','The organization has implemented the scaled agile framework complete with enterprise value streams defined, portfolio backlogs with lean budgets and enterprise strategic themes.','Enterprise value stream definitions\u000aportfolio backlogs\u000alean budgets defined (portfolio backlog specific)\u000ainnovation sprint outcome reporting\u000avalue streams definitions\u000aportfolio definition\u000asafe certified tracking\u000asafe certifications\u000alessons learned training for innovation sprints\u000aenterprise roles definitions\u000aagile release trains\u000aoutcomes of innovation sprints\u000acentralized storage and sharing systems for lessons learned\u000aproject portfolio reviews\u000abusiness case analysis\u000aproject portfolio roadmap\u000aproject governance model\u000aproject maturity assessment',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1128,213,1,'Ad Hoc','Few engineering teams agree to follow modern sdlc practices including devops on an ad-hoc basis and there is not standardization companywide nor are there processes in place to encourage use of modern methods.','Very high lead time for business changes.\u000amanual and infrequent releases.\u000aarduous change review process.\u000adisparate tooling, tracking of requirements.\u000ahigh rate of failures / degradations.\u000along time to recover from failures / degradations.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1129,213,2,'Defined','Modern sdlc practices including devops are valued by the organization as a whole, but there is limited resource allocation or encouragement to follow best practices as a standard. some teams practice modern engineering methodologies.','Teams following their own tooling and processes.\u000alow adoption of standardized sdlc environments and tooling',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1130,213,3,'Integrated','Modern sdlc practices including devops are defined as the gold standard organization wide. ','High frequency of releases.\u000astandardized sdlc environments and tooling\u000acloud native engineering practices',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1131,213,4,'Intelligent','Modern sdlc practices including devops are defined as the gold standard organization wide. all teams are dedicated to staying current on best practices and incorporating them into all aspects of the development process. adoption is high and formalized amongst all teams.','High frequency of releases.\u000ahigh requirements traceability.\u000acloud native engineering practices\u000aagile, peer reviewed process.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1132,213,5,'Adaptive','Modern sdlc practices including devops are defined as the gold standard organization wide. all teams are dedicated to staying current on best practices and incorporating them into all aspects of the development process. adoption is high and formalized amongst all teams. leadership regularly evaluates the current practices and adjusts standards and established processes as need to ensure continued success companywide.','High frequency of releases.\u000ahigh requirements traceability\u000acloud native engineering practices\u000aagile, peer reviewed process.\u000aregular process reviews, retrospectives lead to measurable improvements.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1133,214,1,'Ad Hoc','Limited effectiveness of governance and monitoring applied only to high priority business units','Ad-hoc metrics available for a subset of the organization\u000aeffectiveness understood on a limited set of metrics/criteria',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1134,214,2,'Defined','Most business units are effectively supported by the company''s governance and monitoring mechanisms. expanding support companywide is planned, but not a priority for the business.','Metrics are collected for various parts of the business\u000alacking full visibility across the business\u000ametrics provide low level of effectiveness measures and understanding\u000abasic finops metrics implemented',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1135,214,3,'Integrated','All business units are covered by basic governance and monitoring mechanisms. ','Metrics provide basic effectiveness measures and understanding\u000afull coverage/visibility across the business\u000abasic unit economics metrics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1136,214,4,'Intelligent','All business units are covered by advanced governance monitoring mechanisms effectively meeting or exceeding business and operating requirements.','Metrics provide full featured effectiveness measures\u000adetermine alignment to defined improvement goals and outcomes\u000aability to make efficiency gains and more towards optimal performance',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1137,214,5,'Adaptive','All business units are covered by advanced governance and monitoring mechanisms effectively meeting or exceeding business and operating requirements. leadership routinely evaluates the mechanisms in place and ensures they are meeting the current needs of the business and keeping up with the market.','Monitoring features provide insights into continued optimization\u000abusiness needs are evaluated and aligned to\u000atooling provides preemptive correction where needed',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1138,215,3,'Integrated','Organization is architecting cloud infrastructure by leveraging container design and architecture.','Depth of skill\u000aarchitecture processes for leveraging containers\u000aorganization has a mature container practice \u000acontainerization is common throughout the organization and used where appropriate\u000acentralized library of approved images (security practice is involved)\u000acontainers are integrated into the ci/cd process – allowing automated testing and deployment\u000acontainer logs are aggregated and evaluated with other application logs for troubleshooting, event monitoring and analytics\u000aworkloads are properly normalized (e.g. multi-tier applications are hosted via multiple containers)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1139,215,4,'Intelligent','Organization has standardized process to bring containers to all necessary aspects of the cloud and does this by baking in review cycles of container technologies, leveraging agile methodology to drive fast innovation, and running standardized innovation processes. containerization is elastic based on metrics, as well as redundant in order to ensure our apps stay online to support our customers.','Depth of skill\u000adefined strategy for containers\u000aarchitecture processes for leveraging containers\u000acontainers are elastic – scale up and down based on metrics\u000acontainers are redundant with failover capability\u000aimage updates are automatically and seamlessly scaled into live deployments',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1140,215,5,'Adaptive','Organization is a leader in container innovation and publishes frequently new processes, containers, updates, etc. of containers.  container-style design is baked into all architecture designs as well as overall organization business strategy and the organization has a continuously updated strategy and associated processes to innovate on containers.  organization works with open source as a contributor and user.','Depth of skill\u000adefined strategy for containers\u000aarchitecture processes for leveraging containers\u000aopen source projects\u000acontainer-related processes/information publishing',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1141,216,3,'Integrated','Organization is architecting cloud infrastructure by leveraging newest design and architecture.','Learning program for new csp features\u000adiscovery program for new csp features\u000ametrics for new csp feature integration (% integrated, % explored, % successful, etc.)\u000aorganizational initiatives to ensure integration of csp features (metrics, kpis, strategies, etc.)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1142,216,4,'Intelligent','Organization has standardized process to bring newest technologies to all necessary aspects of the cloud and does this by baking in review cycles of newest technologies, leveraging agile methodology to drive fast innovation, and running standardized innovation processes.','Learning program for new csp features\u000adiscovery program for new csp features\u000ametrics for new csp feature integration (% integrated, % explored, % successful, etc.)\u000aorganizational initiatives to ensure integration of csp features (metrics, kpis, strategies, etc.)\u000anewest capability integration processes and standards',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1143,216,5,'Adaptive','Organization is a leader in newest csp technology innovation and publishes frequently new processes, strategies, updates, etc. of newest technologies.  new technology-style design is baked into all architecture designs as well as overall organization business strategy and the organization has a continuously updated strategy and associated processes to innovate.  organization works with open source as a contributor and user.','Open source projects\u000aauthoritative source on newest csp capabilities',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1144,217,1,'Ad Hoc','Organization pursues new innovative cloud technologies on ad hoc basis and encourages employees to actively pursue new innovative technologies.','Exploration process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1145,217,2,'Defined','Organization defines standardized processes for cloud technology discovery and bakes into talent development programs.','Exploration process\u000aevaluation process\u000atraining and education process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1146,217,3,'Integrated','Organization develops processes to incubate discovered cloud technologies and defines structured programs to move employee idea (discovery) from basic understanding to deciding on implementation to full deployment of new cloud technology.','Quantity of identified cloud technologies\u000aquantity of leveraged cloud technologies\u000aexploration process\u000aevaluation process\u000aselection process\u000atraining and education process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1147,217,4,'Intelligent','Standardized and repeatable processes are prevalent across organization that work to improve cloud experiences.  all employees are able to participate in innovation related to discovery, incubation, and acceleration of internal and external cloud technologies and all processes are updated and reviewed continuously for improvements.  organization works with open source as a contributor and user.','Quantity of identified cloud technologies\u000aquantity of leveraged cloud technologies\u000aexploration process\u000aevaluation process\u000aselection process\u000atraining and education process\u000aopen source project participation',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1148,218,1,'Ad Hoc','Organization leverages out of the box solutions for ml/ai and innovation is defined by acquiring new industry products.','Out of the box solutions',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1149,218,2,'Defined','Organization uses multiple ml/ai products to drive aspects of business and may also confirm solutions using at least two different out of the box approaches.','Out of the box solutions\u000aquantity of out of the box solutions\u000astructured evaluation process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1150,218,3,'Integrated','Organization takes a deeper dive into understanding ml/ai approaches used and leverages learned strategies/technologies to drive future product development to better service customers and lines of business.','Quantity of unique ai strategies employed (chatbots, predictive analytics, autofill, vision, etc.)\u000astructured education processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1151,218,4,'Intelligent','Organization uses expertise to design and develop own ml/ai that are unique to the organization.  innovation events are held continuously to perfect and build out new ml/ai to fit organization/customer needs.','Quantity of unique ai strategies employed (chatbots, predictive analytics, autofill, vision, etc.)\u000astructured evaluation process\u000astructured education processes\u000ain house ml/ai algorithms',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1152,218,5,'Adaptive','Organization is a leader of ml/ai and operates in some capacity as a think tank.  ml/ai is a core component of organization''s competitive edge and a key feature of overall innovation strategy to design the future.  ml/ai is intertwined tightly with cloud computing resources to acceleration innovation.  organization works with open source as a contributor and user.','Quantity of unique ai strategies employed (chatbots, predictive analytics, autofill, vision, etc.)\u000astructured evaluation process\u000astructured education processes\u000ain house ml/ai\u000aactive in open source community (consumer and creator)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1153,219,3,'Integrated','Organization is architecting with cloud agnostic in mind, developing skills related to all major csps, and exploring the key features of cpss that can be exploited.','Cloud agnostic testing and validation (are there standard tests that can be applied to any cloud)\u000areal-time mapping of csp services against other csp services (including pre-release)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1154,219,4,'Intelligent','Organization is running tests of different csps'' features and services in preparation of leveraging unique features of a given csp.','Quantity of clouds used\u000adr/bcp across multi-cloud\u000acloud agnostic testing and validation (are there standard tests that can be applied to any cloud)\u000amulti-cloud expertise (i.e. depth of knowledge in each cloud based on employee skills)\u000areal-time mapping of csp services against other csp services (including pre-release)\u000aarchitecture design, architecture documentation (readable across csps, translatable between csps, etc.)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1155,219,5,'Adaptive','Organization seamlessly applies the best option (of service/feature) from csps to define competitive edge and be a leader in adaption and leveraging of new technologies.  the is no dependence on a single csp through carefully designed architecture and forward-thinking  style of design.  organization works with open source as a contributor and user.','Quantity of clouds used\u000adr/bcp across multi-cloud\u000acloud agnostic testing and validation (are there standard tests that can be applied to any cloud)\u000amulti-cloud expertise (i.e. depth of knowledge in each cloud based on employee skills)\u000areal-time mapping of csp services against other csp services (including pre-release)\u000aarchitecture design, architecture documentation (readable across csps, translatable between csps, etc.)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1156,220,1,'Ad Hoc','Organization identifies multiple technology solutions to leverage on ad hoc basis with limited to no interactions between solutions','Technology identification process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1157,220,2,'Defined','By leveraging learning capabilities, the organization begins to intertwine various solution talent to increase cross-pollination surrounding usage of solutions.','Technology identification process\u000astructured evaluation process\u000aeducation and training processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1158,220,3,'Integrated','The organization uses defined processes to ensure constant cross-pollination of solution expertise and encourages experimentation of multi-technology solutions.','Education and training processes\u000aexperimentation tracking',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1159,220,4,'Intelligent','Multi-tech talent departs silo and begins to learn other solutions and leverages organization''s innovative functions to help chart a path forward with multi-tech.','Silo identification and tracking metrics/kpis',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1160,220,5,'Adaptive','Organization leverages multi-tech solutions to enhance innovative practices by combining key benefits of each technology in conjunction to solve complex, multi-dimensional problems.  experts from each technology often times have more than one expertise and combine fields of interest at will.  organization works with open source as a contributor and user.','Open source community (consumer and/or creator)\u000asilo identification and tracking metrics/kpis',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1161,221,1,'Ad Hoc','Organization uses out of the box security tools and innovation occurs in pockets around specific tool features.','Structured evaluation process\u000astructured selection process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1162,221,2,'Defined','Organization builds standardized processes to capture security tool events and builds working teams to innovate and fix any issue.','Structured education processes\u000acommunication plan\u000aknowledge sharing database/centralized system',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1163,221,3,'Integrated','Organization designs security architecture and solutions to identify security-related events before the events occur.  using identified events, the organization builds innovation pipelines to design additional tools/features.','Security-related innovation pipeline\u000asecurity event trend analysis\u000asecurity event database',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1164,221,4,'Intelligent','Organization designs security architecture and solutions to remediate security-related events before the events occur.  using identified events, the organization builds standardized innovation infrastructure that is self-sustaining to design additional tools/features.','Security-related innovation pipeline\u000asecurity event trend analysis\u000asecurity event database\u000asecurity event remediation architecture',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1165,221,5,'Adaptive','Organization leverages technologies (ai/ml/containers/etc.) to predict security related issues before they occur and automatically mitigate.  organization then uses lessons learned to innovate and improve security stance of overall company and acts an industry leader and publishes white papers/strategies/technologies to help protect all.  organization works with open source as a contributor and user.','Active in open source community (consumer and creator)\u000asecurity ml/ai\u000aautomated security event remediation and identification\u000asecurity whitepapers',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1166,222,1,'Ad Hoc','There is at least one formal incremental improvement program within the organization, and kpis are defined and measured against. the organization has identified a need to expand this program.','Incremental improvement program\u000aincremental improvement program metrics/kpis\u000adocumented implementation plan \u000aservice improvement policy defined',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1167,222,2,'Defined','There are either several formal incremental improvement programs within the organization or one program reaching across several areas. \u000athe organization has a defined continual improvement program.  kpis are defined and measured against.','Continual improvement program\u000acontinual improvement program metrics/kpis\u000acontinual improvement program metrics/kpis tracking\u000aimprovement tracking process\u000ainstalled continual improvement register\u000adefined improvement evaluation process \u000acontinual improvement funding',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1168,222,3,'Integrated','There is a unified, organization-wide continual improvement program. there are incentives in place for management to focus on incremental improvement and measure against universally-understood kpis.','Incremental improvement program\u000aemployee incentives (incremental improvement program)\u000acentralized process \u000astandardized communication program\u000aimprovement ideation capture processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1169,222,4,'Intelligent','The organization has expanded the continual improvement program as part of the defining culture.','Improvement trend analysis process\u000apost implementation success criteria measurement process\u000aintegration into the culture through senior leadership documented expectations',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1170,223,1,'Ad Hoc','An innovation vision or strategy is defined in at least one "pocket" of the organization; there has been at least one attempt to define innovation goals within the organization','Innovation vision\u000ainnovation strategy\u000ainnovation goals',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1171,223,2,'Defined','Innovation vision and strategy are formally defined in at least one area of the organization','Innovation vision\u000ainnovation strategy',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1172,223,3,'Integrated','Innovation vision and strategy are formally established with executive buy-in and understood across several areas within the organization','Innovation vision\u000ainnovation strategy\u000aexecutive buy-in tracking\u000aexecutive education program',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1173,223,4,'Intelligent','Innovation vision and strategy are used to measure success across all areas of the organization by leadership; every department is actively incentivized to carry out the vision and strategy','Innovation vision and strategy metrics/kpis\u000ainnovation progress tracking\u000aincentive program (meeting vision and strategy metrics/kpis/goals)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1174,223,5,'Adaptive','Innovation vision and strategy are core to the board-level and c-suite level strategy of the organization and are considered a competitive advantage. there are executive incentives tied to innovation','Innovation vision and strategy metrics/kpis\u000aexecutive incentive program (meeting vision and strategy metrics/kpis/goals)\u000aboard-level innovation education program',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1175,224,4,'Intelligent','All results of innovation are accepted as part of the innovation lifecycle; there are no punishments, official or unofficial, for a failed hypothesis','No history of disciplinary action, official or unofficial, towards failed innovation hypotheses',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1176,224,5,'Adaptive','All results of innovation are not only accepted as part of the innovation lifecycle, but are actively celebrated','Evidence of past innovation celebration\u000ano history of disciplinary action, official or unofficial, towards failed innovation hypotheses',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1177,225,1,'Ad Hoc','Feedback loop developed to capture data insights generated via innovation functions.  processes are designed for discovery of innovation ideas and solutions.','Innovation feedback loop\u000afeedback loop tooling (edison365, excel, pen & paper, etc.)\u000ainnovation function result insights',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1178,225,2,'Defined','Closed feedback loop is integrated into daily motions and recurring meetings, basic data insights are pursued and leveraged to help improve innovation function.  organization is using tooling to enhance innovation functions.','Recurring integration of insights in daily meetings\u000aclosed innovation feedback loop\u000afeedback loop tooling (edison365, excel, pen & paper, etc.)\u000ainnovation function result insights',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1179,225,3,'Integrated','Closed feedback loop is integrated into all relevant daily motions and recurring meetings, data insights are pursued and leveraged to improve innovation functions.  the closed feedback loop drives future execution of data insights.','Recurring integration of insights in daily meetings\u000aclosed innovation feedback loop\u000afeedback loop tooling (edison365, excel, pen & paper, etc.)\u000ainnovation function result insights execution',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1180,226,1,'Ad Hoc','Initial technology foundation to provide innovation services throughout the rest of the organization has been established by it, and there are plans to reach out to key stakeholders throughout the organization to offer it as a platform for innovation','It innovation services\u000ait innovation services communication and messaging strategy/pipeline\u000akey stakeholder messaging',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1181,226,2,'Defined','It has started to build key partnership throughout the organization and has documented plans in place to create innovative solutions','It innovation services\u000ait innovation services communication and messaging strategy/pipeline\u000akey partnerships (it to other areas)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1182,226,3,'Integrated','Innovation joint ventures between it and other departments are underway, with at least one active or past project','It to other area partnerships\u000ait to other area joint projects',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1183,226,4,'Intelligent','There is a track record of successful innovation partnership between it and other areas of the organization. there has been at least one successful joint venture in which it has partnered with another area of the organization to change an existing process or produce a new product or service.','Partnership success tracking\u000asuccessful project tracking\u000ait to other area partnerships\u000ait to other area joint projects',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1184,226,5,'Adaptive','Positioning it as an innovation partner is a c- suite level priority, and this is proven through an extensive track record of successful it innovation and partnerships throughout the organization.','Partnership success tracking\u000asuccessful project tracking\u000ac-suite incentive program\u000aits place within organizations (seen as a driving force of innovation)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1185,227,2,'Defined','Brand alignment is given at least some consideration when evaluating innovation activities','Marketing and innovation engagement\u000abasic measurements for innovation team\u000abasic measurements for marketing team',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1186,227,3,'Integrated','Marketing department, pr, or similar contacts within the organization are formally consulted to ensure innovation activities inform company branding efforts','Marketing plan\u000afacilitation plans\u000abrand message\u000abrand communication strategy',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1187,227,4,'Intelligent','Marketing works with innovation-focused teams to actively enhance the company image as that of an industry leader in innovation','Tight alignment between marketing and innovation teams\u000aideal image\u000abrand message\u000ashort and longer term objectives and goals',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1188,227,5,'Adaptive','Innovation is a part of the organization''s brand identity. the company "sells innovation" - they are known in the marketplace as a leader in selling innovative solutions','Innovative solutions\u000areal-time communication\u000astrong brand messaging processes\u000abrand-culture for all employees',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1189,228,3,'Integrated','Organization has initial framework for processes in place to initiate radical innovation and works with people to document and develop best practices.','Radical innovation framework\u000ainnovation best practices repository',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1190,228,4,'Intelligent','Organization has formalized processes in place to support radical innovation and actively finds way to improve upon support infrastructure.','Radical innovation framework\u000aradical innovation support processes (i.e. team structure, time commitment, etc.)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1191,228,5,'Adaptive','Organization has formalized processes in place to sustain radical innovation and consistently disrupts entire industry verticals through systematic innovation.','Radical innovation framework\u000aradical innovation support processes (i.e. team structure, time commitment, etc.)\u000aindustry disruption measurements',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1192,229,2,'Defined','Pockets of organization engaged in evaluating start-ups for investment','Investment program\u000aevaluation criteria for funding (roi/business case)\u000abudget and funding model\u000abasic start-up tracking dashboard is being developed',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1193,229,3,'Integrated','Multiple departments and engagements to evaluate start-up for investment','Investment program\u000aevaluation criteria for funding (roi/business case)\u000abudget and funding model\u000astartup tracking dashboard is in place',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1194,229,4,'Intelligent','Repeated funding established for investments in start-ups','Investment program\u000aevaluation criteria for funding (roi/business case)\u000abudget and funding model',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1195,229,5,'Adaptive','Enterprise investment program established at the appropriate levels (angel, series a, b, or c)','Investment program\u000aevaluation criteria for funding (roi/business case)\u000abudget and funding model',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1196,230,1,'Ad Hoc','Few select individuals involved in mentoring and/or judging at accelerators and/or incubators','{internal} mentor grooming & development program\u000aaccelerator/incubator events',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1197,230,2,'Defined','Few select individuals mentoring  internal to the company on innovation/start-up','Incubation mentorship program & budget\u000a{internal} mentor grooming & development program\u000abusiness outreach programs\u000amentor tracking processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1198,230,3,'Integrated','Defined program within the organization to engage in start-up community','Incubation mentorship program & budget\u000a{internal} mentor grooming & development program\u000abusiness outreach program\u000amentor tracking processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1199,230,4,'Intelligent','Multiple departments engaged in mentoring start-ups beyond just technology','Incubation mentorship program & budget\u000a{internal} mentor grooming & development program\u000abusiness outreach program\u000amentor tracking processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1200,230,5,'Adaptive','Enterprise focus on engaging start-ups learning and sharing learnings.','Incubation mentorship program & budget\u000a{internal} mentor grooming & development program\u000abusiness outreach program\u000amentor tracking processes\u000aknowledge sharing mechanisms\u000astart-up engagement tracking',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1201,231,4,'Intelligent','Investment/creation of an incubator that is managed by partner firm.  (example: capital innovators)','First-party incubator management\u000athird-party incubator management\u000astrategic partner relationships',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1202,231,5,'Adaptive','An innovation venture capital/ incubator/accelerator owned and managed by a division of the company.  (examples: t.rowe price innovation lab, capital one, coca-cola, verizon, amazon)','First-party incubator management\u000athird-party incubator management\u000astrategic partner relationships',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1203,232,3,'Integrated','A contract has been established with an entrepreneurial managed service that provides start-up access to companies and the company has selected a base membership allowing access to start-up demos and access to start-up community for limited exploration of new solutions.','Contractual relationship with startup managed service\u000aengagement in voting for start-up inclusion\u000aparticipation in demos creates increased understanding of ecosystem',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1204,232,4,'Intelligent','A contract has been established with an entrepreneurial managed service that provides start-up access to companies and the company has selected a moderate level of membership allowing voting rights to start-ups included, access to demos, and more defined opportunities for start-up engagement.','Contractual relationship with startup managed service\u000aactive engagement in voting for start-up inclusion\u000aactive participation in demos creates increased understanding of ecosystem\u000aleveraging engagement to build prototypes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1205,232,5,'Adaptive','A contract has been established with an entrepreneurial managed service that provides start-up access to companies and the company has selected the highest level of membership allowing voting rights to start-ups included, access to demos, and continuous opportunities for start-up engagement.','Contractual relationship with startup managed service\u000aactive engagement in voting for start-up inclusion\u000aactive participation in demos creates increased understanding of ecosystem\u000aleveraging engagement to build prototypes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1206,233,2,'Defined','Capture customer innovation ideas on ad hoc basis.','Customer tracking system:\u000a-how often customers ideas are captured',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1207,233,3,'Integrated','Customers have channels to provide direct feedback to the organization. the feedback is centrally tracked and built into future improvements, and formally addressed by employee incentive programs from management','Type of capture mechanism used (dropbox, sharepoint, emails, etc.)\u000acentralized platform (word doc, edison365, whiteboard, etc.)\u000acustomer tracking system:\u000a-how often customers ideas are captured',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1208,233,4,'Intelligent','Customer obsession is a core value of the organization. there is a dedicated team focused on customer service and customer retention, and they regularly meet kpis and reach goals set by upper management. customers are actively surveyed and consulted for potential future improvements and are a part of the ideation process. there is evidence of customer ideas consistently being included in solutions','Quantity of ideas produced\u000aquantity of ideas captured\u000atype of capture mechanism used (dropbox, sharepoint, emails, etc.)\u000acentralized platform (word doc, edison365, whiteboard, etc.)\u000acustomer tracking system:\u000a-how often customer provides ideas\u000a-how often customers ideas are captured',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1209,233,5,'Adaptive','Work with customers to capture innovation ideas, continuously seek customer input for ideas and input them in centralized database, actively encourage customers to partner to innovate together.','Quantity of ideas produced\u000aquantity of ideas captured\u000aquantity of ideas captured during discovery that progress to incubation\u000aquantity of ideas captured during discovery that progress to acceleration\u000atype of capture mechanism used (dropbox, sharepoint, emails, etc.)\u000acentralized platform (word doc, edison365, whiteboard, etc.)\u000acustomer tracking system:\u000a-how often customer provides ideas\u000a-how often customers ideas are captured\u000a-how often customers ideas are incubated\u000a-how often customers ideas are accelerated',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1210,234,1,'Ad Hoc','Ad hoc idea capture (i.e. the occasional manager captures an idea)','Quantity of ideas captured',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1211,234,2,'Defined','Basic idea capture structure developed and used consisting of processes such as drop boxes, polls, lunch and share, etc.','Quantity of ideas produced (metric)\u000aquantity of ideas captured (metric)\u000atype of capture mechanism used (dropbox, sharepoint, emails, etc.)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1212,234,3,'Integrated','Centralized idea capturing tool selected and localized teams share ideas on recurring basis','Quantity of ideas produced (metric)\u000aquantity of ideas captured (metric)\u000atype of capture mechanism used (dropbox, sharepoint, emails, etc.)\u000acentralized platform (word doc, edison365, whiteboard, etc.)\u000aidea capture metrics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1213,234,4,'Intelligent','Formalized idea capture (ideation) process put in place across organization, centralized sharing and storage tools for ideas is in place, and leadership sponsors idea capture challenges and events occasionally.','Quantity of ideas produced (metric)\u000aquantity of ideas captured (metric)\u000aquantity of ideas captured during discovery that progress to incubation\u000aquantity of ideas captured during discovery that progress to acceleration\u000atype of capture mechanism used (dropbox, sharepoint, emails, etc.)\u000acentralized platform (word doc, edison365, whiteboard, etc.)\u000aidea capture events\u000aidea capture sponsorship (leadership)\u000aidea capture metrics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1214,234,5,'Adaptive','Centralized idea capturing and tracking system leveraged to spread awareness of ideas and use.  people capture ideas on a recurring basis and frequently collaborate across organization on idea discovery.','Quantity of ideas produced (metric)\u000aquantity of ideas captured (metric)\u000aquantity of ideas captured during discovery that progress to incubation\u000aquantity of ideas captured during discovery that progress to acceleration\u000atype of capture mechanism used (dropbox, sharepoint, emails, etc.)\u000acentralized platform (word doc, edison365, whiteboard, etc.)\u000aidea awareness metrics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1215,235,2,'Defined','Develop evaluation criteria for ideas generated at company on an ad hoc basis.','Company has criteria for selection of ideas to incubate',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1216,235,3,'Integrated','Develop formalized evaluation criteria for ideas and educate all employees on process.  run recurring monthly evaluation sessions (i.e. lunch and pitch, pitch competitions, etc.)','Company has criteria for selection of ideas to incubate\u000aselected ideas tracking mechanisms\u000arecurring evaluation sessions\u000ainternal company policy for taking an idea and running with it\u000aeducation initiatives',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1217,235,4,'Intelligent','Develop formalized incubation strategies, select limited ideas to incubate on ad hoc basis based on needs of organization now.','Quantity of ideas captured during discovery that progress to incubation\u000aselected ideas tracking mechanisms\u000acompany has criteria for selection of ideas to incubate\u000ainternal company policy for taking an idea and running with it\u000aquantity of successful ideas that moved through incubation\u000acapacity for incubation:\u000a-funding\u000a-human resources and skills\u000a-time available for idea incubation\u000a-organization commitment to see idea through incubation (including when it might be failed)\u000a-defined processes for incubation process\u000a-metric tracking and knowledge storage/sharing processes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1218,235,5,'Adaptive','Have process in place to fully evaluate all ideas gathered in company, have selection criteria for potential ideas to build upon, leverage internal resources to take an idea from idea to minimum viable product, develop formalized processes to incubate ideas, and have recurring cycle of evaluation.','Quantity of ideas captured during discovery that progress to incubation\u000acompany has criteria for selection of ideas to incubate\u000ainternal company policy for taking an idea and running with it\u000aquantity of successful ideas that moved through incubation\u000acapacity for incubation:\u000a-funding\u000a-human resources and skills\u000a-time available for idea incubation\u000a-organization commitment to see idea through incubation (including when it might be failed)\u000a-defined processes for incubation process\u000a-metric tracking and knowledge storage/sharing processes\u000arecurring review cycles of results of incubation process and continuous improvement',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1219,236,1,'Ad Hoc','Small group of people run an impromptu hackathon that is limited to a team with no purpose to results.','Budget (event + prizes)\u000amarketing & communications plan\u000aweb site and social media integration\u000ahackathon host/csp',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1220,236,2,'Defined','A formalized team hackathon or other ideation process intended to solve a problem (related or unrelated to work) is executed.  results from the hackathon or other ideation process are sometimes pursued internally.','Budget (event + prizes)\u000amarketing & communications plan\u000aweb site and social media integration\u000ahackathon host/csp\u000acollaboration & planning tools (includes idea-tracking)\u000ahackathon playbook and runbook',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1221,236,3,'Integrated','A formalized company hackathon or other ideation process intended to solve company problems and spur innovation is executed.  results from the hackathon or other ideation process are pursued internally.','Budget (event + prizes)\u000amarketing & communications plan\u000aweb site and social media integration\u000ahackathon host/csp\u000acollaboration & planning tools (includes idea-tracking)\u000ahackathon playbook and runbook\u000asecurity support ... with a focus on these items:\u000a--network access\u000a--conditional access model for participants and collaborators\u000a--support for third-party identities and federation\u000a--intellectual property protection\u000a--data leakage prevention',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1222,236,4,'Intelligent','A company hackathon or other ideation process that is executed and invites external people to join (participants, observers, judges, etc.), the problems are related to innovation in industry or company, and from time to time the results of the hackathon or other ideation process are pursued to mvp.','Budget (event + prizes)\u000amarketing & communications plan\u000aweb site and social media integration\u000ahackathon host/csp\u000acollaboration & planning tools (includes idea-tracking)\u000ahackathon playbook and runbook\u000aparticipant tracking\u000asecurity support ... with a focus on these items:\u000a--network access\u000a--conditional access model for participants and collaborators\u000a--support for third-party identities and federation\u000a--intellectual property protection\u000a--data leakage prevention',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1223,236,5,'Adaptive','Company hackathon or other ideation process is known across industry with significant active participants, the problems selected help drive either innovation in industry or company, and results of hackathon or other ideation process are always pursued.','Budget (event + prizes)\u000amarketing & communications plan\u000aweb site and social media integration\u000ahackathon host/csp\u000acollaboration & planning tools (includes idea-tracking)\u000ahackathon playbook and runbook\u000aparticipant tracking\u000asecurity support ... with a focus on these items:\u000a--network access\u000a--conditional access model for participants and collaborators\u000a--support for third-party identities and federation\u000a--intellectual property protection\u000a--data leakage prevention',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1224,237,3,'Integrated','Select a few incubated ideas to accelerate on an ad hoc basis.','Quantity of ideas incubated that progress to acceleration\u000aacceleration selection process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1225,237,4,'Intelligent','Select incubated ideas based on selection framework to be accelerated and a standard acceleration framework is implemented.','Quantity of ideas incubated that progress to acceleration\u000aacceleration selection framework\u000aacceleration framework\u000acapacity for acceleration:\u000a-funding\u000a-human resources and skills\u000a-time available for idea acceleration\u000a-organization commitment to see idea through incubation (including when it might be failed)\u000a-defined processes for incubation process\u000a-metric tracking and knowledge storage/sharing processes\u000a-standardized mvp requirements and specific-to-idea mvp requirements outlined and tracked\u000a-formalized organizational initiative defined\u000a-ad hoc selection / selection framework / automatic selection framework',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1226,237,5,'Adaptive','Significantly drive selected ideas based on framework to accelerate to finished product.  incubated ideas are reviewed continuously and innovation resources are prioritized on par with core business lines.','Quantity of ideas incubated that progress to acceleration\u000aacceleration selection framework\u000aacceleration framework\u000acontinuous review process for incubated/accelerated ideas\u000aacceleration-to-business lines alignment\u000acapacity for acceleration:\u000a-funding\u000a-human resources and skills\u000a-time available for idea acceleration\u000a-organization commitment to see idea through incubation (including when it might be failed)\u000a-defined processes for incubation process\u000a-metric tracking and knowledge storage/sharing processes\u000a-standardized mvp requirements and specific-to-idea mvp requirements outlined and tracked\u000a-formalized organizational initiative defined\u000a-ad hoc selection / selection framework / automatic selection framework',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1227,238,1,'Ad Hoc','Agile/scaled agile framework (safe) training established with in pockets of the organization and is leveraging the concept of innovation at ip iterations.','Safe trainings\u000asafe implementation (on team level)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1228,238,2,'Defined','Agile /safe being expanded to multiple teams with pi planning including shared services and is leveraging the concept of innovation at ip iterations.','Safe implementation on teams',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1229,238,3,'Integrated','Enterprise roles defined, multiple agile release trains implemented. innovation sprints'' learnings shared across areas.','Enterprise roles definitions\u000aagile release trains\u000aoutcomes of innovation sprints\u000acentralized storage and sharing systems for lessons learned',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1230,238,4,'Intelligent','Majority of value streams defined, portfolio being defined, number of safe certified roles (release train engineer, advanced scrum master, safe po''s, and safe scrum masters). learnings from innovation sprints are adopted and implemented.','Value streams definitions\u000aportfolio definition\u000asafe certified tracking\u000asafe certifications\u000alessons learned training for innovation sprints',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1231,238,5,'Adaptive','Enterprise value streams defined, portfolio backlogs with lean budgets and enterprise strategic themes. innovation sprints outcomes are reported at the value stream level and impact the portfolio.','Enterprise value stream definitions\u000aportfolio backlogs\u000alean budgets defined (portfolio backlog specific)\u000ainnovation sprint outcome reporting',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1232,239,1,'Ad Hoc','Initial: tightly coupled (or monolithic) applications which are potentially managed via manual/foundational processes. due to their current architecture, significant work is required to decouple and rebuild to gain the cloud benefits. additionally, development processes are not well defined, services levels may not be measured consistently, and satisfaction levels may not be formalized.','Application architectural standards are informal\u000areference architecture is understood to be needed\u000aupdated permit-todesign, build, and operate standards/policies\u000adesign patterns are somewhat in use\u000asegmentation with some service architecture\u000areference architecture\u000acontainerization is limited',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1233,239,2,'Defined','Managed: development is planned, measured and controlled with specific separation of environment layers. there is greater degree of independence between application capabilities. services are measured and communicated in a formal manner.','Application architectural standards are documented\u000areference architecture are starting to be developed\u000aupdated permit-todesign, build, and operate standards/policies\u000adesign patterns are capabilities are growing \u000aservice architecture is defined but manual\u000areference architecture\u000acontainerization is somewhat in use',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1234,239,3,'Integrated','Defined: organization standards that provides for loosely coupled applications. standards are adhered to with defined exceptions. components are loosely coupled allowing for resiliency and scaling based on component needs.','Application architectural standards are reviewed and current\u000areference architecture is developed and deployed\u000aupdated permit-todesign, build, and operate standards/policies\u000adesign patterns are part of new development design enterprise wide\u000aextensive service architecture is in place \u000areference architecture\u000acontainerization is mature',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1235,239,4,'Intelligent','Quantitative: managed and controlled development with microservices and containerization. re-use of components is evident throughout the environment.','Application architectural standards compliance is automated\u000areference architecture is comprehensive \u000aupdated permit-todesign, build, and operate standards/policies\u000adesign patterns are reviewed periodically\u000aservice mesh is integrated into ci/cd pipeline\u000areference architecture\u000acontainerization is abstracted through orchestration',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1236,239,5,'Adaptive','Optimizing: loosely coupled and orchestrated which is highly optimized with continuous improvement','Application architectural standards are flexible configurations\u000areference architecture is flexible\u000aupdated permit-todesign, build, and operate standards/policies\u000adesign pattern thought leadership \u000ainnovation in the service mesh space\u000areference architecture\u000acontainerization is advanced',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1237,240,1,'Ad Hoc','Customer facing applications (voice and web) are designed with design thinking /customer-centric. these include all interactions including security protocols for forgotten passwords, or security protocols for account authentication as examples. each customer touch point provides an opportunity to put the customer needs first balancing ease of use with security and privacy.','Design thinking process & tooling',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1238,240,2,'Defined','Customer facing applications with evidence of persona focus design and customer journey maps','Persona definition process & tooling',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1239,240,3,'Integrated','Customer facing applications based on customer empathy with hypothesis measurements in place','Hypothesis testing is in place and metrics are tracked to validate outcomes',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1240,240,4,'Intelligent','Product development within the firm leverages design thinking, customer journey maps, and empathy. additionally, evidence of hypothesis that did not meet the initial expectations and are considered to have a "failed fast"','Fail fast examples are celebrated \u000acustomer journey maps are created',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1241,240,5,'Adaptive','Entire enterprise is focused on customer centric approach with evidence of hypothesis testing with clients and pivoting based on hypothesis validation','Pivot between hypothesis testing is evident',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1242,241,1,'Ad Hoc','Silo based, manual processes, manual builds and deploys','Heroism \u000afire drills are a norm',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1243,241,2,'Defined','Managed communications, processes within silos, automated builds','Reduced fire-drills / ado solutioning\u000alow frequency of continuous improvement practices.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1244,241,3,'Integrated','Collaboration exists, process are automated across sdlc, automated build and test cycle, push button deployment','Regular cadence established for improvement practices.\u000adocumented devops processes.\u000areduced occurrence of fire drill incidents.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1245,241,4,'Intelligent','Shared metrics and optimization focus, proactive monitoring, transparent metrics, auto roll-backs','Regular cadence established for improvement practices.\u000aincentives for organizational impact.\u000afire drills rarely occur.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1246,241,5,'Adaptive','Culture of continuous improvement, self-service automation, zero downtime deployments, immutable infrastructure.','Strategic importance to devops practices/culture.\u000acultivation and practice for high impact improvement ideas. \u000ahigh frequency of communication of improvement strategies and backlog.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1247,242,1,'Ad Hoc','Infrastructure is deployed manually with long completion lead times due to multiple hand offs between siloed infrastructure teams. few teams use automation tools on an ad hoc basis. varying tools used with limited sharing between teams.','Existence of multiple source code repositories, configuration management and orchestration engines. \u000anonstandard cloud templates are being used, templates are also static and rarely portable. \u000aorchestration engines being used inconsistently across the organization. \u000aminimal use of binary repositories. \u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1248,242,2,'Defined','Standards defined: standards are established for core infrastructure patterns and the deployment process is clearly outlined. most teams use basic automation routinely.  varying tools used with some sharing between teams. standards for infrastructure-as-code, automation tooling and deployment are identified.','Some apps / infrastructure deployments are leveraging pipelines that are integrated with source code and binary repos. \u000astandards around templates have emerged. \u000aautomation orchestration is focused on integration with a single cloud platform. \u000aautomation tools are configured to support multi region deployments. \u000amanual testing is done post deployment. \u000amajority of deployments are focused on pre-production environments.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1249,242,3,'Integrated','Repeatable: organization leverages an automation framework to deploy standardized infrastructure.    the organization has a standardized and complete set of tools and processes to cover all infrastructure needs. tooling to support application development and deployment decided and developed. standardized infrastructure templates developed and in use to deploy infrastructure.','Automation deployments can be deployed on-demand via a self-service portal that is integrated with automation tools. \u000arole based access is leveraged to provide secure access to shared framework portals. \u000ateams are leveraging modular pipelines that break various deployment tasks into stages. \u000ateams are regularly using automation to deploy to production environments. \u000ateams can deploy similar app / infrastructure patterns to at least two cloud platforms (csp). some static testing is done via automation pre deployment.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1250,242,4,'Intelligent','Managed: infrastructure can be requested and deployed via a self-service portal. account / subscription creation is self-service based. the organization has a comprehensive tooling framework covering infrastructure and application needs. template repository is developed and shared by all teams.','Automated deployments support event-based triggers such has code commits and scheduled deployments. \u000ateams can deploy similar app / infrastructure patterns to at least three cloud platforms (csp). \u000aall deployments undergo automated static code testing pre deployment. \u000asome dynamic testing is done via automation post deployment. \u000asome teams are leveraging sophisticated pipeline usage via successful pre-prod deployment testing to chain production deployments.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1251,242,5,'Adaptive','Optimized: automation includes sophisticated guardrails that use event-based remediation of deployment violations and alerting. the organization has a comprehensive automation tooling framework covering all infrastructure needs and testing needs. template library is developed and maintained by all teams. leadership evaluates the value provided by framework and recommends updates/changes as the needs of the business change.','Framework supports completely touch free automation requiring zero manual steps for > 90 of deployments. \u000adynamic testing is supported for > 90 of all deployment components and supports real time event-based remediation. \u000aautomation platform is deployed in multiple regions and supports regional failure.',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1252,243,1,'Ad Hoc','There are occasionally specific times set aside for innovation activities for certain employees.','Dedicated employee time',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1253,243,2,'Defined','There is regularly time set aside for innovation activities for certain employees.','Dedicated employee time',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1254,243,3,'Integrated','There is a regular cadence in place for setting time aside for innovation activities, and most employees are able to participate.','Dedicated employee time',NULL,1);
