INSERT INTO Next_CapabilityLevel VALUES(1256,243,5,'Adaptive','Setting time aside for innovation is an executive priority; there are certain groups in the organization who focus full-time on innovation and majority of employees regularly take part in widespread innovation activities on a regular cadence.','Employee awareness tracking\u000adedicated employee time\u000ainnovation-specific jobs (focus of employee)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1257,244,1,'Ad Hoc','A few innovation titles exist on an ad hoc basis as people pursue being an ''innovation champion''.','Innovation titles\u000ainnovation champions',NULL,1);
