INSERT INTO Next_CapabilityLevel VALUES(1260,244,4,'Intelligent','Majority of the organization leverages new innovation-related title structure and change operations to align with new structure.  top level management still operates in traditional manner and is not fully aligned.','Innovation title structure\u000ainnovation roles & requirements',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1261,244,5,'Adaptive','The entire organization leverages a single innovation-related title structure and fully embraces all changes.','Innovation title structure\u000ainnovation roles & requirements',NULL,1);
