INSERT INTO Next_CapabilityLevel VALUES(1270,246,4,'Intelligent','Most business units have a specific innovation budget and the freedom to use it as deemed fit. the budget is large enough to cover most innovation needs.','Innovation activities funding\u000ainnovation funding process\u000abusiness unit innovation funding budgets',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1271,246,5,'Adaptive','There are executive-level initiatives that involve funding innovation, including required innovation hires, funding of incubators, and startup m&a activity.','Innovation activities funding\u000ainnovation funding process\u000aexecutive level initiatives\u000ainvesting/incubators/accelerators/m&a',NULL,1);
