INSERT INTO Next_CapabilityLevel VALUES(1276,247,5,'Adaptive','Innovation metrics are a board-level priority and are measured against for executive performance','Metrics & kpis\u000ainnovation progress tracking\u000ametric-based innovation compensation (executive level)',NULL,1);
