INSERT INTO Next_CapabilityLevel VALUES(1279,248,5,'Adaptive','Centralized r&d group overseas robust and wide spread innovation projects across organization and leverages standardized/defined processes and systems to ensure funding and completion of each project.','R&d organization/business unit',NULL,1);
