INSERT INTO Next_CapabilityLevel VALUES(1282,249,3,'Integrated','The organization has a well-funded training program with long-term third-party partnerships and encourages employees to attend innovation-related events. training activities and certifications are tracked by business units.','Innovation-related training education funds\u000a3rd party partnerships (training partners)\u000aevent/conference attendance\u000acertification tracking\u000acertification education and learned',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1283,249,4,'Intelligent','Innovation enablement via training is widespread in the organization. there are robust training resources, and training goals are formally incentivized by management. certifications are centrally tracked and celebrated within bu''s','Innovation enablement training\u000atraining goal incentives\u000acertification tracking\u000acertification celebration activities\u000atraining resources',NULL,1);
