INSERT INTO Next_CapabilityLevel VALUES(1285,250,1,'Ad Hoc','Pass/fail application sampling.  application logs are collected.','Simple application monitoring ping or http response\u000aapplication logs are collected but there are no events or triggers\u000aapplication failure investigation is after the fact',NULL,1);
