INSERT INTO Next_CapabilityLevel VALUES(1287,250,3,'Integrated','Centralized application log processing.  metrics are defined allowing comprehensive application health determination.','Enterprise has centralized logging tool e.g. sumo logic allowing a single pain of glass for real time status of the entire application portfolio',NULL,1);
