INSERT INTO Next_CapabilityLevel VALUES(1291,251,2,'Defined','Third party applications are patched for major revision updates','Ensure compliance, risk, and vulnerability concerns are addressed by the patching process\u000ause a tool or process to define patch management and provide reporting on patch status',NULL,1);
