INSERT INTO Next_CapabilityLevel VALUES(1305,35,3,'Integrated','Defined processes and devops culture leads to support events  to be automatically captured and scripts are developed for event remediation','Runbooks, architecture diagrams, and scripts are documented and accessible\u000athe support team tracks and publishes metrics',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1306,140,3,'Integrated','Defined processes and devops culture leads to support events  to be automatically captured and scripts are developed for event remediation','Runbooks, architecture diagrams, and scripts are documented and accessible\u000athe support team tracks and publishes metrics',NULL,1);
