INSERT INTO Next_CapabilityLevel VALUES(1308,35,4,'Intelligent','Application resilience is imbedded in design of application. production support is measured.','Support is integrated in the sdlc process. reporting is available and feedback is part of the process\u000areporting dashboard\u000asupport kpis\u000aautomation roadmap',NULL,1);
