INSERT INTO Next_CapabilityLevel VALUES(1311,35,5,'Adaptive','Leveraging automation and embedded sre,  application resilience is tested spontaneously in production to validate resilience (e.g. chaos monkey)','Support is fully integrated into the design lifecycle of all applications and workloads',NULL,1);
