INSERT INTO Next_CapabilityLevel VALUES(1314,254,1,'Ad Hoc','Organization has implemented and enforces a policy to utilize source control management for all code.','Source control is being used ad-hoc by individual teams or projects as needed\u000atrunk-based development\u000adifficult to correlate point-in-time commit to deployed code in an environment',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1315,254,2,'Defined','Organization enforces standardized tooling and workflow for all source code management systems.','Federated source controls processes\u000aenforced checkout and checking procedures across all environments\u000adevelopers commit their own changes only\u000aversion control is fully implemented across all projects and teams\u000adetailed notes are required at each commit\u000a\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1316,254,3,'Integrated','The organization has fully enabled multi-developer source controls practices with transparency throughout the lifecycle.','Branches are leveraged to enable multiple developers to work in parallel\u000acommits are reversible\u000astandardize source control management workflow processes are defined\u000acode reviews happen before integration into trunk on a per-team basis\u000adependencies are integrated\u000aimmutable history of all changes \u000asecrets are externalized',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1317,254,4,'Intelligent','The organization has automated quality control integrated into source control with clear promotion paths supporting multiple versions.','Source control is integrated into code quality automation\u000alabeling/tagging is required \u000aa commit often culture is established\u000arbac is well-defined for source control\u000aconfiguration is externalized\u000abranching best practices are optimized and provide a clear promotion path for changes and support multiple versions of release software\u000acode review process is defined and followed for the entire organization',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1318,254,5,'Adaptive','The organization has source control fully integrated into devsecops with atomic commits being common practice.','Atomic commits are common practice focusing on one contextual change\u000asource control is built into all lifecycle management practices\u000ausage of immutable tags are in place \u000asource control system is fully integrated into the devsecops practices\u000astaging areas are utilized to review deployed changes prior to integration',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1319,255,1,'Ad Hoc','Availability requirements are documented for applications allowing business units to manage expectations. cost for resiliency is utilized and documented for each application.','Sla and slos defined \u000adefined business continuity requirements \u000arto and rpos defined for cloud dependent services\u000a mtbf, mttr are defined see (failure mode analysis capability)\u000aroi process to determine availability approach \u000arepository or documentation approach for application availability requirements \u000aservice failure analysis process \u000aavailability management process owner\u000adocumented availably management targets \u000acapacity plan documented for proactive availability plan\u000a availability management strategies (and the start of contingency plans)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1320,255,2,'Defined','Business units approve all aspects of resiliency which are reconciled and validated on a periodic basis. service tiers are codified (cmdb) to automate.  service attainment is reported consistently and continually.','Availability approval process\u000adashboards inclusive of availability management\u000aavailability requirement reconciliation process\u000acmdb with availability tiers included\u000aagreement review process\u000adesigning availability metrics and reports\u000aavailability management policy\u000aavailability monitoring process defined\u000aavailability dashboard being used internally\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1321,255,3,'Integrated','Business units approve all aspects of performance including system and new functionality delivery which is in turn directly linked to customer requirements and expectations.','Documented applications and services performance expectation\u000adocumented new functionality delivery goals\u000acontinuous availability option\u000anew csp feature review process \u000adocumented vital business functions\u000adocumented impacts of service loss or degradation\u000aformal risk modeling process \u000aprojected services outage document\u000aavailability reports are well defined and provided frequently\u000aavailability trends are documented \u000aavailability review process is defined\u000aavailability improvement plans are defined as needed',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1322,255,4,'Intelligent','It and business units are aligned via shared goals regarding technology availability including traditional measures (sla,slo,rto,rpo) as well as application performance and business unit support. ultimate measure of unity is common compensation regarding business outcomes.','Defined business outcomes \u000ashared goals between business unit and it\u000amulti-faceted slas \u000aavailability management information system \u000aavailability dashboard being used internally and externally\u000a availability improvement strategies\u000aavailability management information system (amis is a subset of cms)\u000aavailability forecasts are documented',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1323,256,1,'Ad Hoc','Enterprise backup strategy and tools extended to cloud estate; cloud native backup and snapshot solutions leveraged for non-production services and data needs; legacy data protection and retention strategies extended to cloud; backups are validated against policy expectations.','Documented rto and rpo for all systems and data\u000adocumented backup and data retention strategy\u000acloud backups and snapshots\u000abackups are tested manually',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1324,256,2,'Defined','Cloud native backup strategies leveraged to augment enterprise backup strategy; data protection and retention strategies begin to be adapted for cloud based workload. backup processes often siloed by estate location; data archival strategy begins to shift to cloud. data (or application) tier framework exists to standardize and automate backups and snapshots via policy','Cloud backups span availability zones\u000acloud snapshots span availability zones and regions\u000aon premise to cloud backups exist\u000aapplication availability tiering framework \u000atiers are codified likely in cmdb \u000abackups are tested automatically \u000acloud native backups',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1325,256,3,'Integrated','Hybrid backup strategy refined based on data retention and tiering; best of breed model leveraged across enterprise; multi-site data copies replaces tradition backup for selected data tiers. segregated backups exist (or are configured via worm encryption) to protect against ransomware.','Certain backups are segregated or encrypted via (worm) \u000abackups and snapshots stored in different azs\u000aintegrated hybrid backups\u000aautomated backup up validation and testing process\u000aprocesses to back up on premise to cloud\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1326,256,4,'Intelligent','Select on-prem apps and workloads are backed up to the public cloud','Same as above but deeper implementations',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1327,256,5,'Adaptive','Select cloud apps and workloads are backed up from one public cloud to another (multi-cloud)','Multi-cloud strategy for backup segregation',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1328,257,1,'Ad Hoc','Disaster recovery management guided by legacy approach. cloud leveraged to provide dr capabilities to legacy environments. rto/rpo defined but inconsistently tested for applications and services across hybrid estate; cloud pilot light scenarios predominant.','Disaster recovery plan\u000aground to cloud failover pattern\u000adr monitoring and alerting\u000abcp requirements\u000adr testing \u000artos and rpos defined',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1329,257,2,'Defined','Disaster recovery management beginning to leverage cloud native architectures to drive rto/rpos. dr testing consistent across hybrid estate; some applications fail/failback across cloud perimeter; hybrid dr patterns begin to emerge; data (or application) rto/rpos are tied directly to availability framework reconciled with business continuity tiers.','Cloud native dr automation \u000aregion failover capabilities\u000abcp planning for cloud services\u000adr testing program\u000adr patterns for hybrid cloud \u000adr patterns for multi-cloud \u000adr playbooks \u000acmdb',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1330,257,3,'Integrated','Disaster recovery management supports hybrid, multi-region failure modes which meet rto/rpos for critical workloads; production workloads do not require failback; cloud native dr model beginning to impact application design','Multi-region failover\u000ahybrid cloud dr testing \u000acloud native dr automation \u000afailback processes developed\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1331,257,4,'Intelligent','Disaster recovery management supports hybrid, multi-cloud failure modes which meet rto/rpos. cloud native dr model drives application design','Multi-cloud failover\u000asite recovery engineering\u000achaos engineering program\u000acomponent dr testing',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1332,257,5,'Adaptive','Hybrid, multi-cloud disaster recovery model support enterprise wide, global business continuity','Fully automated dr platform\u000achaos monkey testing',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1333,258,1,'Ad Hoc','The organization establishes service continuity strategy & policy to reduce the business and operational impact during/after an it service incident.','Service continuity strategy\u000a_service continuity policy\u000a_service continuity standards\u000a_service continuity plan\u000a_service continuity guidelines\u000a_service continuity requirements\u000a_business impact assessment (bia)\u000a_service continuity tiers defined\u000a_service continuity communication plan\u000a_executive leadership support \u000aservice continuity defined rto and rpos\u000abusiness continuity plan integration process\u000amonitoring tools, emergency conferencing tools, incident management tools',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1334,258,2,'Defined','Service continuity leverages a tiered approach to disruption and risk, with detailed integration of business unit objectives and priorities.','Service continuity tiers implemented \u000a_technical impact assessment (tia) aligned with dr \u000a_business impact assessment (bia) aligned with dr\u000a_service continuity tabletop testing\u000a_service continuity refresh schedule\u000a_service continuity communication plan\u000a_regulatory compliance\u000a_internal call tree matrix\u000a_metrics & kpis\u000a_business unit objectives\u000a_business unit process & procedures\u000a_service continuity business unit review schedule\u000a_service continuity tooling\u000avirtual business functions documented \u000ainterdependencies between vbf and service components documented\u000aservice continuity requirements documented \u000arisk assessment process\u000atesting results documented\u000aknowledge management tools\u000abusiness continuity planning tools analytical tools, risk assessment tools, incident management tools',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1335,258,3,'Integrated','The organization develops and sustains service continuity readiness by leveraging scheduled exercises and a comprehensive feedback loop. critical integrations are established with critical functions such as: business continuity, crisis mgmt., disaster recovery, incident response, and grc.','Service continuity process & procedure\u000a_service continuity plan currency executive report\u000a_impact assessment schedule\u000a_escalation process \u000a_external call tree matrix\u000a_communication and legal process for external communication development\u000a_service continuity exercises\u000a_service continuity exercise schedule\u000a_service continuity testing\u000a_service continuity communication strategy (refined)\u000a_alignment to crisis management, availability management, dr, ir, and physical security\u000a_feedback loop\u000a_service continuity business unit review schedule\u000a_service continuity tooling and grc alignment\u000a_service continuity staff certified\u000aservice continuity integration processes \u000aservice continuity mapping \u000aservice continuity auditing process',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1336,258,4,'Intelligent','The organization establishes a comprehensive approach to service  continuity that incorporates a shared responsibility model across first- and third-parties. dashboards and reports are available to communicate status and results to interested/obligated stakeholders.','External call tree matrix (audit process)\u000a_service continuity playbook\u000a_service continuity runbook\u000a_integration with disaster recovery\u000a_integration with risk mgmt. (which notably includes risk assessment)\u000a_shared responsibility model\u000a_dashboards & reporting\u000a',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1337,258,5,'Adaptive','Service continuity is tailored to geography and geo-political variables.','\u000a_continuous improvement\u000a_external service continuity testing engagements \u000a_service continuity staff leading local coes / guilds\u000a_alignment with related government crisis management\u000a_service continuity capabilities aligned with geopolitical requirements (i.e.. responses may be different by country)',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1338,259,1,'Ad Hoc','Service availability based on provider slas / slos. minimal foundational services defined in internal cloud services catalog. \u000a\u000aon premises availability requirements are defined for tier 1 production workloads and used to inform  resiliency objectives. details for availability requirements for lower tier and non-production workloads inconsistent. on-premises architectural assumptions are prevalent in availability design.','External sla/slo\u000abusiness availability requirements\u000abusiness impact analysis\u000aresiliency objectives\u000aperformance objectives\u000acsp objectives \u000aapplication requirements \u000asla communication and enablement\u000aslas include hours of service availability.\u000aslas include hours of support coverage.\u000aslas include support response.\u000aslas include service restoration times.\u000aslas include service availability goals.\u000aslas include security requirements.\u000aslas include a procedure for negotiating temporary changes to service levels\u000aservice level agreements (slas) specifying the agreed-upon service levels\u000aservice level requirements (slrs) defining the expected service levels\u000aservice level objectives (slos) setting measurable goals for service performance',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1339,259,2,'Defined','Service level agreements, service level objectives and service indicators defined for all deployed and pipeline services. site reliability engineering foundations defined for cloud estate. availability testing has started.\u000a\u000aworkloads/services are grouped and prioritized based on resiliency requirements and externalized in a consumable framework. availability requirements are defined for initial, first mover cloud workloads and foundational cloud services. business impact analysis work begins to include both legacy and cloud native availability design models.','Internal sla/slo\u000acloud service catalog\u000aperformance baselines\u000aservice onboarding\u000aservice level indicators\u000aavailability testing\u000aslas include specification of data backup and restoration.\u000aslas include agreed workload, throughput and scalability requirements.\u000aslas include contingency arrangements.\u000aslas include costs, charges and penalties, as appropriate.\u000aslas, or other formal documentation, include a description of the service.\u000aslas include escalation process and triggers \u000aservice level reports showing performance against slas\u000aservice level reviews assessing and improving service performance\u000aservice level targets identifying performance goals for the next period\u000aservice level metrics to track and monitor service performance',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1340,259,3,'Integrated','Applications, workloads and cloud services have availability requirements defined for every level of the stack. requirements are incorporated into application design and deployment models for the cloud portfolio. infra availability requirements distinguish between cloud and non-cloud environments.   requirements for cloud based applications/service begin to include multiple geographies','Site reliability engineering (availability driven service design)\u000ageographic diversity\u000aself-healing \u000aresilient shared services \u000aservice level dashboards providing real-time performance data\u000aservice level trends and forecasts predicting future performance\u000aservice level improvement plans setting out actions to improve service levels',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1341,259,4,'Intelligent','Availability requirements are incorporated into fully automated, self-healing, cost optimized full stack application deployments; availability requirements no longer distinguish between cloud vs non-cloud','Self-healing\u000acomplex global requirements\u000aservice level alerts to inform stakeholders of changes in service performance (pro active, automated)\u000aservice level escalation procedures to ensure timely resolution of service issues',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1342,259,5,'Adaptive','Availability requirements are used to help drive product and service innovation','Availability as a product feature\u000aservice level automation to improve service delivery and performance\u000aservice level benchmarking to compare performance against industry standards\u000aservice level predictability to forecast future service performance trends',NULL,1);
