INSERT INTO Next_CapabilityLevel VALUES(1344,260,1,'Ad Hoc','Source control and artifact repositories are used but different tools are scattered throughout the organization.  iac and application source control are segregated.  branching and merging strategy is immature.  build and deploy processes are largely manual with little alerting.  little to no rollback/dr strategy is defined. there are infrequent releases with limited ci/cd.','Documentation exists\u000adevops culture is understood and implementation plan is formulated\u000aautomated testing candidates are identified\u000alogging and monitoring in place with manual remediation\u000aci/cd workflow standardization\u000aworkflow processes documented and shared\u000aci/cd standards documented and shared\u000aintegration with other management tools\u000aci/cd penetration/coverage across app portfolio\u000abranching strategy documented and shared',NULL,1);
