INSERT INTO Next_CapabilityLevel VALUES(1347,187,3,'Integrated','Application and infrastructure pipelines are integrated.  ci/cd pipelines are used in production workloads.  centralized logging enables enhanced monitoring and alerting. automated testing is in place.','Documentation exists\u000adevops culture is adopted\u000aautomated testing is part of the pipeline\u000acentralized logging and monitoring in place with manual remediation and meets compliance standards\u000asource and artifact repositories are in use\u000abranching and merging strategy is in use\u000arollback/dr is integrated into delivery process\u000aalerting with manual remediation is in place',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1348,260,3,'Integrated','Application and infrastructure pipelines are integrated.  ci/cd pipelines are used in production workloads.  centralized logging enables enhanced monitoring and alerting. automated testing is in place.','Documentation exists\u000adevops culture is adopted\u000aautomated testing is part of the pipeline\u000acentralized logging and monitoring in place with manual remediation and meets compliance standards\u000asource and artifact repositories are in use\u000abranching and merging strategy is in use\u000arollback/dr is integrated into delivery process\u000aalerting with manual remediation is in place',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1349,187,4,'Intelligent','The organization has a comprehensive repository of ci/cd toolchains shared by all relevant teams. build, test, deployment, and monitoring are mostly automated for all relevant teams. there are frequent (weekly or bi-weekly) automated releases. pipeline is fully automated.  deployments are optimized to meet or exceed availability requirements.','Code quality checks\u000aci/cd workflow standardization\u000aworkflow processes documented and shared\u000aci/cd standards documented and shared\u000aintegration with other management tools\u000aci/cd penetration/coverage across app portfolio\u000adevops culture is adopted\u000afull automation is in place\u000acentralized logging and monitoring in place with manual remediation and meets compliance standards\u000asource and artifact repositories are in use\u000abranching and merging strategy is in use\u000arollback/dr is integrated into delivery process\u000aalerting with manual remediation is in place\u000azero downtime deployments',NULL,1);
