INSERT INTO Next_CapabilityLevel VALUES(1352,260,5,'Adaptive','Roi and business value is quantified, published, with appropriate refinements and improvements as needed.  operational efficiency is at its peak and time to market for new features is optimized.  12factor application methodology is in place.','Documentation exists\u000adevops culture is adopted\u000afull automation is in place\u000acentralized logging and monitoring in place with manual remediation and meets compliance standards\u000asource and artifact repositories are in use\u000abranching and merging strategy is in use\u000apipeline are able to self-heal\u000arollback/dr is automated\u000aalerting with manual remediation is in place\u000azero downtime deployments happen daily or more frequently',NULL,1);
