INSERT INTO Next_CapabilityLevel VALUES(1412,271,5,'Adaptive','Networking deployments include automated testing that is run via post deployment validation pipeline.  network connectivity includes multiple csp interconnections allowing applicable applications to scale and move across csps.  vendor redundant external connectivity that spans multiple regions.  self-healing security controls that auto remediate all high priority events.  self-service portal for client requests.','Network design spans multiple csps\u000amesh network using multiple providers for high speed links to csp(s)\u000aintrusion/breach can self-heal\u000anetwork design spans multiple csps\u000afirewall automation \u000aself service \u000a',NULL,1);
