INSERT INTO Next_CapabilityLevel VALUES(1427,274,5,'Adaptive','The it asset register maintains 100% accuracy is optimized to meet specific goals and is the hub for automation.','Fully automated discovery processes with automated configuration item creations and archival in real-time. \u000ait asset register (or cms) is fully populated with ci configurations and ci relationships to support specific use cases and goals which may include incident, problem, availability, change, asset, knowledge, risk and continuity management. \u000athe well-constructed it asset register (or cms) has documented goals regarding expected service management support expectations to optimize content',NULL,1);
