INSERT INTO Next_CapabilityLevel VALUES(1429,275,2,'Defined','The organization  will have more detailed and structured processes in place. capacity and performance management have the appropriate baselines and agreed upon metrics and reporting to respond to business requirements.','Query performance tuning\u000adashboard\u000aservice capacity and performance reporting process\u000astaffing capacity management process\u000acapacity and performance baselines \u000acapacity and performance policies\u000acapacity and performance plans – at this level this would be based against (and include) the requirements\u000acapacity and performance models – includes policies\u000acapacity and performance dashboards – includes agreed requirements\u000acapacity and performance gap analyses\u000acapacity and performance reports\u000acapacity and performance reviews\u000acapacity and performance thresholds',NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(1430,275,3,'Integrated','The organization will have more proactive and predictive processes in place. performance monitoring is in place for all data workloads. appropriate capacity and performance data is collected and analyzed such that future requirements can be estimated and incorporated into the plan.  capacity data is analyzed on a regular basis, to identify trends, capacity levels, bottlenecks and overcapacity.','Performance monitoring\u000aperformance alters\u000acapacity monitoring and alerting process \u000aintegrated capacity plan\u000ademand management processes\u000acapacity and performance analysis tools\u000acapacity and performance forecasts\u000acapacity and performance optimization techniques\u000acapacity and performance simulations\u000acapacity and performance trend analysis\u000a',NULL,1);
