INSERT INTO Next_CapabilityLevel VALUES(2155,144,1,NULL,'The enterprise does not have a complete, up to date census of their application portfolio. \u000aany rationalization efforts are ad-hoc or one-off, usually triggered by externalities such as evaluation of a new vendor or maintenance issues/limitations with an existing application. \u000aapplication tco analysis does not exist or is minimal.\u000ano enterprise architectural or tech stack standards/recommendations.',NULL,NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(2156,144,2,NULL,'Application portfolio information has been compiled, but information is known to be dirty and possibly incomplete. \u000aattempts are being made to develop tco and usage mappings for all applications. \u000aapplication tech stack is noted and an effort to consolidate (enterprise recommendations) have been developed, as well as a basic enterprise architecture.',NULL,NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(2157,144,3,NULL,'The enterprise uses instrumentation to track application tco, as well as customer usage, resources and other metrics\u000abasic productivity unit-cost metrics\u000athere is an enterprise wide architecture design patterns as well as tech guidelines\u000apart of the sdlc process is periodic rationalization review and that leads to a possible retire/replace/refactor effort\u000alegacy applications using non-standard tech or anti-pattern resources might still exist, but there is a plan to address these issues',NULL,NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(2158,144,4,NULL,'Rationalization reviews are annual or even more frequent\u000aarchitectural patterns are well-designed but flexible and allow for developer innovation\u000aenterprise tech recommendations are clear but often amended and new technology evaluation is encouraged\u000aapplication functionality is mapped (e.g. searchable microservices library) for easy reuse and duplication avoidance\u000alive application meta data allows for easy identification of under-utilized or high-cost applications. these applications are quickly updated or retired\u000aworkload aligned hosting service selection',NULL,NULL,1);
INSERT INTO Next_CapabilityLevel VALUES(2159,144,5,NULL,'Rationalization is part of the continuous agile process. \u000ain this environment, all applications are being maintained and updated continuously. \u000athe entire portfolio is implemented in a loosely coupled, modular fashion that allows for easy re-use or partial update easily and quickly. \u000aapplications are continuously being assessed for cost/usage footprint, and optimizing these metrics is part of the regular development process.',NULL,NULL,1);
