INSERT INTO Next_ChangeRecord VALUES(1,2,'capability','ADD','Next_Capability',304,'FinOps & Cloud Economics (id=304)',NULL,NULL,'category=Core | domain=Strategy & Governance | subdomain=Vendor Management (initial) | owner=FinOps Lead / Cloud Financial Manager','Gap analysis identified no explicit FinOps capability. UC11 and UC33 had no assessable capability anchor.','Vernon Rauch','2026-03-07 09:42:49');
INSERT INTO Next_ChangeRecord VALUES(2,2,'capability','MOVE','Next_Capability',304,'FinOps & Cloud Economics (id=304)','subdomain_id','5 (Vendor Management)','1 (Oversight)','FinOps is a governance and financial accountability discipline, not a vendor relationship discipline. Oversight peers share the same accountability-first posture. Corrected after initial placement.','Vernon Rauch','2026-03-07 09:42:53');
INSERT INTO Next_ChangeRecord VALUES(3,2,'level','SEED','Next_CapabilityLevel',NULL,'FinOps & Cloud Economics L1-L5 (ids 2828-2832)',NULL,NULL,'L1 Ad Hoc through L5 Adaptive with full capability_state and key_indicators per level','L1 Ad Hoc through L5 Adaptive. Covers CSP billing-only baseline through ROCI/TCO at board level with FinOps Foundation benchmarking.','Vernon Rauch','2026-03-07 09:43:35');
INSERT INTO Next_ChangeRecord VALUES(4,2,'assessment','SEED','Next_MaturityAssessment',NULL,'FinOps - 4 dimension baseline assessments (score=1 each)',NULL,NULL,'Process=1, People=1, Technology=1, Governance=1','All 4 dimensions seeded at Ad Hoc baseline. Typical posture for organisations without a formal FinOps practice.','Vernon Rauch','2026-03-07 09:43:45');
INSERT INTO Next_ChangeRecord VALUES(5,2,'tag','ADD','Next_CapabilityTagMap',304,'FinOps tags: governance (id=7) + cloud (id=1)',NULL,NULL,'governance, cloud','governance as primary, cloud as secondary. Mirrors Cloud Benchmarking pattern as closest sibling in Vendor Management.','Vernon Rauch','2026-03-07 09:43:45');
INSERT INTO Next_ChangeRecord VALUES(6,2,'cluster','ADD','Next_CapabilityClusterMap',304,'FinOps cluster: Operations & Reliability (id=5)',NULL,NULL,'Operations & Reliability','Consistent with all Oversight subdomain siblings (KPIs & Metrics, Governance Risk Management, Transformation Business Office).','Vernon Rauch','2026-03-07 09:43:45');
INSERT INTO Next_ChangeRecord VALUES(7,2,'interdependency','ADD','Next_CapabilityInterdependency',NULL,'FinOps - 5 inbound + 5 outbound interdependencies',NULL,NULL,'See interdependency graph','Inbound: Account & Subscription Structure (Foundational/5), KPIs & Metrics (Foundational/4), Governance Risk Mgmt (Foundational/3), License & Subscription Mgmt (Amplifying/3), Cloud Benchmarking (Amplifying/3). Outbound: KPIs & Metrics (Amplifying/4), Capacity & Performance Mgmt (Foundational/4), Technology Adoption & Utilization (Foundational/3), Automation Framework (Amplifying/3), Sustainability Analytics (Complementary/3).','Vernon Rauch','2026-03-07 09:43:45');
INSERT INTO Next_ChangeRecord VALUES(8,2,'usecase','ADD','Next_UseCaseCapabilityImpact',NULL,'FinOps linked to UC11, UC33, UC29',NULL,NULL,'UC11 impact=5/target=L4, UC33 impact=5/target=L4, UC29 impact=4/target=L3','UC11 Hybrid IT/Cloud Cost Optimization and UC33 Cloud Cost Optimization are primary. UC29 Technology Debt & Financial Alignment is strong secondary.','Vernon Rauch','2026-03-07 09:43:45');
INSERT INTO Next_ChangeRecord VALUES(9,2,'assessment','SEED','Next_TargetMaturity',NULL,'FinOps - 12 target maturity rows (3 UCs x 4 dimensions)',NULL,NULL,'UC11: P=4,Pe=3,T=4,G=4 | UC33: P=4,Pe=3,T=4,G=3 | UC29: P=3,Pe=2,T=3,G=3','Target maturity seeded to enable roadmap generation and investment scoring for all three linked use cases.','Vernon Rauch','2026-03-07 09:43:45');
INSERT INTO Next_ChangeRecord VALUES(10,3,'capability','ADD','Next_Capability',305,'Supply Chain Security (id=305)',NULL,NULL,'domain=Security | subdomain=GRC | category=Core | owner=CISO/Supply Chain Security Lead','Tier 1 gap — SBOM governance, dependency scanning, supplier attestation. No existing framework coverage despite NIST 800-161, NIS2, and SOCI obligations. Placed in Security GRC alongside Cybersecurity Strategy and Security Risk Management.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(11,3,'capability','ADD','Next_Capability',306,'Zero Trust Network Access Architecture (id=306)',NULL,NULL,'domain=Security | subdomain=Infrastructure & Platform Security | category=Core | owner=Network Security Architect','Tier 1 gap — UC18 Zero Trust use case had no assessable capability anchor. ZTNA is an architectural discipline distinct from general Network Security (id=60). Placed in Infrastructure & Platform Security.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(12,3,'capability','ADD','Next_Capability',307,'AI Security & Model Integrity (id=307)',NULL,NULL,'domain=Security | subdomain=GRC | category=Core | owner=AI Security Lead/CISO','Tier 1 gap — domain 9 (AI & Cognitive Systems) has Responsible AI Governance but no security control layer for AI-specific threats (adversarial inputs, prompt injection, model poisoning). Placed in Security GRC as a governance-posture capability.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(13,3,'capability','ADD','Next_Capability',308,'Technical Debt Management (id=308)',NULL,NULL,'domain=Applications | subdomain=Strategy | category=Core | owner=Chief Architect/Engineering Lead','Tier 1 gap — UC29 Technology Debt & Financial Alignment had no assessable capability anchor. App Rationalization (id=144) governs portfolio decisions; Technical Debt Management governs ongoing health of retained assets. Placed in Applications Strategy.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(14,3,'capability','ADD','Next_Capability',309,'Generative AI & LLM Operations (id=309)',NULL,NULL,'domain=AI & Cognitive Systems | subdomain=AI Lifecycle Management | category=Core | owner=GenAI Platform Lead','Emerging gap — extends AI Model Lifecycle Management (id=291) specifically for foundation model workloads. Covers RAG pipelines, prompt governance, hallucination monitoring, token cost management.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(15,3,'capability','ADD','Next_Capability',310,'Digital Twin & Simulation (id=310)',NULL,NULL,'domain=Innovation | subdomain=Innovation Enablement Value Chain | category=Core | owner=Digital Twin Architect','Emerging gap — no simulation capability in the framework. Placed in Innovation Enablement Value Chain alongside IaC and Cloud Optimized Development. Connects to Sustainability Analytics (carbon twins) and Capacity & Performance Management.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(16,3,'level','SEED','Next_CapabilityLevel',NULL,'L1-L5 for all 6 new capabilities (30 rows)',NULL,NULL,'5 levels x 6 capabilities with full capability_state and key_indicators','Full maturity progression defined for each capability from Ad Hoc to Adaptive.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(17,3,'assessment','SEED','Next_MaturityAssessment',NULL,'4-dimension baseline for all 6 capabilities (24 rows)',NULL,NULL,'All dimensions at score=1 (Ad Hoc)','Standard baseline for new framework capabilities prior to client assessment.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(18,3,'tag','ADD','Next_CapabilityTagMap',NULL,'12 tag assignments across 6 capabilities',NULL,NULL,'305:security+governance | 306:security+cloud | 307:security+governance | 308:applications+governance | 309:applications+cloud | 310:innovation+cloud','Tagged to support intent-weighted use case scoring and dashboard filtering.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(19,3,'cluster','ADD','Next_CapabilityClusterMap',NULL,'6 cluster assignments',NULL,NULL,'305,306,307→Security Foundation | 308→Application Platform | 309→AI & Cognitive Systems | 310→Innovation & Experimentation','Cluster assignment consistent with domain and peer capability patterns.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(20,3,'interdependency','ADD','Next_CapabilityInterdependency',NULL,'37 interdependencies across 6 capabilities',NULL,NULL,'See interdependency graph','Inbound and outbound links mapped for all 6 capabilities. Key chains: AI Security→GenAI Ops, Authentication→ZTNA, App Rationalization↔Technical Debt, Digital Twin→Sustainability Analytics.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(21,3,'usecase','ADD','Next_UseCaseCapabilityImpact',NULL,'18 use case impact links across 6 capabilities',NULL,NULL,'305:UC15,UC18,UC31 | 306:UC18,UC20,UC15 | 307:UC30,UC18,UC31 | 308:UC29,UC19,UC34 | 309:UC30,UC9,UC31 | 310:UC9,UC32,UC14','Use case anchoring ensures new capabilities surface in assessment and roadmap generation.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(22,3,'assessment','SEED','Next_TargetMaturity',NULL,'40 target maturity rows across 6 capabilities and 10 use case linkages',NULL,NULL,'Per capability: target L3-L5 depending on use case criticality','Target maturity seeded to enable immediate roadmap generation for all linked use cases.','Vernon Rauch','2026-03-07 09:52:44');
INSERT INTO Next_ChangeRecord VALUES(23,3,'usecase','ADD','Next_UseCaseCapabilityImpact',NULL,'24 additional UC impact links across all 6 capabilities',NULL,'Partial coverage (3 UCs per capability)','305:7 UCs | 306:7 UCs | 307:6 UCs | 308:7 UCs | 309:7 UCs | 310:8 UCs','Extended coverage to all relevant use cases. Notable additions: 305→UC26 Digital Supply Chain (impact=5, primary); 309→UC25 Health Intelligence (impact=5, primary); 310→UC22 IT&OT Convergence (impact=4, OT twin use case). All 6 capabilities now linked to UC35 Enterprise Baseline Assessment.','Vernon Rauch','2026-03-07 10:01:25');
INSERT INTO Next_ChangeRecord VALUES(24,3,'assessment','ADD','Next_TargetMaturity',NULL,'128 target maturity rows added across all 6 capabilities',NULL,'40 rows from initial integration','305:28 rows/7 UCs | 306:28 rows/7 UCs | 307:24 rows/6 UCs | 308:28 rows/7 UCs | 309:28 rows/7 UCs | 310:32 rows/8 UCs','Full target maturity coverage — every UC impact link now has 4-dimension target scores. All 8 previously identified gaps closed. 96 new rows for extended UC links.','Vernon Rauch','2026-03-07 10:01:25');
INSERT INTO Next_ChangeRecord VALUES(25,3,'taxonomy','ADD','Next_RoadmapStep',NULL,'44 roadmap steps inserted across 6 capabilities and 18 use cases',NULL,'0 roadmap steps','Phase 1 (priority 15): primary anchors in UC18 Zero Trust, UC26 Digital Supply Chain, UC30 AI Readiness, UC25 Health Intelligence | Phase 2: most secondary links | Phase 3-4: baseline/supporting','Phase assignment based on impact weight (5=phase 1-2, 4=phase 2, 3=phase 3). Priority score = impact_weight × maturity_gap from current baseline of L1.','Vernon Rauch','2026-03-07 10:01:25');
INSERT INTO Next_ChangeRecord VALUES(26,3,'metadata','ADD','Next_CapabilityInvestmentCost',NULL,'6 investment cost rows — differentiated by capability complexity',NULL,'No investment cost rows','305:2.5 | 306:3.0 (highest — architectural programme) | 307:2.0 | 308:1.5 (lowest — process uplift) | 309:2.5 | 310:2.0','Cost estimates differentiated based on implementation complexity. ZTNA (306) is highest at 3.0× due to architectural change programme. Technical Debt (308) is lowest at 1.5× as primarily process and lightweight tooling.','Vernon Rauch','2026-03-07 10:01:25');
INSERT INTO Next_ChangeRecord VALUES(27,3,'taxonomy','ADD','Next_ScenarioCapabilityChange',NULL,'16 scenario capability change rows across 3 scenarios',NULL,'0 scenario rows for new capabilities','Scenario 4 (Innovation at Scale): 309 GenAI (L1→L3), 310 Digital Twin (L1→L3). Scenario 3 (BC&DR): 310 Digital Twin (L1→L3). Scenario 2 (Op Model Mod): 308 Technical Debt (L1→L3)','Wired new capabilities into existing transformation scenarios where conceptually aligned. Enables what-if simulation for these capability improvements.','Vernon Rauch','2026-03-07 10:01:25');
INSERT INTO Next_ChangeRecord VALUES(28,4,'taxonomy','ADD','Next_SubDomain',59,'AI Infrastructure & Compute',NULL,NULL,'subdomain_id=59, domain_id=9','Gap identified: no subdomain covering GPU/accelerator provisioning, model serving infrastructure, or AI-specific compute. Industry frameworks (AWS Well-Architected ML, Google Cloud AI Platform, NVIDIA AI Enterprise) all treat compute as a distinct capability domain. Added as 5th subdomain of AI & Cognitive Systems.','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(29,4,'capability','ADD','Next_Capability',311,'Feature Store & Data Preparation',NULL,NULL,'domain_id=9, subdomain_id=45 (AI Lifecycle Management)','Gap: feature engineering is the most common MLOps failure point causing training-serving skew. Absent from domain despite being a core AI Lifecycle capability in Feast, Tecton, Hopsworks, and all major cloud ML platforms.','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(30,4,'capability','ADD','Next_Capability',312,'Model Evaluation & Benchmarking',NULL,NULL,'domain_id=9, subdomain_id=45 (AI Lifecycle Management)','Gap: model promotion without standardised evaluation is a leading cause of AI quality failures. Distinct from production monitoring — covers pre-deployment validation, A/B testing, and LLM-specific evaluation (RAGAS, hallucination benchmarks).','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(31,4,'capability','ADD','Next_Capability',313,'AI Bias Detection & Fairness Testing',NULL,NULL,'domain_id=9, subdomain_id=46 (Responsible & Ethical AI)','Gap: Responsible AI Governance (292) is a process wrapper but has no capability covering the technical practice of bias measurement and remediation. Required for NIST AI RMF MAP-2 and Australian AI Ethics compliance.','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(32,4,'capability','ADD','Next_Capability',314,'AI Explainability & Interpretability',NULL,NULL,'domain_id=9, subdomain_id=46 (Responsible & Ethical AI)','Gap: EU AI Act Article 13 requires explainability for high-risk AI systems. No current capability covers SHAP/LIME, counterfactual explanation, or XAI tooling. Critical for financial services, healthcare, and public sector clients.','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(33,4,'capability','ADD','Next_Capability',315,'AI Regulatory Compliance & Risk Management',NULL,NULL,'domain_id=9, subdomain_id=46 (Responsible & Ethical AI)','Gap: EU AI Act, Australia AI Ethics Framework, APRA CPG 234 are all now active or imminent. No current capability covers AI regulatory compliance specifically. Clients in financial services and health increasingly require AI conformity assessment evidence.','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(34,4,'capability','ADD','Next_Capability',316,'Predictive Analytics & Forecasting',NULL,NULL,'domain_id=9, subdomain_id=47 (Decision Intelligence)','Gap: Decision Intelligence Enablement (293) covers embedding AI in decisions but not the model-building and production forecasting platform. Predictive Analytics is a distinct, foundational capability present in all major AI maturity models (Gartner, McKinsey, AWS).','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(35,4,'capability','ADD','Next_Capability',317,'AI Agent & Orchestration Framework',NULL,NULL,'domain_id=9, subdomain_id=48 (AI Integration & Orchestration)','Gap: Agentic AI (multi-agent systems, LangGraph, AutoGen) is the fastest-growing enterprise AI pattern in 2025-26. No current capability covers agent orchestration, tool-use governance, or agent risk management. GenAI & LLM Ops (309) covers individual models; this covers the orchestration layer above.','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(36,4,'capability','ADD','Next_Capability',318,'Cognitive Search & Knowledge Retrieval',NULL,NULL,'domain_id=9, subdomain_id=48 (AI Integration & Orchestration)','Gap: RAG and vector search are now foundational to enterprise AI deployment. No current capability covers vector database governance, embedding model management, or retrieval quality measurement. Foundational to GenAI & LLM Operations (309).','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(37,4,'capability','ADD','Next_Capability',319,'AI Compute & Accelerator Management',NULL,NULL,'domain_id=9, subdomain_id=59 (AI Infrastructure & Compute)','Gap: GPU fleet management, inference serving (Triton, vLLM), and AI-specific networking (InfiniBand) are absent from the framework despite being the most significant AI cost driver and a key constraint on AI programme delivery at scale.','Vernon Rauch','2026-03-07');
INSERT INTO Next_ChangeRecord VALUES(38,4,'metadata','ADD','Next_Framework',NULL,'Multi-framework migration',NULL,NULL,NULL,'Added Next_Framework registry and framework_id columns for multi-framework support','Vernon Rauch','2026-03-16 04:02:40');
INSERT INTO Next_Domain VALUES(1,'Strategy & Governance','Focuses on aligning strategy, standards, and oversight to enable enterprise-wide modernization and governance maturity.','E2CAF_Next_v1.0','2026-01-23 19:14:02',1);
INSERT INTO Next_Domain VALUES(2,'Security','Builds and maintains trust, compliance, and risk management across digital and operational systems.','E2CAF_Next_v1.0','2026-01-23 19:14:02',1);
INSERT INTO Next_Domain VALUES(3,'People','Addresses workforce enablement, culture, skills, and organizational adaptability for sustained transformation.','E2CAF_Next_v1.0','2026-01-23 19:14:02',1);
INSERT INTO Next_Domain VALUES(4,'Applications','Supports capabilities related to enterprise maturity and modernization.','E2CAF_Next_v1.0','2026-01-23 19:14:02',1);
INSERT INTO Next_Domain VALUES(5,'Data','Ensures the effective governance, quality, and utilization of data to drive insight and value across the enterprise.','E2CAF_Next_v1.0','2026-01-23 19:14:02',1);
INSERT INTO Next_Domain VALUES(6,'DevOps','Integrates development and operations practices to enhance agility, automation, and continuous delivery.','E2CAF_Next_v1.0','2026-01-23 19:14:02',1);
INSERT INTO Next_Domain VALUES(7,'Innovation','Supports capabilities related to enterprise maturity and modernization.','E2CAF_Next_v1.0','2026-01-23 19:14:02',1);
INSERT INTO Next_Domain VALUES(8,'Operations','Covers service operations, management, and optimization to ensure consistent and resilient service delivery.','E2CAF_Next_v1.0','2026-01-23 19:14:02',1);
INSERT INTO Next_Domain VALUES(9,'AI & Cognitive Systems','Enables intelligent automation, decision augmentation, and cognitive insight through AI, ML, and natural language technologies.','E2CAF_Next_v1.0','2026-01-23 19:15:34',1);
INSERT INTO Next_Domain VALUES(10,'Intelligent Automation & Operations','Combines process automation, AIOps, and autonomous systems to deliver continuous, intelligent, self-optimizing operations.','E2CAF_Next_v1.0','2026-01-23 19:15:34',1);
INSERT INTO Next_Domain VALUES(11,'Sustainability & Responsible Technology','Focuses on environmentally and socially responsible technology management, sustainable cloud operations, and ESG reporting enablement.','E2CAF_Next_v1.0','2026-01-23 19:15:34',1);
INSERT INTO Next_Domain VALUES(12,'Experience & Ecosystem Enablement','Creates value through connected experiences, data-driven personalization, and partner ecosystem integration.','E2CAF_Next_v1.0','2026-01-23 19:15:34',1);
INSERT INTO Next_Domain VALUES(13,'Govern','Establishes and monitors the organisation''s cybersecurity risk management strategy, expectations, and policy.','NIST_CSF_2.0','2026-03-16 04:21:07',2);
INSERT INTO Next_Domain VALUES(14,'Identify','Helps develop an organisational understanding to manage cybersecurity risk to systems, people, assets, data, and capabilities.','NIST_CSF_2.0','2026-03-16 04:21:07',2);
INSERT INTO Next_Domain VALUES(15,'Protect','Develops and implements appropriate safeguards to ensure delivery of critical services.','NIST_CSF_2.0','2026-03-16 04:21:07',2);
INSERT INTO Next_Domain VALUES(16,'Detect','Develops and implements appropriate activities to identify the occurrence of a cybersecurity event.','NIST_CSF_2.0','2026-03-16 04:21:07',2);
INSERT INTO Next_Domain VALUES(17,'Respond','Develops and implements appropriate activities to take action regarding a detected cybersecurity incident.','NIST_CSF_2.0','2026-03-16 04:21:07',2);
INSERT INTO Next_Domain VALUES(18,'Recover','Develops and implements appropriate activities to maintain plans for resilience and to restore any capabilities or services that were impaired due to a cybersecurity incident.','NIST_CSF_2.0','2026-03-16 04:21:07',2);
INSERT INTO Next_FrameworkVersion VALUES(1,'v1.0','E2CAF Next Baseline','published','Framework Evolution Taskforce','2026-01-23 19:14:02','Initial framework population from E2CAF baseline. 303 capabilities across 8 core domains (Strategy & Governance, Security, People, Applications, Data, DevOps, Innovation, Operations) plus 4 emerging domains (AI & Cognitive Systems, Intelligent Automation & Operations, Sustainability & Responsible Technology, Experience & Ecosystem Enablement). Full maturity level descriptors, interdependency graph, use case impact model, and roadmap scaffolding established.');
INSERT INTO Next_FrameworkVersion VALUES(2,'v1.1','FinOps Integration & Subdomain Correction','published','Vernon Rauch','2026-03-07','Added FinOps & Cloud Economics (id=304) capability to Strategy & Governance domain. Initially placed under Vendor Management subdomain, then correctly relocated to Oversight subdomain. Full model integration completed: tags, cluster mapping, 10 interdependencies, use case impact links to UC11/UC33/UC29, and target maturity seeded for all 3 use cases across 4 dimensions.');
INSERT INTO Next_FrameworkVersion VALUES(3,'v1.2','Tier 1 & Emerging Gap Capabilities','published','Vernon Rauch','2026-03-07 09:48:19','Six gap capabilities added from gap analysis: Supply Chain Security, ZTNA Architecture, AI Security & Model Integrity (Tier 1 priority), Technical Debt Management (Tier 1), Generative AI & LLM Operations, Digital Twin & Simulation (Emerging). No new domains or subdomains required — all placed within existing taxonomy. | Full integration pass completed: UC impact links, target maturity (4 dimensions × all UCs), roadmap steps (44), investment costs (differentiated), scenario wiring (3 scenarios).');
INSERT INTO Next_FrameworkVersion VALUES(4,'v1.3','AI & Cognitive Systems — Domain Expansion','published','Vernon Rauch','2026-03-07','9 new capabilities added across 5 subdomains of domain 9 (AI & Cognitive Systems). Added new subdomain: AI Infrastructure & Compute (id=59). Capabilities added: Feature Store & Data Preparation (311), Model Evaluation & Benchmarking (312), AI Bias Detection & Fairness Testing (313), AI Explainability & Interpretability (314), AI Regulatory Compliance & Risk Management (315), Predictive Analytics & Forecasting (316), AI Agent & Orchestration Framework (317), Cognitive Search & Knowledge Retrieval (318), AI Compute & Accelerator Management (319). Domain now has 14 capabilities across 5 subdomains. Full integration: 45 maturity levels, 36 baseline assessments, 18 tag assignments, 9 cluster assignments, 30 interdependencies, 38 UC impact links, 152 target maturity rows, 38 roadmap steps, 9 investment cost rows.');
