INSERT INTO Next_SubDomain VALUES(45,9,'AI Lifecycle Management','Processes and tools to manage AI model lifecycle from design through deployment and monitoring.',1);
INSERT INTO Next_SubDomain VALUES(46,9,'Responsible & Ethical AI','Frameworks ensuring fairness, transparency, accountability, and regulatory compliance in AI systems.',1);
INSERT INTO Next_SubDomain VALUES(47,9,'Decision Intelligence','Integration of AI insights into business decision-making and optimization.',1);
INSERT INTO Next_SubDomain VALUES(48,9,'AI Integration & Orchestration','Connecting AI services and cognitive components across enterprise systems.',1);
INSERT INTO Next_SubDomain VALUES(49,10,'Process Automation & RPA','Automation of repetitive business processes through RPA and low-code platforms.',1);
INSERT INTO Next_SubDomain VALUES(50,10,'AIOps & Autonomous Operations','Leveraging AI for predictive monitoring, incident prevention, and self-healing infrastructure.',1);
INSERT INTO Next_SubDomain VALUES(51,10,'Workflow Orchestration','Integration and orchestration of automated workflows across systems and domains.',1);
INSERT INTO Next_SubDomain VALUES(52,11,'Sustainable IT Operations','Optimization of technology infrastructure for energy efficiency and carbon reduction.',1);
INSERT INTO Next_SubDomain VALUES(53,11,'ESG Data & Reporting','Integration of sustainability metrics into enterprise data ecosystems for compliance and transparency.',1);
INSERT INTO Next_SubDomain VALUES(54,11,'Ethical & Circular Tech','Strategies to reduce waste, improve recycling, and design for sustainability across the IT lifecycle.',1);
INSERT INTO Next_SubDomain VALUES(55,12,'Customer & Employee Experience','Design and orchestration of digital experiences across user journeys and touchpoints.',1);
INSERT INTO Next_SubDomain VALUES(56,12,'Experience Analytics & Insights','Measurement of user sentiment, engagement, and value realization using analytics and AI.',1);
INSERT INTO Next_SubDomain VALUES(57,12,'Ecosystem Integration','Enabling interoperability and data sharing across partners, platforms, and ecosystems.',1);
INSERT INTO Next_SubDomain VALUES(58,5,'Data Strategy & Culture','Directional and behavioural capabilities that set organisational intent for data — including data strategy, data-driven culture, and adoption of data metrics.',1);
INSERT INTO Next_SubDomain VALUES(59,9,'AI Infrastructure & Compute','Provision, management, and optimisation of compute infrastructure — including GPU/accelerator clusters, model serving platforms, and AI-specific networking — required to train, fine-tune, and serve AI workloads at enterprise scale.',1);
INSERT INTO Next_SubDomain VALUES(60,13,'Organizational Context','The circumstances — mission, stakeholder expectations, dependencies — surrounding the organisation''s cybersecurity risk decisions are understood.',2);
INSERT INTO Next_SubDomain VALUES(61,13,'Risk Management Strategy','The organisation''s priorities, constraints, risk tolerance and appetite statements, and assumptions are established, communicated, and used to support operational risk decisions.',2);
INSERT INTO Next_SubDomain VALUES(62,13,'Roles, Responsibilities, and Authorities','Cybersecurity roles, responsibilities, and authorities to foster accountability, performance assessment, and continuous improvement are established and communicated.',2);
INSERT INTO Next_SubDomain VALUES(63,13,'Policy','Organisational cybersecurity policy is established, communicated, and enforced.',2);
INSERT INTO Next_SubDomain VALUES(64,13,'Oversight','Results of organisation-wide cybersecurity risk management activities and performance are used to inform, improve, and adjust the risk management strategy.',2);
INSERT INTO Next_SubDomain VALUES(65,13,'Cybersecurity Supply Chain Risk Management','Cyber supply chain risk management processes are identified, established, managed, monitored, and improved by organisational stakeholders.',2);
INSERT INTO Next_SubDomain VALUES(66,14,'Asset Management','Assets (data, hardware, software, systems, facilities, services, people) that enable the organisation to achieve business purposes are identified and managed consistent with their relative importance to organisational objectives and the organisation''s risk strategy.',2);
INSERT INTO Next_SubDomain VALUES(67,14,'Risk Assessment','The organisation understands the cybersecurity risk to organisational operations (including mission, functions, image, or reputation), organisational assets, and individuals.',2);
INSERT INTO Next_SubDomain VALUES(68,14,'Improvement','Improvements to organisational cybersecurity risk management processes, procedures and activities are identified across all CSF Functions.',2);
INSERT INTO Next_SubDomain VALUES(69,15,'Identity Management, Authentication, and Access Control','Access to physical and logical assets is limited to authorised users, services, and hardware and managed commensurate with the assessed risk of unauthorised access.',2);
INSERT INTO Next_SubDomain VALUES(70,15,'Awareness and Training','The organisation''s personnel and partners are provided cybersecurity awareness education and are trained to perform their cybersecurity-related duties and responsibilities.',2);
INSERT INTO Next_SubDomain VALUES(71,15,'Data Security','Data are managed consistent with the organisation''s risk strategy to protect the confidentiality, integrity, and availability of information.',2);
INSERT INTO Next_SubDomain VALUES(72,15,'Platform Security','The hardware, software (e.g., firmware, operating systems, applications), and services of physical and virtual platforms are managed consistent with the organisation''s risk strategy.',2);
INSERT INTO Next_SubDomain VALUES(73,15,'Technology Infrastructure Resilience','Security architectures are managed with the organisation''s risk strategy to protect asset confidentiality, integrity, and availability, and organisational resilience.',2);
INSERT INTO Next_SubDomain VALUES(74,16,'Continuous Monitoring','Assets are monitored to find anomalies, indicators of compromise, and other potentially adverse events.',2);
INSERT INTO Next_SubDomain VALUES(75,16,'Adverse Event Analysis','Anomalies and indicators of compromise and other potentially adverse events are analysed to characterise the events and detect cybersecurity incidents.',2);
INSERT INTO Next_SubDomain VALUES(76,17,'Incident Management','Responses to detected cybersecurity incidents are managed.',2);
INSERT INTO Next_SubDomain VALUES(77,17,'Incident Analysis','Investigations are conducted to ensure effective response and support forensics and recovery activities.',2);
INSERT INTO Next_SubDomain VALUES(78,17,'Incident Response Reporting and Communication','Response activities are coordinated with internal and external stakeholders (e.g. external support from law enforcement agencies).',2);
INSERT INTO Next_SubDomain VALUES(79,17,'Incident Mitigation','Activities are performed to prevent expansion of an event, mitigate its effects, and resolve the incident.',2);
INSERT INTO Next_SubDomain VALUES(80,18,'Incident Recovery Plan Execution','Restoration activities are performed to ensure operational availability of systems and services affected by cybersecurity incidents.',2);
INSERT INTO Next_SubDomain VALUES(81,18,'Incident Recovery Communication','Restoration activities are coordinated with internal and external parties (e.g. coordinating centres, Internet Service Providers, owners of attacking systems, victims, other CSIRTs, and vendors).',2);
