INSERT INTO Next_UseCase VALUES(35,'Enterprise Baseline Assessment','Full-spectrum E2CAF maturity baseline assessment across all 12 domains and 292 capabilities. Establishes current state scores and target maturity levels to drive transformation roadmap prioritisation.','Provides a structured, defensible foundation for enterprise transformation planning, investment prioritisation, and executive alignment against HPE Bold Goals 2026.','Chief Technologist / Senior Consultant','E2CAF_Next_v1.0',1);
INSERT INTO Next_UseCase VALUES(36,'Cybersecurity Baseline Assessment','Establish an organisation-wide baseline maturity across all six NIST CSF 2.0 functions.','Provides a defensible, structured view of current cybersecurity posture for leadership and board reporting.','CISO / Head of Cybersecurity','NIST_CSF_2.0',2);
INSERT INTO Next_UseCase VALUES(37,'Incident Response Readiness','Assess the organisation''s capability to detect, respond to, and recover from cybersecurity incidents.','Reduces mean time to detect and respond to incidents, limiting operational and reputational impact.','Head of Security Operations','NIST_CSF_2.0',2);
INSERT INTO Next_UseCase VALUES(38,'Cybersecurity Governance Review','Evaluate the maturity of cybersecurity governance, risk management strategy, and policy frameworks.','Strengthens accountability, risk-informed decision making, and regulatory alignment.','CRO / CISO','NIST_CSF_2.0',2);
INSERT INTO Next_UseCase VALUES(39,'Supply Chain Risk Assessment','Assess cybersecurity risk management practices across the supply chain and third-party ecosystem.','Reduces exposure to supplier-introduced vulnerabilities and strengthens third-party risk programmes.','Head of Procurement / CISO','NIST_CSF_2.0',2);
INSERT INTO Next_UseCase VALUES(40,'Protect and Detect Maturity','Deep-dive assessment of technical controls maturity across protection and detection capabilities.','Identifies gaps in technical security controls and monitoring capabilities to prioritise investment.','Head of Security Architecture','NIST_CSF_2.0',2);
