PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE Next_Capability (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    domain_id INTEGER NOT NULL,
    subdomain_id INTEGER NOT NULL,
    capability_name TEXT NOT NULL,
    capability_description TEXT,
    category TEXT,
    owner_role TEXT, framework_id INTEGER DEFAULT 1,
    FOREIGN KEY (domain_id) REFERENCES Next_Domain(id),
    FOREIGN KEY (subdomain_id) REFERENCES Next_SubDomain(id)
);
CREATE TABLE Next_CapabilityCluster (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  cluster_name TEXT NOT NULL UNIQUE,
  cluster_description TEXT,
  created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_CapabilityClusterMap (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  capability_id INTEGER NOT NULL UNIQUE,
  cluster_id INTEGER NOT NULL
);
CREATE TABLE Next_CapabilityFeature (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    capability_id INTEGER NOT NULL,
    feature_name TEXT NOT NULL,
    feature_description TEXT,
    FOREIGN KEY (capability_id) REFERENCES Next_Capability(id)
);
CREATE TABLE Next_CapabilityInteractionType (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    interaction_type TEXT NOT NULL,
    description TEXT
);
CREATE TABLE Next_CapabilityInterdependency (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    source_capability_id INTEGER NOT NULL,
    target_capability_id INTEGER NOT NULL,
    interaction_type_id INTEGER NOT NULL,
    influence_strength INTEGER CHECK(influence_strength BETWEEN 1 AND 5),
    notes TEXT, framework_id INTEGER DEFAULT 1,
    FOREIGN KEY (source_capability_id) REFERENCES Next_Capability(id),
    FOREIGN KEY (target_capability_id) REFERENCES Next_Capability(id),
    FOREIGN KEY (interaction_type_id) REFERENCES Next_CapabilityInteractionType(id)
);
CREATE TABLE Next_CapabilityInvestmentCost (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  capability_id INTEGER NOT NULL UNIQUE,
  estimated_cost REAL NOT NULL DEFAULT 1.0,
  cost_notes TEXT,
  created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_CapabilityLevel (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    capability_id INTEGER NOT NULL,
    level INTEGER NOT NULL CHECK(level BETWEEN 1 AND 5),
    level_name TEXT,
    capability_state TEXT,
    key_indicators TEXT,
    scoring_criteria TEXT, framework_id INTEGER DEFAULT 1,
    FOREIGN KEY (capability_id) REFERENCES Next_Capability(id)
);
''cloud policies are reviewed on a scheduled/periodic basis with the goal of modernization and continuous improvement.','Automated violation response\u000avendor esg policy enforcement\u000apolicy review',NULL,1);
- the red team improves the organization''s vulnerability management processes
- the blue team learns to get into the attackers'' mindset
- the purple team allows for the development of better incident response programs and vulnerability detection processes','Facility penetration testing\u000a_red | blue | purple teams\u000a_red | blue | purple team exercises',NULL,1);
several managers have adjusted goals to incentivize greater collaboration across development and operational boundaries, but this practice isn''t necessarily aligned to a shared strategy or purpose.
the organization supports heroics. some teams value defined processes and incremental improvements but they lack the resources to properly implement them and it is not a priority nor promoted organization wide.','Heroism\u000afire drills are a norm',NULL,1);
CREATE TABLE Next_CapabilityTag (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    tag_name TEXT NOT NULL,
    tag_description TEXT
);
CREATE TABLE Next_CapabilityTagMap (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    capability_id INTEGER NOT NULL,
    tag_id INTEGER NOT NULL,
    FOREIGN KEY (capability_id) REFERENCES Next_Capability(id),
    FOREIGN KEY (tag_id) REFERENCES Next_CapabilityTag(id)
);
CREATE TABLE Next_ChangeLog (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    table_name TEXT,
    change_type TEXT,
    change_summary TEXT,
    changed_by TEXT,
    changed_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_ChangeRecord (
    id                  INTEGER PRIMARY KEY AUTOINCREMENT,
    version_id          INTEGER REFERENCES Next_FrameworkVersion(id),
    change_category     TEXT NOT NULL             -- capability | level | assessment | interdependency | usecase | tag | cluster | metadata
                        CHECK(change_category IN ('capability','level','assessment','interdependency','usecase','tag','cluster','taxonomy','metadata')),
    change_type         TEXT NOT NULL             -- ADD | UPDATE | DELETE | MOVE | SEED
                        CHECK(change_type IN ('ADD','UPDATE','DELETE','MOVE','SEED')),
    table_name          TEXT NOT NULL,            -- exact table affected
    record_id           INTEGER,                  -- FK to the affected row (nullable for batch ops)
    record_label        TEXT,                     -- human-readable label e.g. 'FinOps & Cloud Economics (id=304)'
    field_changed       TEXT,                     -- column name if UPDATE, NULL if ADD/DELETE
    previous_value      TEXT,                     -- serialised prior value
    new_value           TEXT,                     -- serialised new value
    rationale           TEXT,                     -- why this change was made
    changed_by          TEXT DEFAULT 'Vernon Rauch',
    changed_on          DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_Domain (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    domain_name TEXT NOT NULL,
    domain_description TEXT,
    version TEXT DEFAULT 'E2CAF_Next_v1.0',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, framework_id INTEGER DEFAULT 1);
CREATE TABLE Next_FrameworkVersion (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    version_tag     TEXT NOT NULL UNIQUE,        -- e.g. 'v1.1', 'v1.2'
    version_label   TEXT,                        -- e.g. 'FinOps Integration Release'
    status          TEXT DEFAULT 'draft'         -- draft | published | archived
                    CHECK(status IN ('draft','published','archived')),
    released_by     TEXT,
    released_on     DATETIME DEFAULT CURRENT_TIMESTAMP,
    notes           TEXT                         -- release narrative / summary
);
CREATE TABLE Next_InvestmentRun (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  usecase_id INTEGER NOT NULL,
  budget REAL NOT NULL,
  cost_model TEXT,
  created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_InvestmentSelection (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  run_id INTEGER NOT NULL,
  capability_id INTEGER NOT NULL,
  selected_order INTEGER NOT NULL,
  estimated_cost REAL NOT NULL,
  benefit_score REAL NOT NULL,
  benefit_per_cost REAL NOT NULL,
  created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_MaturityAssessment (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    capability_id INTEGER NOT NULL,
    dimension_id INTEGER NOT NULL,
    maturity_score INTEGER CHECK(maturity_score BETWEEN 1 AND 5),
    assessment_notes TEXT,
    assessed_on DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (capability_id) REFERENCES Next_Capability(id),
    FOREIGN KEY (dimension_id) REFERENCES Next_MaturityDimension(id)
);
CREATE TABLE Next_MaturityDimension (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    description TEXT
);
CREATE TABLE Next_ModelMetadata (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    version TEXT,
    created_by TEXT,
    created_date DATETIME DEFAULT CURRENT_TIMESTAMP,
    description TEXT
);
CREATE TABLE Next_RoadmapClusterStep (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  usecase_id INTEGER NOT NULL,
  cluster_id INTEGER NOT NULL,
  phase INTEGER,
  priority_score REAL,
  capability_count INTEGER,
  created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_RoadmapStep (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    usecase_id INTEGER NOT NULL,
    capability_id INTEGER NOT NULL,
    phase INTEGER,
    priority_score REAL,
    expected_value_theme_id INTEGER
, framework_id INTEGER DEFAULT 1);
CREATE TABLE Next_ScenarioCapabilityChange (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  scenario_id INTEGER NOT NULL,
  capability_id INTEGER NOT NULL,
  dimension_id INTEGER NOT NULL,
  current_score INTEGER,
  target_score INTEGER NOT NULL
);
CREATE TABLE Next_ScenarioImpactCapability (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  scenario_id INTEGER NOT NULL,
  capability_id INTEGER NOT NULL,
  impact_score REAL NOT NULL,
  depth INTEGER NOT NULL,
  created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_ScenarioImpactCluster (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  scenario_id INTEGER NOT NULL,
  cluster_id INTEGER NOT NULL,
  impact_score REAL NOT NULL,
  capability_count INTEGER NOT NULL,
  created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_SubDomain (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    domain_id INTEGER NOT NULL,
    subdomain_name TEXT NOT NULL,
    subdomain_description TEXT, framework_id INTEGER DEFAULT 1,
    FOREIGN KEY (domain_id) REFERENCES Next_Domain(id)
);
CREATE TABLE Next_TargetMaturity (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    usecase_id INTEGER NOT NULL,
    capability_id INTEGER NOT NULL,
    dimension_id INTEGER NOT NULL,
    target_score INTEGER NOT NULL
);
CREATE TABLE Next_TransformationScenario (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  scenario_name TEXT NOT NULL,
  description TEXT,
  usecase_id INTEGER,
  created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_UseCase (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    usecase_title TEXT NOT NULL,
    usecase_description TEXT,
    business_value TEXT,
    owner_role TEXT,
    version TEXT DEFAULT 'E2CAF_Next_v1.0'
, framework_id INTEGER DEFAULT 1);
CREATE TABLE Next_UseCaseCapabilityImpact (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    usecase_id INTEGER NOT NULL,
    capability_id INTEGER NOT NULL,
    impact_weight INTEGER CHECK(impact_weight BETWEEN 1 AND 5),
    maturity_target INTEGER CHECK(maturity_target BETWEEN 1 AND 5),
    feasibility_score INTEGER CHECK(feasibility_score BETWEEN 1 AND 5),
    FOREIGN KEY (usecase_id) REFERENCES Next_UseCase(id),
    FOREIGN KEY (capability_id) REFERENCES Next_Capability(id)
);
CREATE TABLE Next_UseCaseIntent (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    usecase_id INTEGER NOT NULL,
    intent_tag_id INTEGER NOT NULL,
    weight INTEGER DEFAULT 1,
    source TEXT,
    created_on DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE Next_ValueTheme (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    theme_name TEXT NOT NULL,
    theme_description TEXT
);
CREATE TABLE AssessmentRecommendation (
    id                    INTEGER PRIMARY KEY AUTOINCREMENT,
    assessment_id         INTEGER NOT NULL,
    capability_id         INTEGER,
    capability_name       TEXT NOT NULL,
    domain                TEXT,
    capability_role       TEXT,
    current_score         REAL,
    target_maturity       INTEGER,
    gap                   REAL,
    priority_tier         TEXT,
    effort_estimate       TEXT,
    recommended_actions   TEXT,
    enabling_dependencies TEXT,
    success_indicators    TEXT,
    hpe_relevance         TEXT,
    narrative             TEXT,
    created_at            TEXT DEFAULT (datetime('now')),
    FOREIGN KEY (assessment_id) REFERENCES Assessment(id)
);
CREATE TABLE Next_Framework (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    framework_key   TEXT    NOT NULL UNIQUE,
    framework_name  TEXT    NOT NULL,
    version         TEXT,
    status          TEXT    DEFAULT 'active'
                            CHECK(status IN ('active', 'draft', 'archived')),
    is_native       INTEGER DEFAULT 0,
    label_level1    TEXT    DEFAULT 'Pillar',
    label_level2    TEXT    DEFAULT 'Domain',
    label_level3    TEXT    DEFAULT 'Capability',
    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP
);
COMMIT;
